#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

void solve() {
    int n;
    long long k;
    std::cin >> n >> k;
    std::vector<long long> a(n);
    long long min_val = k + 1; // Initialize with a value larger than any possible a_i
    int min_idx = -1;

    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
        if (a[i] < min_val) {
            min_val = a[i];
            min_idx = i;
        }
    }

    long long total_spells = 0;

    // We always copy from the pile with the minimum number of candies (a[min_idx])
    // to other piles.
    // The pile a[min_idx] itself cannot be the target pile for copying from itself.
    // If it were chosen as a_j, its value would increase, potentially making it
    // no longer the minimum, or making it exceed k.
    // To maximize operations, we keep a[min_idx] as the source and its value unchanged.

    for (int i = 0; i < n; ++i) {
        if (i == min_idx) {
            continue; // Don't copy to the minimum pile itself
        }

        // For each other pile a[i], we can add a[min_idx] to it as many times
        // as possible without exceeding k.
        // The current value of a[i] is a[i].
        // Each operation adds min_val.
        // We need a[i] + count * min_val <= k
        // count * min_val <= k - a[i]
        // count <= (k - a[i]) / min_val
        // Since count must be an integer, count = floor((k - a[i]) / min_val)

        if (min_val > 0) { // To avoid division by zero, though problem constraints say a_i >= 1
            total_spells += (k - a[i]) / min_val;
        }
    }

    std::cout << total_spells << std::endl;
}

