void solve() {
    int n, d;
    std::cin >> n >> d;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    int haybales_in_pile1 = a[0];

    for (int i = 1; i < n; ++i) { // Iterate through piles from index 1 (pile 2) to n-1 (pile n)
        int pile_idx = i + 1; // Convert 0-indexed i to 1-indexed pile number
        int cost_per_haybale = i; // Cost to move from pile (i+1) to pile 1 is i days

        if (d <= 0) { // If no days left, stop
            break;
        }

        if (a[i] > 0) { // If there are haybales in the current pile
            int haybales_can_move = d / cost_per_haybale; // Max haybales we can move from this pile given remaining days

            // We can move at most a[i] haybales from this pile
            int actual_haybales_to_move = std::min(a[i], haybales_can_move);

            haybales_in_pile1 += actual_haybales_to_move;
            d -= actual_haybales_to_move * cost_per_haybale;
        }
    }
    std::cout << haybales_in_pile1 << std::endl;
}

