int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        std::string s;
        std::cin >> s;
        int max_dist = 0;
        int last_r_pos = -1; // Represents the last 'R' position or the starting point 0
        for (int i = 0; i < s.length(); ++i) {
            if (s[i] == 'R') {
                // Current cell is i+1 (1-indexed)
                // Distance from last_r_pos to current cell (i+1)
                // is (i+1) - last_r_pos
                max_dist = std::max(max_dist, (i + 1) - last_r_pos);
                last_r_pos = i + 1;
            }
        }
        // After iterating through the string, consider the jump from the last 'R'
        // (or 0 if no 'R's) to the target n+1.
        // The target cell is s.length() + 1.
        // The last position from which a right jump was possible is last_r_pos.
        max_dist = std::max(max_dist, (int)s.length() + 1 - last_r_pos);
        std::cout << max_dist << "\n";
    }
    return 0;
}

