int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    double h;
    std::cin >> n >> h;

    std::cout << std::fixed << std::setprecision(12);

    for (int i = 1; i < n; ++i) {
        // The area of the triangle from the apex to a cut at height x is x^2 / (2h_total)
        // The total area of the carrot is h_total / 2
        // We want to divide the total area into n equal parts.
        // Each part has area (h_total / 2) / n = h_total / (2n)
        // The i-th cut (from the apex) should enclose an area of i * (h_total / (2n))
        // So, x_i^2 / (2h_total) = i * (h_total / (2n))
        // x_i^2 = i * (h_total^2 / n)
        // x_i = sqrt(i * h_total^2 / n)
        // x_i = h_total * sqrt(i / n)
        double x_i = h * std::sqrt(static_cast<double>(i) / n);
        std::cout << x_i << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        long long c, m, x;
        std::cin >> c >> m >> x;

        // The maximum number of teams is limited by three factors:
        // 1. The number of coders available (each team needs at least one coder).
        // 2. The number of mathematicians available (each team needs at least one mathematician).
        // 3. The total number of students available (each team needs 3 students).
        // So, k <= c, k <= m, and 3*k <= c + m + x.
        // This implies k <= min(c, m, (c + m + x) / 3).
        // The minimum of c and m is a strong upper bound because each team must have at least one of each.
        // Let's call this initial upper bound 'low_bound'.
        long long low_bound = std::min({c, m, (c + m + x) / 3});

        // The actual answer could be 'low_bound'.
        // However, we need to check if it's possible to form 'low_bound' teams.
        // If we form 'low_bound' teams, we need 'low_bound' coders and 'low_bound' mathematicians.
        // The remaining students are (c - low_bound) coders, (m - low_bound) mathematicians, and x unspecialized students.
        // The total number of remaining students is (c - low_bound) + (m - low_bound) + x.
        // Each of the 'low_bound' teams needs 3 members. We've already assigned 1 coder and 1 mathematician to each.
        // So, each team still needs 1 more member.
        // The total number of "slots" for these third members is 'low_bound'.
        // If the total number of remaining students is less than 'low_bound', we cannot form 'low_bound' teams.
        // In this case, the number of teams is limited by the total number of students available for these "third slots".
        // The total number of students available for these "third slots" is (c - low_bound) + (m - low_bound) + x.
        // So, the number of teams would be (c - low_bound) + (m - low_bound) + x + low_bound (the initial 2 members per team) / 3.
        // This simplifies to (c + m + x) / 3.
        // This is already covered by the (c + m + x) / 3 term in the min function.

        // The logic is simpler: the number of teams `k` must satisfy:
        // 1. `k <= c` (enough coders)
        // 2. `k <= m` (enough mathematicians)
        // 3. `3 * k <= c + m + x` (enough total students)
        // All these conditions must hold. So, `k` must be less than or equal to the minimum of these three upper bounds.
        // `k <= min(c, m, (c + m + x) / 3)`

        // This single line correctly captures all constraints.
        // For example, if c=1, m=1, x=1: min(1, 1, (1+1+1)/3) = min(1, 1, 1) = 1.
        // If c=3, m=6, x=0: min(3, 6, (3+6+0)/3) = min(3, 6, 3) = 3.
        // If c=0, m=0, x=0: min(0, 0, (0+0+0)/3) = min(0, 0, 0) = 0.
        // If c=0, m=1, x=1: min(0, 1, (0+1+1)/3) = min(0, 1, 0) = 0.
        // If c=10, m=1, x=10: min(10, 1, (10+1+10)/3) = min(10, 1, 21/3) = min(10, 1, 7) = 1.
        // If c=4, m=4, x=1: min(4, 4, (4+4+1)/3) = min(4, 4, 9/3) = min(4, 4, 3) = 3.

        std::cout << low_bound << "\n";
    }
    return 0;
}

