    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n, k;
    std::cin >> n >> k;

    int left = 1;
    int right = k + 1;

    for (int i = 0; i <= k; ++i) {
        if (i % 2 == 0) {
            std::cout << left++;
        } else {
            std::cout << right--;
        }
        if (i < n - 1) { // Only print space if not the last number
            std::cout << " ";
        }
    }

    // For the remaining n - (k + 1) numbers, just print them in increasing order
    // starting from the last number used + 1.
    // The last number used was either left-1 or right+1.
    // If k is even, the last number printed was left-1. So next is left.
    // If k is odd, the last number printed was right+1. So next is right.
    // In both cases, the next number to print is left.
    for (int i = k + 1; i < n; ++i) {
        std::cout << " " << left++;
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <string>
#include <vector>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n, k;
    std::cin >> n >> k;
    std::string s;
    std::cin >> s;

    std::string result = "";
    int open_count = 0;
    int close_count = 0;
    int target_open = k / 2;
    int target_close = k / 2;

    for (char c : s) {
        if (c == '(') {
            if (open_count < target_open) {
                result += '(';
                open_count++;
            }
        } else { // c == ')'
            if (close_count < target_close && open_count > close_count) {
                result += ')';
                close_count++;
            }
        }
        if (open_count == target_open && close_count == target_close) {
            break;
        }
    }

    std::cout << result << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        long long n, m;
        std::cin >> n >> m;

        long long k_max = n / m;

        if (k_max == 0) {
            std::cout << 0 << "\n";
            continue;
        }

        std::vector<long long> cycle_last_digits;
        long long current_sum = 0;
        for (int i = 1; i <= 10; ++i) {
            long long last_digit = (m * i) % 10;
            cycle_last_digits.push_back(last_digit);
            current_sum += last_digit;
        }

        long long num_full_cycles = k_max / 10;
        long long remaining_elements = k_max % 10;

        long long total_sum = num_full_cycles * current_sum;

        for (int i = 0; i < remaining_elements; ++i) {
            total_sum += cycle_last_digits[i];
        }

        std::cout << total_sum << "\n";
    }
    return 0;
}

