        std::cout << ans1 << " " << ans2 << " " << ans3 << " " << ans4 << "\n";
        return;
    }

    // Case 1: Final toy in Box 1 (negative, magnitude >= 1)
    // This requires an odd number of negative toys in total.
    // And it requires that the final magnitude can be >= 1.
    // The only way to guarantee magnitude >= 1 is if at least one toy with magnitude >= 1 is involved.
    // If all initial toys have magnitude < 1, the final product will have magnitude < 1.
    // So, if A+D == 0, then Box 1 is impossible.
    if ((a + b) % 2 == 1 && (a + d > 0)) {
        ans1 = "Ya";
    }

    // Case 2: Final toy in Box 2 (negative, magnitude < 1)
    // This requires an odd number of negative toys in total.
    // It's always possible to get magnitude < 1 if there's at least one toy with magnitude < 1.
    // If all initial toys have magnitude >= 1, the final product will have magnitude >= 1.
    // So, if B+C == 0, then Box 2 is impossible.
    if ((a + b) % 2 == 1 && (b + c > 0)) {
        ans2 = "Ya";
    }

    // Case 3: Final toy in Box 3 (positive, magnitude < 1)
    // This requires an even number of negative toys in total.
    // It's always possible to get magnitude < 1 if there's at least one toy with magnitude < 1.
    // If all initial toys have magnitude >= 1, the final product will have magnitude >= 1.
    // So, if B+C == 0, then Box 3 is impossible.
    if ((a + b) % 2 == 0 && (b + c > 0)) {
        ans3 = "Ya";
    }

    // Case 4: Final toy in Box 4 (positive, magnitude >= 1)
    // This requires an even number of negative toys in total.
    // It's always possible to get magnitude >= 1 if there's at least one toy with magnitude >= 1.
    // If all initial toys have magnitude < 1, the final product will have magnitude < 1.
    // So, if A+D == 0, then Box 4 is impossible.
    if ((a + b) % 2 == 0 && (a + d > 0)) {
        ans4 = "Ya";
    }

    // Special case: If all toys are in B and C (i.e., A=0, D=0)
    // Then all products will have magnitude < 1.
    // So, Box 1 and Box 4 are impossible.
    if (a == 0 && d == 0) {
        ans1 = "Tidak";
        ans4 = "Tidak";
    }
    // Special case: If all toys are in A and D (i.e., B=0, C=0)
    // Then all products will have magnitude >= 1.
    // So, Box 2 and Box 3 are impossible.
    if (b == 0 && c == 0) {
        ans2 = "Tidak";
        ans3 = "Tidak";
    }

    std::cout << ans1 << " " << ans2 << " " << ans3 << " " << ans4 << "\n";
}

