void solve() {
    int n;
    std::cin >> n;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n == 1) {
        std::cout << "Yes\n";
        return;
    }

    // Check if it's possible to form the increasing part
    // For a_1 < a_2 < ... < a_k, we need a_i >= i-1 for 1 <= i <= k.
    // The maximum possible k is n.
    // We need to find the largest prefix where a_i >= i-1 holds.
    int max_inc_len = 0;
    for (int i = 0; i < n; ++i) {
        if (a[i] >= i) { // a_i must be at least i (0-indexed)
            max_inc_len = i + 1;
        } else {
            break;
        }
    }

    // Check if it's possible to form the decreasing part
    // For a_k > a_{k+1} > ... > a_n, we need a_i >= n-i for k <= i <= n.
    // The maximum possible k is 1.
    // We need to find the largest suffix where a_i >= n-1-i holds.
    int max_dec_len = 0;
    for (int i = n - 1; i >= 0; --i) {
        if (a[i] >= (n - 1 - i)) { // a_i must be at least (n-1-i) (0-indexed)
            max_dec_len = n - i;
        } else {
            break;
        }
    }

    // If there is any element that can be part of both an increasing prefix and a decreasing suffix,
    // then it's possible.
    // This means there exists a k (1-indexed) such that:
    // 1. a_1 < ... < a_k is possible (i.e., a_i >= i-1 for 1 <= i <= k)
    // 2. a_k > ... > a_n is possible (i.e., a_i >= n-i for k <= i <= n)
    // In 0-indexed terms:
    // 1. a_0 < ... < a_{k-1} is possible (i.e., a_i >= i for 0 <= i <= k-1)
    // 2. a_{k-1} > ... > a_{n-1} is possible (i.e., a_i >= n-1-i for k-1 <= i <= n-1)
    //
    // This is equivalent to checking if max_inc_len + max_dec_len > n.
    // max_inc_len is the length of the longest prefix a[0...k_inc-1] such that a_i >= i.
    // max_dec_len is the length of the longest suffix a[k_dec...n-1] such that a_i >= n-1-i.
    // If max_inc_len + max_dec_len > n, it means there's an overlap.
    // The overlap implies there's at least one index `j` such that `j < max_inc_len` AND `j >= n - max_dec_len`.
    // This `j` can be our peak `k-1`.
    // For example, if n=5, max_inc_len=3, max_dec_len=3.
    // Inc part covers indices 0, 1, 2.
    // Dec part covers indices 2, 3, 4.
    // Index 2 is covered by both. So a[2] can be the peak.
    //
    // The condition max_inc_len + max_dec_len > n correctly identifies if there's an overlap.
    // If max_inc_len is the length of the prefix, it covers indices [0, max_inc_len-1].
    // If max_dec_len is the length of the suffix, it covers indices [n-max_dec_len, n-1].
    // An overlap exists if (max_inc_len - 1) >= (n - max_dec_len).
    // Which simplifies to max_inc_len + max_dec_len - 1 >= n.
    // Or max_inc_len + max_dec_len > n.

    if (max_inc_len + max_dec_len > n) {
        std::cout << "Yes\n";
    } else {
        std::cout << "No\n";
    }
}

