int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }
    std::sort(a.begin(), a.end());
    int count = 0;
    int b_ptr = 0; // Pointer for the elements we are trying to place (the 'b' array)
    for (int i = 0; i < n; ++i) { // Iterate through elements of the sorted 'a' array (original positions)
        // We want to find an element a[b_ptr] from the available elements
        // such that a[b_ptr] > a[i].
        // Since both arrays are sorted, if a[b_ptr] > a[i], then a[b_ptr+1], a[b_ptr+2], ...
        // are also candidates. To maximize matches, we should use the smallest
        // possible element from the available pool that satisfies the condition.
        // This means we advance b_ptr until a[b_ptr] > a[i].
        while (b_ptr < n && a[b_ptr] <= a[i]) {
            b_ptr++;
        }
        // If we found such an element, we use it for position i.
        // This means a[i] is replaced by a[b_ptr], and a[b_ptr] is now "used".
        if (b_ptr < n) {
            count++;
            b_ptr++; // Move to the next available element for the next position
        } else {
            // No more elements in 'a' (from b_ptr onwards) are greater than a[i].
            // We cannot make any more matches for the remaining positions.
            break;
        }
    }
    std::cout << count << std::endl;
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

// Function to check if a prefix is a permutation
bool is_prefix_permutation(int len, const std::vector<int>& a, const std::vector<int>& max_prefix_val, const std::vector<bool>& distinct_prefix) {
    if (len == 0) return false; // Permutations have non-zero length
    return distinct_prefix[len - 1] && max_prefix_val[len - 1] == len;
}

// Function to check if a suffix is a permutation
bool is_suffix_permutation(int len, const std::vector<int>& a, const std::vector<int>& max_suffix_val, const std::vector<bool>& distinct_suffix) {
    if (len == 0) return false; // Permutations have non-zero length
    return distinct_suffix[len - 1] && max_suffix_val[len - 1] == len;
}

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    // Precompute for prefixes
    std::vector<int> max_prefix_val(n);
    std::vector<bool> distinct_prefix(n);
    std::vector<bool> seen_prefix(n + 1, false); // Max value can be n, so size n+1
    int current_max_prefix = 0;
    bool current_distinct_prefix = true;

    for (int i = 0; i < n; ++i) {
        if (a[i] > n || a[i] <= 0 || seen_prefix[a[i]]) { // a[i] > n is technically not possible given constraints 1 <= a_i <= n-1, but good for robustness
            current_distinct_prefix = false;
        }
        seen_prefix[a[i]] = true;
        current_max_prefix = std::max(current_max_prefix, a[i]);
        max_prefix_val[i] = current_max_prefix;
        distinct_prefix[i] = current_distinct_prefix;
    }

    // Precompute for suffixes
    std::vector<int> max_suffix_val(n);
    std::vector<bool> distinct_suffix(n);
    std::fill(seen_prefix.begin(), seen_prefix.end(), false); // Reuse seen_prefix for suffix check
    int current_max_suffix = 0;
    bool current_distinct_suffix = true;

    for (int i = n - 1; i >= 0; --i) {
        if (a[i] > n || a[i] <= 0 || seen_prefix[a[i]]) {
            current_distinct_suffix = false;
        }
        seen_prefix[a[i]] = true;
        current_max_suffix = std::max(current_max_suffix, a[i]);
        max_suffix_val[n - 1 - i] = current_max_suffix; // Store for length (n-i)
        distinct_suffix[n - 1 - i] = current_distinct_suffix;
    }

    std::vector<std::pair<int, int>> results;
    for (int l1 = 1; l1 < n; ++l1) { // l1 must be at least 1, l2 must be at least 1
        int l2 = n - l1;
        if (is_prefix_permutation(l1, a, max_prefix_val, distinct_prefix) &&
            is_suffix_permutation(l2, a, max_suffix_val, distinct_suffix)) {
            results.push_back({l1, l2});
        }
    }

    std::cout << results.size() << "\n";
    for (const auto& p : results) {
        std::cout << p.first << " " << p.second << "\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

