// Function to convert a number to its parity pattern string
// The pattern will always have 18 characters, padded with '0's from the left
std::string get_parity_pattern(long long n) {
    std::string pattern = "";
    if (n == 0) {
        pattern = "0";
    } else {
        while (n > 0) {
            if ((n % 10) % 2 == 0) {
                pattern += '0';
            } else {
                pattern += '1';
            }
            n /= 10;
        }
    }
    // Pad with '0's from the right to make it 18 characters long
    // This corresponds to padding with '0's from the left for the number
    while (pattern.length() < 18) {
        pattern += '0';
    }
    return pattern;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int t;
    std::cin >> t;

    std::map<std::string, int> counts;

    for (int i = 0; i < t; ++i) {
        char type;
        std::cin >> type;

        if (type == '+') {
            long long a;
            std::cin >> a;
            counts[get_parity_pattern(a)]++;
        } else if (type == '-') {
            long long a;
            std::cin >> a;
            counts[get_parity_pattern(a)]--;
        } else { // type == '?'
            std::string s;
            std::cin >> s;
            // Pad the query pattern with '0's from the right to make it 18 characters long
            // This corresponds to padding with '0's from the left for the pattern
            while (s.length() < 18) {
                s += '0';
            }
            std::cout << counts[s] << "\n";
        }
    }

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;

    long long total_steps = 0;
    long long count_a = 0;
    long long MOD = 1e9 + 7;

    // Iterate the string from right to left
    for (int i = s.length() - 1; i >= 0; --i) {
        if (s[i] == 'a') {
            // If we encounter an 'a', it means this 'a' will eventually
            // need to move past all 'b's to its right.
            // Each 'b' to its right will cause this 'a' to generate a new 'b'.
            // The number of 'b's this 'a' needs to pass is `count_a` (which represents
            // the number of 'b's that were originally to its right, plus 'b's generated
            // by 'a's to its right).
            // When 'ab' -> 'bba', the 'a' effectively moves past the 'b', and a new 'b' is created.
            // The number of steps for this 'a' to move past `count_a` 'b's is `count_a + 1`.
            // This is because each 'ab' operation consumes one 'a' and one 'b' to produce 'bba'.
            // The 'a' effectively moves past the 'b'.
            // If there are `k` 'b's to the right of an 'a', this 'a' will need `k` operations
            // to move past them. Each operation 'ab' -> 'bba' creates a new 'b'.
            // So, if an 'a' is followed by `k` 'b's, it will take `k` steps to move past them.
            // However, the problem states "ab" -> "bba".
            // Consider "a" followed by `k` 'b's.
            // "ab...b" (k 'b's)
            // "ab" -> "bba"
            // The 'a' is now "bba" + "b...b". The 'a' is now at index 2.
            // The number of 'b's to its left has increased.
            // The number of 'b's to its right has decreased by 1.
            // The key insight is that when an 'a' encounters a 'b' to its right, it performs an operation.
            // This operation consumes the 'a' and 'b', and produces 'bba'.
            // The 'a' effectively moves past the 'b', and a new 'b' is generated.
            // The number of 'b's that this 'a' needs to pass is `count_a`.
            // Each 'ab' operation adds 1 to the total steps.
            // When an 'a' is processed, it will interact with all 'b's that are currently to its right.
            // `count_a` represents the number of 'b's that this 'a' will eventually pass.
            // Each such pass is an operation.
            // So, `total_steps += count_a`.
            // After this 'a' has passed all `count_a` 'b's, it will be to the right of them.
            // However, each 'ab' -> 'bba' operation also generates a new 'b'.
            // So, this 'a' itself will generate `count_a` new 'b's.
            // These new 'b's will be to the left of this 'a'.
            // These new 'b's will then be available for 'a's further to the left to interact with.
            // So, the number of 'b's that 'a's to the left will see increases by `count_a`.
            // And this 'a' itself becomes a 'b' for 'a's to its left.
            // So, `count_a` effectively doubles for the next 'a' to the left.
            // `count_a = (count_a * 2) % MOD`.
            // This logic is based on the observation that if an 'a' has `k` 'b's to its right,
            // it will perform `k` operations. Each operation 'ab' -> 'bba' adds 1 to the step count.
            // And each operation effectively doubles the number of 'b's that an 'a' to its left would see.
            // Example: "aab"
            // i=2, s[2]='b'. count_a = 1.
            // i=1, s[1]='a'. total_steps += count_a (1). total_steps = 1. count_a = (1*2)%MOD = 2.
            // i=0, s[0]='a'. total_steps += count_a (2). total_steps = 1+2 = 3. count_a = (2*2)%MOD = 4.
            // Final total_steps = 3. This matches the example.

            total_steps = (total_steps + count_a) % MOD;
            count_a = (count_a * 2) % MOD;
        } else { // s[i] == 'b'
            // If we encounter a 'b', it means this 'b' is now available
            // for 'a's to its left to interact with.
            // So, we increment the count of 'b's that 'a's to the left will see.
            count_a = (count_a + 1) % MOD;
        }
    }

    std::cout << total_steps << std::endl;

    return 0;
}

