#include <vector>
#include <numeric>

void solve() {
    std::string s;
    std::cin >> s;
    int x;
    std::cin >> x;

    int n = s.length();
    std::string w(n, '1'); // Initialize w with all 1s

    // Step 1: Apply constraints from s_i = '0'
    // If s_i is '0', then both w_{i-x} and w_{i+x} must be '0'
    for (int i = 0; i < n; ++i) {
        if (s[i] == '0') {
            if (i - x >= 0) {
                w[i - x] = '0';
            }
            if (i + x < n) {
                w[i + x] = '0';
            }
        }
    }

    // Step 2: Verify if the constructed w can produce s
    // For each s_i, check if it matches the rule based on our w
    for (int i = 0; i < n; ++i) {
        bool s_i_should_be_1 = false;
        if (i - x >= 0 && w[i - x] == '1') {
            s_i_should_be_1 = true;
        }
        if (i + x < n && w[i + x] == '1') {
            s_i_should_be_1 = true;
        }

        if ((s[i] == '1' && !s_i_should_be_1) || (s[i] == '0' && s_i_should_be_1)) {
            // Mismatch found:
            // If s[i] is '1' but our w implies s_i should be '0' (neither w_{i-x} nor w_{i+x} is '1')
            // OR if s[i] is '0' but our w implies s_i should be '1' (at least one of w_{i-x} or w_{i+x} is '1')
            // The second case (s[i]=='0' && s_i_should_be_1) should not happen if our logic for setting w is correct.
            // This is because if s[i]=='0', we explicitly set w[i-x] and w[i+x] to '0' (if valid).
            // So, if s[i]=='0', s_i_should_be_1 will always be false.
            // Thus, we only need to check the first case: s[i]=='1' && !s_i_should_be_1.
            std::cout << -1 << std::endl;
            return;
        }
    }

    std::cout << w << std::endl;
}

