#include <numeric>
#include <algorithm>
#include <cmath>

// Function to get prime factors of a number
std::vector<long long> get_prime_factors(long long n) {
    std::vector<long long> factors;
    for (long long i = 2; i * i <= n; ++i) {
        if (n % i == 0) {
            factors.push_back(i);
            while (n % i == 0) {
                n /= i;
            }
        }
    }
    if (n > 1) {
        factors.push_back(n);
    }
    return factors;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long p, q;
        std::cin >> p >> q;

        if (p % q != 0) {
            std::cout << p << "\n";
            continue;
        }

        // p is divisible by q. We need to find the largest divisor x of p such that x is not divisible by q.
        // This means we must remove some prime factors from p such that x is no longer divisible by q.
        // To maximize x, we should remove the minimum necessary factors.
        // Specifically, for each prime factor r of q, we need to reduce the power of r in p
        // such that the resulting x has a lower power of r than q has.
        // The largest such x will be p / (r^k) where r^k is the smallest power of r that makes x not divisible by q.

        std::vector<long long> q_prime_factors = get_prime_factors(q);
        long long max_x = 0;

        for (long long r : q_prime_factors) {
            long long current_p = p;
            // Count the power of r in p
            long long p_r_power = 0;
            while (current_p > 0 && current_p % r == 0) {
                current_p /= r;
                p_r_power++;
            }

            // Count the power of r in q
            long long q_r_power = 0;
            long long temp_q = q;
            while (temp_q > 0 && temp_q % r == 0) {
                temp_q /= r;
                q_r_power++;
            }

            // We need to reduce the power of r in p such that it's less than q_r_power.
            // The smallest reduction is to make it p_r_power - q_r_power + 1.
            // So, we divide p by r^(p_r_power - q_r_power + 1).
            long long divisor_r_power = p_r_power - q_r_power + 1;
            long long divisor_val = 1;
            for(int i = 0; i < divisor_r_power; ++i) {
                divisor_val *= r;
            }

            max_x = std::max(max_x, p / divisor_val);
        }
        std::cout << max_x << "\n";
    }
    return 0;
}

