int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        int n;
        std::cin >> n;
        long long min_x = -2000000000LL; // Effectively negative infinity
        long long max_x = 2000000000LL;  // Effectively positive infinity
        long long min_y = -2000000000LL;
        long long max_y = 2000000000LL;

        for (int i = 0; i < n; ++i) {
            long long x, y;
            int f1, f2, f3, f4;
            std::cin >> x >> y >> f1 >> f2 >> f3 >> f4;

            if (f1 == 0) { // Cannot move left, so X must be >= current x
                min_x = std::max(min_x, x);
            }
            if (f3 == 0) { // Cannot move right, so X must be <= current x
                max_x = std::min(max_x, x);
            }
            if (f4 == 0) { // Cannot move down, so Y must be >= current y
                min_y = std::max(min_y, y);
            }
            if (f2 == 0) { // Cannot move up, so Y must be <= current y
                max_y = std::min(max_y, y);
            }
        }

        if (min_x <= max_x && min_y <= max_y) {
            std::cout << 1 << " " << min_x << " " << min_y << "\n";
        } else {
            std::cout << 0 << "\n";
        }
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::string s;
    std::cin >> s;

    for (int p = 0; p <= 9; ++p) {
        std::string colors(n, ' ');
        char last1 = '0';
        char last2 = '0';
        bool possible = true;

        // First pass: assign digits < p to color 1, digits > p to color 2
        // For digits == p, assign them to color 2 initially.
        // This ensures that any 'p' assigned to color 1 later will be <= the first 'p' assigned to color 2.
        for (int i = 0; i < n; ++i) {
            if (s[i] < (char)('0' + p)) {
                colors[i] = '1';
                if (s[i] < last1) {
                    possible = false;
                    break;
                }
                last1 = s[i];
            } else if (s[i] > (char)('0' + p)) {
                colors[i] = '2';
                if (s[i] < last2) {
                    possible = false;
                    break;
                }
                last2 = s[i];
            } else { // s[i] == (char)('0' + p)
                colors[i] = '2'; // Tentatively assign 'p' to color 2
                if (s[i] < last2) { // Check against last2, as it's assigned to color 2
                    possible = false;
                    break;
                }
                last2 = s[i];
            }
        }

        if (!possible) {
            continue;
        }

        // Second pass: for digits == p, try to assign them to color 1 if possible.
        // This means they must be >= last1 and <= first 'p' assigned to color 2.
        // Since we assigned all 'p's to color 2 in the first pass, last1 is the max of digits < p.
        // And last2 is the max of digits >= p.
        // We need to find the first 'p' that was assigned to color 2.
        // Any 'p' before that can be assigned to color 1 if it's >= last1.
        // Any 'p' after that must be assigned to color 2.

        // Find the index of the first digit 'p' that was assigned to color 2.
        // All 'p's before this index can potentially be color 1.
        // All 'p's at or after this index must be color 2.
        int first_p_as_2_idx = -1;
        for (int i = 0; i < n; ++i) {
            if (s[i] == (char)('0' + p)) {
                first_p_as_2_idx = i;
                break;
            }
        }

        if (first_p_as_2_idx != -1) { // If there are any 'p's
            last1 = '0'; // Reset last1 to check non-decreasing for color 1
            for (int i = 0; i < n; ++i) {
                if (s[i] < (char)('0' + p)) {
                    colors[i] = '1';
                    if (s[i] < last1) { possible = false; break; }
                    last1 = s[i];
                } else if (s[i] > (char)('0' + p)) {
                    colors[i] = '2'; // This will be checked in the final validation
                } else { // s[i] == (char)('0' + p)
                    if (i < first_p_as_2_idx) { // Digits 'p' before the first 'p' that must be 2
                        colors[i] = '1';
                        if (s[i] < last1) { possible = false; break; }
                        last1 = s[i];
                    } else { // Digits 'p' at or after the first 'p' that must be 2
                        colors[i] = '2';
                    }
                }
            }
        } else { // No 'p' digits, the first pass coloring is already final.
            // We still need to reconstruct the string to ensure last1 and last2 are correct.
            last1 = '0';
            for (int i = 0; i < n; ++i) {
                if (colors[i] == '1') {
                    if (s[i] < last1) { possible = false; break; }
                    last1 = s[i];
                }
            }
        }

        if (!possible) {
            continue;
        }

        // Final validation: check if the combined sequence is non-decreasing
        std::string s1_str = "";
        std::string s2_str = "";
        for (int i = 0; i < n; ++i) {
            if (colors[i] == '1') {
                s1_str += s[i];
            } else {
                s2_str += s[i];
            }
        }

        bool sorted = true;
        if (!s1_str.empty()) {
            for (size_t i = 0; i < s1_str.length() - 1; ++i) {
                if (s1_str[i] > s1_str[i+1]) {
                    sorted = false;
                    break;
                }
            }
        }
        if (sorted && !s2_str.empty()) {
            for (size_t i = 0; i < s2_str.length() - 1; ++i) {
                if (s2_str[i] > s2_str[i+1]) {
                    sorted = false;
                    break;
                }
            }
        }
        if (sorted && !s1_str.empty() && !s2_str.empty()) {
            if (s1_str.back() > s2_str.front()) {
                sorted = false;
            }
        }

        if (sorted) {
            std::cout << colors << "\n";
            return;
        }
    }

    std::cout << "-\n";
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

