#include <iostream>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    long long a, b;
    std::cin >> a >> b;
    long long MOD = 1000000007;

    if (b == 1) {
        std::cout << 0 << std::endl;
        return 0;
    }

    // Sum of r from 1 to b-1: (b-1) * b / 2
    // This sum is (b-1) * b / 2.
    // We need to compute this modulo MOD.
    // Since b can be up to 10^7, (b-1)*b can be up to 10^14, so use long long.
    // Division by 2 means multiplying by modular inverse of 2.
    // MOD is 10^9 + 7, which is prime. Inverse of 2 is (MOD + 1) / 2.
    long long sum_r_term = (b - 1);
    sum_r_term = (sum_r_term * b) % MOD;
    long long inv2 = (MOD + 1) / 2;
    sum_r_term = (sum_r_term * inv2) % MOD;

    // Sum of (k * b + 1) for k from 1 to a
    // This is sum_{k=1 to a} (k*b + 1)
    // = b * sum_{k=1 to a} k + sum_{k=1 to a} 1
    // = b * (a * (a+1) / 2) + a
    // Compute this modulo MOD.
    long long sum_kb_plus_1_term = (a * (a + 1) / 2) % MOD; // (a * (a+1) / 2) is sum of k
    sum_kb_plus_1_term = (sum_kb_plus_1_term * b) % MOD; // b * sum of k
    sum_kb_plus_1_term = (sum_kb_plus_1_term + a) % MOD; // + a

    // Total sum is (sum_r_term * sum_kb_plus_1_term) % MOD
    long long total_sum = (sum_r_term * sum_kb_plus_1_term) % MOD;

    std::cout << total_sum << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <numeric>
#include <algorithm>
#include <iomanip>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;
    int n = s.length();

    std::vector<std::vector<int>> char_indices(26);
    for (int i = 0; i < n; ++i) {
        char_indices[s[i] - 'a'].push_back(i);
    }

    double total_win_prob = 0.0;

    for (int k_actual = 0; k_actual < n; ++k_actual) {
        char first_char_t = s[k_actual]; // t[0] = s[k_actual]

        // Possible k values given t[0]
        const std::vector<int>& possible_k_values = char_indices[first_char_t - 'a'];

        if (possible_k_values.size() == 1) {
            // If only one k matches t[0], Vasya wins immediately.
            total_win_prob += 1.0;
            continue;
        }

        double max_win_prob_for_k_actual = 0.0;

        // Vasya chooses p (1 to N-1) to maximize win probability
        for (int p = 1; p < n; ++p) {
            // t[p] = s[(k_actual + p) % N]
            char second_char_t = s[(k_actual + p) % n];

            int count_matches = 0;
            for (int k_candidate : possible_k_values) {
                // Check if this k_candidate is consistent with t[0] and t[p]
                // t[0] = s[k_candidate] (already guaranteed by possible_k_values)
                // t[p] = s[(k_candidate + p) % N]
                if (s[(k_candidate + p) % n] == second_char_t) {
                    count_matches++;
                }
            }

            if (count_matches == 1) {
                // If only one k_candidate matches both t[0] and t[p], Vasya wins.
                max_win_prob_for_k_actual = std::max(max_win_prob_for_k_actual, 1.0);
            }
        }
        total_win_prob += max_win_prob_for_k_actual;
    }

    std::cout << std::fixed << std::setprecision(15) << total_win_prob / n << std::endl;

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <numeric>
#include <set>
#include <algorithm>
#include <map>

void solve() {
    std::string s;
    std::cin >> s;

    std::map<char, std::set<char>> adj;
    std::set<char> used_in_s;

    for (size_t i = 0; i < s.length(); ++i) {
        used_in_s.insert(s[i]);
        if (i > 0) {
            adj[s[i]].insert(s[i-1]);
            adj[s[i-1]].insert(s[i]);
        }
    }

    for (const auto& pair : adj) {
        if (pair.second.size() > 2) {
            std::cout << "NO\n";
            return;
        }
    }

    std::string layout_str = "";
    std::set<char> visited_in_layout;

    // Find a starting character for a path
    char current_char = '\0';
    for (char c : used_in_s) {
        if (adj[c].size() <= 1) { // Start of a path or isolated character
            current_char = c;
            break;
        }
    }

    // If all characters in s have two neighbors, it means they form a cycle.
    // This is only possible if all characters in s form a single cycle.
    // A single cycle of length > 2 cannot be represented on a linear keyboard.
    // If it's a cycle of length 2 (e.g., "abab"), it's fine, one char has 1 neighbor, the other has 1.
    // If current_char is still null, it means all characters in `used_in_s` have exactly 2 neighbors.
    // This implies a cycle. A cycle cannot be laid out on a linear keyboard.
    // Example: "abcda" -> a-b, b-c, c-d, d-a. 'a' has 'b' and 'd' as neighbors.
    // 'b' has 'a' and 'c'. 'c' has 'b' and 'd'. 'd' has 'c' and 'a'.
    // All have 2 neighbors. This forms a cycle.
    // The only exception is if `used_in_s` is empty (s is empty, but problem says |s| >= 1).
    // Or if `used_in_s` has only one character (e.g., "aaaaa" but problem says no adjacent equal chars).
    // So if current_char is null, it's a NO.
    if (current_char == '\0' && !used_in_s.empty()) {
        std::cout << "NO\n";
        return;
    }

    // If s is empty, this case is not possible due to constraints.
    // If s has only one character, e.g., "a", then used_in_s = {'a'}, adj['a'] is empty.
    // current_char will be 'a'.
    if (used_in_s.empty()) { // Should not happen based on constraints |s| >= 1
        // Handle gracefully, though not strictly necessary for problem constraints
        for (char c = 'a'; c <= 'z'; ++c) {
            layout_str += c;
        }
        std::cout << "YES\n" << layout_str << "\n";
        return;
    }

    // Build the layout string for characters in s
    while (current_char != '\0') {
        if (visited_in_layout.count(current_char)) {
            // This means we've encountered a character already in the current path.
            // This implies a cycle within the path, which is impossible for a linear layout.
            // Or, it means we've processed all characters in a connected component,
            // and current_char was set to null, but then we tried to continue.
            // This check is mostly for safety, the logic should prevent this.
            break;
        }
        layout_str += current_char;
        visited_in_layout.insert(current_char);

        char next_char = '\0';
        for (char neighbor : adj[current_char]) {
            if (!visited_in_layout.count(neighbor)) {
                next_char = neighbor;
                break;
            }
        }
        current_char = next_char;
    }

    // Check if all characters from s are included in the layout_str
    if (layout_str.length() != used_in_s.size()) {
        // This means there are multiple disconnected components in the graph formed by s.
        // E.g., "ab" and "cd". 'a' is adj to 'b', 'c' is adj to 'd'.
        // This cannot be put on a single linear keyboard where all adjacent pairs are adjacent.
        // Example: "ab" and "cd". Layout "abcd..." means 'b' and 'c' are adjacent.
        // But 'b' and 'c' are not adjacent in the password.
        // The only way this is possible is if the components are isolated characters.
        // But if they are isolated characters, they would have been picked up by the initial
        // current_char search (adj[c].size() <= 1).
        // If layout_str.length() < used_in_s.size(), it means there's another path/component
        // that couldn't be connected to the first one. This is a NO.
        std::cout << "NO\n";
        return;
    }

    // Add remaining characters not in s
    for (char c = 'a'; c <= 'z'; ++c) {
        if (!visited_in_layout.count(c)) {
            layout_str += c;
        }
    }

    std::cout << "YES\n" << layout_str << "\n";
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

