int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    int current_and = 1023; // Represents the effect of all '&' operations
    int current_or = 0;    // Represents the effect of all '|' operations
    int current_xor = 0;   // Represents the effect of all '^' operations

    for (int i = 0; i < n; ++i) {
        char op_char;
        int val;
        std::cin >> op_char >> val;

        if (op_char == '&') {
            current_and &= val;
            current_or &= val;
            current_xor &= val;
        } else if (op_char == '|') {
            current_and |= val;
            current_or |= val;
            current_xor |= val;
        } else if (op_char == '^') {
            current_and ^= val;
            current_or ^= val;
            current_xor ^= val;
        }
    }

    // Now, for each bit position (0 to 9), determine the final transformation.
    // Let x_j be the j-th bit of the input.
    // The final j-th bit will be:
    // (x_j & (current_and_j)) | (current_or_j) ^ (current_xor_j)
    //
    // We need to find A, O, X such that for all x_j:
    // (x_j & A_j) | O_j ^ X_j == (x_j & current_and_j) | current_or_j ^ current_xor_j
    //
    // Let's test for x_j = 0 and x_j = 1.
    //
    // For x_j = 0:
    // (0 & A_j) | O_j ^ X_j == (0 & current_and_j) | current_or_j ^ current_xor_j
    // O_j ^ X_j == current_or_j ^ current_xor_j
    //
    // For x_j = 1:
    // (1 & A_j) | O_j ^ X_j == (1 & current_and_j) | current_or_j ^ current_xor_j
    // A_j | O_j ^ X_j == current_and_j | current_or_j ^ current_xor_j
    //
    // Let C0_j = current_or_j ^ current_xor_j
    // Let C1_j = current_and_j | current_or_j ^ current_xor_j
    //
    // So we need:
    // O_j ^ X_j == C0_j
    // A_j | O_j ^ X_j == C1_j
    //
    // Substituting the first into the second:
    // A_j | C0_j == C1_j
    //
    // We want to find A, O, X.
    //
    // For each bit j:
    // Let bit_0_result = (0 & current_and_j) | current_or_j ^ current_xor_j;
    // Let bit_1_result = (1 & current_and_j) | current_or_j ^ current_xor_j;
    //
    // We need to find A_j, O_j, X_j such that:
    // (0 & A_j) | O_j ^ X_j == bit_0_result
    // (1 & A_j) | O_j ^ X_j == bit_1_result
    //
    // This simplifies to:
    // O_j ^ X_j == bit_0_result
    // A_j | (O_j ^ X_j) == bit_1_result
    //
    // So, A_j | bit_0_result == bit_1_result
    //
    // From A_j | bit_0_result == bit_1_result:
    // If bit_0_result == 0: A_j must be bit_1_result.
    // If bit_0_result == 1: A_j can be 0 or 1, as long as bit_1_result is 1.
    //                       If bit_1_result is 0, then no solution for A_j. (This case should not happen,
    //                       as (1 & current_and_j) | C0_j >= C0_j, so bit_1_result >= bit_0_result)
    //                       So if bit_0_result is 1, bit_1_result must be 1. Then A_j can be 0 or 1.
    //                       To minimize operations, we prefer A_j=1 if possible.
    //
    // Let's define the target A, O, X values for the simplified program.
    int final_A = 0;
    int final_O = 0;
    int final_X = 0;

    for (int j = 0; j < 10; ++j) {
        int bit_mask = (1 << j);

        int c_and_j = (current_and & bit_mask) >> j;
        int c_or_j = (current_or & bit_mask) >> j;
        int c_xor_j = (current_xor & bit_mask) >> j;

        int bit_0_result = (0 & c_and_j) | c_or_j ^ c_xor_j;
        int bit_1_result = (1 & c_and_j) | c_or_j ^ c_xor_j;

        int a_j, o_j, x_j;

        // Determine a_j
        if (bit_0_result == 0) {
            a_j = bit_1_result;
        } else { // bit_0_result == 1
            // bit_1_result must be 1 (as (1&c_and_j)|C0_j >= C0_j)
            a_j = 1; // We can choose a_j=1 to make A_j | 1 = 1
        }

        // Determine o_j and x_j such that o_j ^ x_j == bit_0_result
        // We can set o_j = bit_0_result and x_j = 0.
        o_j = bit_0_result;
        x_j = 0;

        // Accumulate into final_A, final_O, final_X
        if (a_j == 1) final_A |= bit_mask;
        if (o_j == 1) final_O |= bit_mask;
        if (x_j == 1) final_X |= bit_mask;
    }

    std::vector<std::pair<char, int>> simplified_ops;

    // The order of operations matters for the simplified program.
    // The form is (x & A) | O ^ X.
    // This means we apply AND first, then OR, then XOR.
    //
    // If final_A is not 1023, we need an '&' operation.
    // If final_O is not 0, we need an '|' operation.
    // If final_X is not 0, we need an '^' operation.
    //
    // However, the problem states "arbitrary sequence of these operations".
    // The derived A, O, X are for the form (x & A) | O ^ X.
    // Let's verify this.
    //
    // If we apply & A, then | O, then ^ X:
    // x' = x & A
    // x'' = x' | O = (x & A) | O
    // x''' = x'' ^ X = ((x & A) | O) ^ X
    //
    // This is exactly the form we derived.
    //
    // So, the operations are:
    // 1. & final_A
    // 2. | final_O
    // 3. ^ final_X
    //
    // We only add an operation if its constant is not the identity for that operation.
    // For '&', identity is 1023.
    // For '|', identity is 0.
    // For '^', identity is 0.

    if (final_A != 1023) {
        simplified_ops.push_back({'&', final_A});
    }
    if (final_O != 0) {
        simplified_ops.push_back({'|', final_O});
    }
    if (final_X != 0) {
        simplified_ops.push_back({'^', final_X});
    }

    std::cout << simplified_ops.size() << "\n";
    for (const auto& op : simplified_ops) {
        std::cout << op.first << " " << op.second << "\n";
    }

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <cmath>
#include <algorithm>

void solve() {
    std::string s;
    std::cin >> s;
    int n = s.length();
    long long good_substrings_count = 0;

    // Iterate through all possible starting positions l
    for (int l = 0; l < n; ++l) {
        // If s[l] is '0', it can only be the start of a good substring if the value is 0.
        // The only way for value to be 0 is if all characters are '0'.
        // If s[l] is '0', the value f(s_l...s_r) will be 0 if all characters are '0'.
        // In this case, length = r - l + 1.
        // If value is 0, then length must be 0, which is impossible for a non-empty substring.
        // So, if s[l] is '0', the value f(s_l...s_r) will be 0 if all characters are '0'.
        // If s[l] is '0', and there's a '1' later, the value will be positive.
        // The problem statement says f(000) = 0.
        // If f(s_l...s_r) = 0, then r-l+1 = 0, which is impossible.
        // So, any good substring must have a positive value.
        // This implies that any good substring must contain at least one '1'.
        // If s[l] is '0', it means the actual binary value starts from the first '1' after l.
        // However, the definition of f(t) includes leading zeros.
        // Example: f(011) = 3. Length is 3. 3 = 3. This is a good substring.
        // Example: f(000) = 0. Length is 3. 3 != 0. Not good.
        // So, if s[l] is '0', we still need to consider it.

        long long current_val = 0;
        // Iterate through possible ending positions r, starting from l
        // The maximum possible length for a good substring is around 18-19.
        // If length is L, value is at most 2^L - 1.
        // If L = 2^L - 1, then L must be small.
        // 2^18 = 262144. Max N is 2e5. So max length is around 18.
        // We can iterate r up to l + MAX_LEN_CONSIDERED.
        // Let's pick a safe upper bound for MAX_LEN_CONSIDERED, say 20.
        // This means for each l, we check at most 20 substrings.
        // Total complexity: N * MAX_LEN_CONSIDERED.
        // N * 20 = 2e5 * 20 = 4e6, which is fine.

        // The maximum length of s is 2e5.
        // The maximum value a good substring can have is 2e5.
        // The binary representation of 2e5 is 11000011010100000 (18 bits).
        // So, a good substring cannot have length much larger than 18.
        // Let's say we check up to length 20.
        // This means r can go up to l + 19.
        // The loop for r should go up to min(n-1, l + 19).
        // However, we need to be careful with leading zeros.
        // If s[l] is '0', the value can be small, but the length can be large.
        // Example: s = "00001000", l=0.
        // s[0...0] = "0", len=1, val=0. Not good.
        // s[0...1] = "00", len=2, val=0. Not good.
        // ...
        // s[0...3] = "0000", len=4, val=0. Not good.
        // s[0...4] = "00001", len=5, val=1. Not good.
        // s[0...5] = "000010", len=6, val=2. Not good.
        // s[0...6] = "0000100", len=7, val=4. Not good.
        // s[0...7] = "00001000", len=8, val=8. Good!

        // The maximum length of a substring is N.
        // The maximum value of a substring is 2^N - 1.
        // If length = value, then length must be small.
        // For example, if length is 20, value can be up to 2^20 - 1.
        // If length is 20, and value is 20, it's not good.
        // If length is 20, and value is 20, it's not good.
        // The maximum length of a good substring is bounded by the maximum value it can represent.
        // If length is L, value is at most 2^L - 1.
        // If L = value, then L <= 2^L - 1. This is true for all L >= 1.
        // However, the value is also bounded by N.
        // So, L <= N.
        // And value <= N.
        // So, L <= N.
        // The maximum value of a binary string of length L is 2^L - 1.
        // If L = value, then L <= 2^L - 1.
        // The maximum length of a good substring is bounded by the maximum value it can represent.
        // If length is L, and value is V, we need L=V.
        // The maximum possible value for V is N (length of string s).
        // So, L <= N.
        // Also, V <= 2^L - 1.
        // So, L <= 2^L - 1.
        // And L <= N.
        // The maximum value of N is 2e5.
        // The smallest L such that 2^L - 1 >= 2e5 is L=18 (2^18 - 1 = 262143).
        // So, any good substring must have length at most 18.
        // This means r - l + 1 <= 18.
        // So, r <= l + 17.

        // This logic is correct. We only need to check substrings of length up to ~18.
        // Let's use a slightly larger constant, say 20, to be safe.
        // This means for each l, we only check r from l to min(n-1, l + 19).
        // This is O(N * MAX_GOOD_LEN).

        for (int r = l; r < n; ++r) {
            int len = r - l + 1;

            // Optimization: If len is already too large, the value `current_val`
            // will likely exceed `len` very quickly, or `current_val` will exceed `N`.
            // If `current_val` becomes greater than `N`, then `current_val` cannot be equal to `len`
            // because `len` is at most `N`.
            // Also, if `len` itself is greater than `MAX_GOOD_LEN_THRESHOLD`, we can stop.
            // MAX_GOOD_LEN_THRESHOLD = 18 is derived from 2^18 > 2e5.
            // If len > 18, then current_val would need to be > 18.
            // If current_val > N, it can't be equal to len (since len <= N).
            // So, if current_val > N, we can break.
            // If len > 18, and current_val is still small, it means there are many leading zeros.
            // Example: "000000000000000001", len=18, val=1. Not good.
            // Example: "00000000000000000010", len=20, val=2. Not good.
            // The condition `len = val` means `val` cannot grow too fast.
            // If `s[l]` is '1', then `current_val` grows exponentially.
            // If `s[l]` is '0', `current_val` might stay 0 for a while, then grow.

            // Update current_val
            current_val = current_val * 2 + (s[r] - '0');

            // If current_val exceeds N, it can no longer be equal to len (since len <= N).
            // This is a strong pruning condition.
            if (current_val > n) {
                break; // No need to extend this substring further
            }

            // If current_val is 0, it can't be equal to len (since len >= 1).
            if (current_val == 0) {
                continue;
            }

            // Check if the condition holds
            if (len == current_val) {
                good_substrings_count++;
            }
        }
    }

    std::cout << good_substrings_count << std::endl;
}

