#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 2) { // Sequences of length 1 or 2 are always stable
        std::cout << 0 << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << a[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
        return 0;
    }

    std::vector<int> L(n, 0), R(n, 0);

    // Calculate L_i: minimum distance to a 0 on the left (inclusive)
    // L_i = 0 if a_i = 0
    // L_i = L_{i-1} + 1 if a_i = 1 and i > 0
    // L_0 = 0 if a_0 = 0, else infinity (effectively, we don't care about L_0 if a_0=1 as it's boundary)
    L[0] = (a[0] == 0 ? 0 : n + 1); // Use n+1 as infinity for distances
    for (int i = 1; i < n; ++i) {
        if (a[i] == 0) {
            L[i] = 0;
        } else {
            L[i] = L[i - 1] + 1;
        }
    }

    // Calculate R_i: minimum distance to a 0 on the right (inclusive)
    // R_i = 0 if a_i = 0
    // R_i = R_{i+1} + 1 if a_i = 1 and i < n-1
    // R_{n-1} = 0 if a_{n-1} = 0, else infinity
    R[n - 1] = (a[n - 1] == 0 ? 0 : n + 1);
    for (int i = n - 2; i >= 0; --i) {
        if (a[i] == 0) {
            R[i] = 0;
        } else {
            R[i] = R[i + 1] + 1;
        }
    }

    int max_dist = 0;
    for (int i = 0; i < n; ++i) {
        if (a[i] == 1) {
            max_dist = std::max(max_dist, std::min(L[i], R[i]));
        }
    }

    int k = (max_dist + 1) / 2;

    std::cout << k << "\n";

    std::vector<int> b(n);
    for (int i = 0; i < n; ++i) {
        if (a[i] == 0) {
            b[i] = 0;
        } else {
            if (std::min(L[i], R[i]) <= k) {
                b[i] = 0;
            } else {
                b[i] = 1;
            }
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << b[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

