struct Child {
    long long v, d, p;
    int original_idx;
    bool in_line;
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<Child> children(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> children[i].v >> children[i].d >> children[i].p;
        children[i].original_idx = i + 1;
        children[i].in_line = true;
    }

    std::vector<int> cured_children_indices;

    for (int i = 0; i < n; ++i) {
        if (!children[i].in_line) {
            continue;
        }

        cured_children_indices.push_back(children[i].original_idx);
        children[i].in_line = false; // This child is now cured and out of line

        long long current_cry_volume = children[i].v;
        long long accumulated_hall_cry = 0;

        for (int j = i + 1; j < n; ++j) {
            if (!children[j].in_line) {
                continue;
            }

            // Apply confidence reduction from the current child in office
            if (current_cry_volume > 0) {
                children[j].p -= current_cry_volume;
                current_cry_volume--;
            }

            // Apply accumulated hall cry from previous children who ran away
            children[j].p -= accumulated_hall_cry;

            // Check if child j's confidence drops below zero
            if (children[j].p < 0) {
                if (children[j].in_line) { // Ensure we only process if still in line
                    children[j].in_line = false;
                    accumulated_hall_cry += children[j].d;
                }
            }
        }
    }

    std::cout << cured_children_indices.size() << "\n";
    for (size_t i = 0; i < cured_children_indices.size(); ++i) {
        std::cout << cured_children_indices[i] << (i == cured_children_indices.size() - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

