bool check(long long T, int n, int m, const std::vector<long long>& h, const std::vector<long long>& p) {
    int p_idx = 0;
    for (int h_idx = 0; h_idx < n; ++h_idx) {
        if (p_idx == m) { // All tracks covered
            return true;
        }

        long long current_h = h[h_idx];
        long long p_start = p[p_idx];

        // If current head cannot reach the current target track p_start within T time,
        // it means this head cannot cover p_start.
        // We need to find a head that can cover p_start.
        // If current_h is too far to the right of p_start, this head is useless for p_start.
        // We must advance p_idx until p_start is reachable by current_h or current_h is to the left of p_start.
        // Or, more simply, if p_start is too far to the left of current_h, this head can't cover it.
        // We need to find the first p_start that current_h can potentially cover.
        // This is implicitly handled by the loop structure.
        // If p_start is already covered by a previous head, p_idx would have advanced.

        // If current_h is to the right of p_start, and p_start is not covered yet,
        // this head can potentially cover p_start by moving left.
        // The leftmost point it can reach is current_h - T.
        // If p_start < current_h - T, then current_h cannot reach p_start.
        // This head can only cover tracks in [current_h - T, current_h + T].
        // However, the actual range covered depends on its movement.
        // If it moves to x, it covers [min(h_i, x), max(h_i, x)].
        // The crucial observation is that to cover p_start, the head must move to some x such that p_start is in [min(h_i, x), max(h_i, x)]
        // AND |h_i - x| <= T.
        // This means x must be in [h_i - T, h_i + T].
        // So, the head can cover p_start if p_start is in [h_i - T, h_i + T].
        // If p_start is outside this range, this head cannot cover p_start.

        // If p_start is to the left of current_h - T, this head cannot cover p_start.
        // We need to find a head that can cover p_start.
        // This head will be used to cover tracks starting from p_start.
        // The range it can cover is [p_start, p_start + T + (current_h - p_start)] if it moves right from p_start.
        // Or [p_start - T - (p_start - current_h), p_start] if it moves left from p_start.

        // Let's simplify: a head at `current_h` can cover a segment `[L, R]` if it moves to `x` such that `|current_h - x| <= T`.
        // The segment covered is `[min(current_h, x), max(current_h, x)]`.
        // To cover `p_start`, the head must move to some `x` such that `p_start` is in `[min(current_h, x), max(current_h, x)]`.
        // And `|current_h - x| <= T`.
        // This means `x` must be in `[current_h - T, current_h + T]`.
        // So, `p_start` must be in `[current_h - T, current_h + T]`.
        // If `p_start < current_h - T`, this head cannot cover `p_start`. We move to the next head.
        // If `p_start > current_h + T`, this head cannot cover `p_start`. This should not happen if `p_idx` is correctly advanced.

        // The strategy is greedy: use the current head to cover `p_start` and as many subsequent `p_j` as possible.
        // The head is at `current_h`. The first uncovered track is `p_start`.
        // Case 1: `current_h` is to the left of `p_start`.
        // The head must move right to cover `p_start`.
        // It takes `p_start - current_h` time to reach `p_start`.
        // Remaining time: `T - (p_start - current_h)`.
        // With this remaining time, it can move further right.
        // The rightmost track it can reach is `p_start + (T - (p_start - current_h)) = current_h + T`.
        // So, it covers `[current_h, current_h + T]`.
        // The tracks it actually covers are `[p_start, current_h + T]`.
        // The rightmost track covered is `current_h + T`.

        // Case 2: `current_h` is to the right of `p_start`.
        // The head must move left to cover `p_start`.
        // It takes `current_h - p_start` time to reach `p_start`.
        // Remaining time: `T - (current_h - p_start)`.
        // With this remaining time, it can move further left.
        // The leftmost track it can reach is `p_start - (T - (current_h - p_start)) = current_h - T`.
        // So, it covers `[current_h - T, current_h]`.
        // The tracks it actually covers are `[current_h - T, p_start]`.
        // The rightmost track covered is `p_start`.

        // Case 3: `current_h` is at `p_start`.
        // It takes 0 time to reach `p_start`.
        // Remaining time: `T`.
        // It can move `T` units left or `T` units right.
        // It covers `[current_h - T, current_h + T]`.
        // The rightmost track covered is `current_h + T`.

        // Combining these:
        // If `current_h <= p_start`: The head moves right. It takes `p_start - current_h` time to reach `p_start`.
        // If `p_start - current_h > T`, this head cannot reach `p_start`.
        // Otherwise, it reaches `p_start` and has `T - (p_start - current_h)` time left.
        // It can then move further right to `p_start + (T - (p_start - current_h)) = current_h + T`.
        // The rightmost track covered is `current_h + T`.

        // If `current_h > p_start`: The head moves left. It takes `current_h - p_start` time to reach `p_start`.
        // If `current_h - p_start > T`, this head cannot reach `p_start`.
        // Otherwise, it reaches `p_start` and has `T - (current_h - p_start)` time left.
        // It can then move further left to `p_start - (T - (current_h - p_start)) = current_h - T`.
        // The rightmost track covered is `p_start`. (Because it moved left to cover p_start, and then further left. The segment covered is [current_h - T, current_h]. The rightmost point of this segment is current_h. But we are interested in the rightmost *target track* covered. If it moves left to p_start, it covers [current_h - T, p_start]. The rightmost target track covered is p_start.)

        // This logic is tricky. Let's re-evaluate.
        // A head at `h_i` can cover any track `x` such that `|h_i - x| <= T`.
        // If it moves to `x`, it covers the segment `[min(h_i, x), max(h_i, x)]`.
        // We want to cover `p_start`.
        // If `p_start` is too far left for `h_i` (i.e., `p_start < h_i - T`), then `h_i` cannot cover `p_start`.
        // In this case, `h_i` is useless for `p_start` and any `p_j` to its left. We should try the next head.
        // If `p_start` is reachable by `h_i` (i.e., `p_start >= h_i - T`), then `h_i` can cover `p_start`.
        // To maximize the coverage to the right, `h_i` should move as far right as possible while still covering `p_start`.
        // If `h_i <= p_start`: `h_i` moves right to `x`. It covers `[h_i, x]`. We need `p_start <= x`.
        // The maximum `x` is `h_i + T`. So it covers `[h_i, h_i + T]`.
        // The rightmost track covered is `h_i + T`.
        // If `h_i > p_start`: `h_i` moves left to `x`. It covers `[x, h_i]`. We need `x <= p_start`.
        // The minimum `x` is `h_i - T`. So it covers `[h_i - T, h_i]`.
        // The rightmost track covered is `h_i`.
        // This is still not quite right. The head can move to any `x` in `[h_i - T, h_i + T]`.
        // If it moves to `x`, it covers `[min(h_i, x), max(h_i, x)]`.
        // We want to cover `p_start`.
        // If `h_i` is used to cover `p_start`, it must move to some `x` such that `p_start` is in `[min(h_i, x), max(h_i, x)]` and `|h_i - x| <= T`.
        // To maximize the rightmost point covered, the head should move to `x = h_i + T`.
        // This covers the range `[h_i, h_i + T]`.
        // This is valid if `p_start` is in `[h_i, h_i + T]`.
        // If `p_start < h_i`, then moving to `h_i + T` does not cover `p_start`.
        // In this case, `h_i` must move left to cover `p_start`.
        // If `h_i` moves left to `x` such that `x <= p_start < h_i`, it covers `[x, h_i]`.
        // The time taken is `h_i - x`. This must be `<= T`. So `x >= h_i - T`.
        // To cover `p_start` and maximize right coverage, `h_i` should move to `p_start`.
        // This takes `h_i - p_start` time. Remaining time `T - (h_i - p_start)`.
        // With this remaining time, it can move further right from `p_start` to `p_start + (T - (h_i - p_start))`.
        // So, if `h_i > p_start`, and `h_i - p_start <= T`, the head can cover up to `p_start + T - (h_i - p_start)`.
        // This is `p_start + T - h_i + p_start = 2*p_start + T - h_i`.
        // This is the rightmost point it can reach *after* covering `p_start` by moving left.

        // Let's use the two-pointer approach with a clearer definition of `rightmost_covered`.
        // `rightmost_covered` is the maximum track index that the current head can cover,
        // given that it must cover `p[p_idx]`.

        // If `p[p_idx]` is to the left of `current_h - T`, then `current_h` cannot cover `p[p_idx]`.
        // This `h_idx` head is too far right to cover `p[p_idx]`. We must use a previous head or fail.
        // Since `h` is sorted, `current_h` is the leftmost head we can use for `p[p_idx]` that is not yet used.
        // If `p[p_idx] < current_h - T`, then this `h_idx` head cannot cover `p[p_idx]`.
        // This means no subsequent head `h_idx+1, ...` can cover `p[p_idx]` either, because they are even further right.
        // So, if `p[p_idx] < current_h - T`, it's impossible.
        // This is the condition for failure.

        // If `p[p_idx] >= current_h - T`, then `current_h` can cover `p[p_idx]`.
        // We want to maximize the rightmost track covered by `current_h` while ensuring `p[p_idx]` is covered.
        // There are two main ways `current_h` can cover `p[p_idx]` and extend coverage:
        // 1. Move right: `current_h` moves to `x_R = current_h + T`. This covers `[current_h, current_h + T]`.
        //    This is valid if `p[p_idx]` is in `[current_h, current_h + T]`.
        //    If `p[p_idx] < current_h`, this strategy doesn't cover `p[p_idx]`.
        //    So, if `p[p_idx] >= current_h`, the rightmost covered is `current_h + T`.
        // 2. Move left then right: `current_h` moves left to `p[p_idx]`. Time taken: `current_h - p[p_idx]`.
        //    This is valid if `current_h - p[p_idx] <= T`.
        //    Remaining time: `T - (current_h - p[p_idx])`.
        //    From `p[p_idx]`, it can move right by this remaining time.
        //    Rightmost covered: `p[p_idx] + (T - (current_h - p[p_idx])) = 2 * p[p_idx] - current_h + T`.
        //    This is valid if `p[p_idx] < current_h`.

        // So, if `p[p_idx] < current_h`:
        //   If `current_h - p[p_idx] > T`, then `current_h` cannot reach `p[p_idx]` by moving left.
        //   Since `p[p_idx] < current_h`, `current_h` cannot reach `p[p_idx]` by moving right either.
        //   So, `current_h` cannot cover `p[p_idx]`. Return false.
        //   Otherwise (`current_h - p[p_idx] <= T`), `current_h` can cover `p[p_idx]` by moving left.
        //   The rightmost point it can cover is `2 * p[p_idx] - current_h + T`.
        // If `p[p_idx] >= current_h`:
        //   If `p[p_idx] - current_h > T`, then `current_h` cannot reach `p[p_idx]` by moving right.
        //   Since `p[p_idx] >= current_h`, `current_h` cannot reach `p[p_idx]` by moving left either.
        //   So, `current_h` cannot cover `p[p_idx]`. Return false.
        //   Otherwise (`p[p_idx] - current_h <= T`), `current_h` can cover `p[p_idx]` by moving right.
        //   The rightmost point it can cover is `current_h + T`.

        // Let `max_reach` be the rightmost track that `current_h` can cover, given it must cover `p[p_idx]`.
        long long max_reach;
        if (p[p_idx] < current_h) { // p_start is to the left of current_h
            if (current_h - p[p_idx] > T) { // Cannot reach p_start
                return false; // This head cannot cover p[p_idx], and no subsequent head can either.
            }
            // Head moves left to p[p_idx], then can move right with remaining time.
            max_reach = p[p_idx] + (T - (current_h - p[p_idx]));
        } else { // p_start is at or to the right of current_h
            if (p[p_idx] - current_h > T) { // Cannot reach p_start
                return false; // This head cannot cover p[p_idx], and no subsequent head can either.
            }
            // Head moves right to p[p_idx], then can move further right.
            max_reach = current_h + T;
        }

        // Now, advance p_idx as long as p[p_idx] is covered by max_reach.
        while (p_idx < m && p[p_idx] <= max_reach) {
            p_idx++;
        }
    }
    return p_idx == m;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<long long> h(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> h[i];
    }

    std::vector<long long> p(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> p[i];
    }

    long long low = 0;
    long long high = 2e10 + 7; // Max possible distance between p_m and h_1, or p_1 and h_n.
                               // Max p_i is 10^10, min h_i is 1. Max diff is 10^10.
                               // Max h_i is 10^10, min p_i is 1. Max diff is 10^10.
                               // So 10^10 is a reasonable upper bound.
                               // 2e10 + 7 is safe.

    long long ans = high;

    while (low <= high) {
        long long mid = low + (high - low) / 2;
        if (check(mid, n, m, h, p)) {
            ans = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    std::cout << ans << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

struct Item {
    int value;
    int original_index;
};

bool compareItems(const Item& a, const Item& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n;
        std::cin >> n;
        std::vector<Item> a(n);
        std::vector<Item> b(n);
        for (int i = 0; i < n; ++i) {
            std::cin >> a[i].value;
            a[i].original_index = i;
        }
        for (int i = 0; i < n; ++i) {
            std::cin >> b[i].value;
            b[i].original_index = i;
        }

        std::sort(a.begin(), a.end(), compareItems);
        std::sort(b.begin(), b.end(), compareItems);

        std::vector<int> x(n);
        std::vector<int> y(n);

        for (int i = 0; i < n; ++i) {
            x[a[i].original_index] = a[i].value;
            y[a[i].original_index] = b[n - 1 - i].value;
        }

        for (int i = 0; i < n; ++i) {
            std::cout << x[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << y[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    }
    return 0;
}

#include <iostream>
