#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
    }

    // The strategy is to reverse the permutation.
    // Let p = [p_1, p_2, ..., p_n].
    // The adjacent sums are [p_1+p_2, p_2+p_3, ..., p_{n-1}+p_n].
    // Let p' = [p_n, p_{n-1}, ..., p_1].
    // The adjacent sums for p' are [p_n+p_{n-1}, p_{n-1}+p_{n-2}, ..., p_2+p_1].
    // These are exactly the same sums as for p, just in reverse order.
    // Since the fingerprint is the sorted list of these sums,
    // F(p) will be equal to F(p').
    // We need to ensure p' is different from p.
    // If p is a palindrome (p_i = p_{n-i+1} for all i), then p' would be equal to p.
    // However, a permutation of length n cannot be a palindrome if n > 1.
    // For example, if n=2, p=[1,2], p'=[2,1]. They are different.
    // If n=3, p=[1,2,3], p'=[3,2,1]. They are different.
    // If p is a palindrome, then p_1 = p_n, p_2 = p_{n-1}, etc.
    // But all elements in a permutation must be distinct.
    // So, p_1 must be different from p_n unless n=1 (which is not allowed, n>=2).
    // If p_1 = p_n, then p is not a permutation because p_1 and p_n are distinct elements.
    // Therefore, p_1 != p_n for any permutation of length n >= 2.
    // This means reversing the permutation always produces a different permutation.

    for (int i = n - 1; i >= 0; --i) {
        std::cout << p[i] << (i == 0 ? "" : " ");
    }
    std::cout << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

