int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n;
        long long d; // d can be up to 100, but sum of costs can exceed int if n is large.
                     // However, n is also up to 100, so max cost is 99. Max haybales 100.
                     // 100 * 99 = 9900. d is up to 100.
                     // The problem statement says d <= 100.
                     // So, d fits in int.
        std::cin >> n >> d;
        std::vector<int> a(n);
        for (int i = 0; i < n; ++i) {
            std::cin >> a[i];
        }

        long long current_a1 = a[0]; // Start with initial haybales in pile 1

        for (int i = 1; i < n; ++i) { // Iterate through piles from 2 to n (index 1 to n-1)
            long long pile_idx = i + 1; // 1-based index of the current pile
            long long cost_per_haybale = pile_idx - 1; // Days to move one haybale to pile 1

            if (d >= cost_per_haybale) { // If we have enough days to move at least one haybale from this pile
                long long haybales_available = a[i];

                // Calculate how many haybales we can move from this pile
                // We have 'd' days remaining. Each haybale costs 'cost_per_haybale' days.
                // So, we can move at most d / cost_per_haybale haybales.
                long long haybales_to_move = std::min(haybales_available, d / cost_per_haybale);

                current_a1 += haybales_to_move;
                d -= haybales_to_move * cost_per_haybale;
            } else {
                // If we don't even have enough days to move one haybale from this pile,
                // we can't move any haybales from this pile or any further piles (as they are even farther).
                break; 
            }
        }
        std::cout << current_a1 << std::endl;
    }
    return 0;
}

