#include <vector>
#include <numeric>

void solve() {
    int n;
    std::cin >> n;
    std::vector<long long> a(n);
    std::vector<long long> b(n);
    int count_pos_one = 0;
    int count_neg_one = 0;

    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
        if (a[i] == 1) {
            count_pos_one++;
        } else if (a[i] == -1) {
            count_neg_one++;
        }
    }
    for (int i = 0; i < n; ++i) {
        std::cin >> b[i];
    }

    if (a[0] != b[0]) {
        std::cout << "NO\n";
        return;
    }

    // Adjust counts for a[0]
    if (a[0] == 1) {
        count_pos_one--;
    } else if (a[0] == -1) {
        count_neg_one--;
    }

    for (int i = 1; i < n; ++i) {
        if (a[i] == 1) {
            count_pos_one--;
        } else if (a[i] == -1) {
            count_neg_one--;
        }

        if (a[i] < b[i]) { // Need to increase a[i]
            if (count_pos_one == 0) { // No 1s available to add from left
                std::cout << "NO\n";
                return;
            }
        } else if (a[i] > b[i]) { // Need to decrease a[i]
            if (count_neg_one == 0) { // No -1s available to add from left
                std::cout << "NO\n";
                return;
            }
        }
    }

    std::cout << "YES\n";
}

