#include <iostream>
#include <vector>
#include <algorithm>
#include <cmath>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n;
        std::cin >> n;
        std::vector<long long> a(2 * n);
        for (int i = 0; i < 2 * n; ++i) {
            std::cin >> a[i];
        }
        std::sort(a.begin(), a.end());
        // The median of the first class will be a[n-1]
        // The median of the second class will be a[n]
        // This is because if we split the sorted array into two halves,
        // the first half a[0...n-1] and the second half a[n...2n-1],
        // and assign a[n-1] to the first class and a[n] to the second class,
        // we can always construct valid odd-sized classes.
        // For example, class 1: {a[n-1]}, class 2: {a[0...n-2], a[n...2n-1]}
        // This is not quite right. The problem is about general odd-sized classes.
        //
        // Let's re-evaluate.
        // We have 2n students.
        // The smallest possible odd size for a class is 1.
        // The largest possible odd size for a class is 2n-1.
        //
        // Consider the sorted array a_0, a_1, ..., a_{2n-1}.
        //
        // If we pick a_i as the median of the first class, and a_j as the median of the second class.
        //
        // Let's consider the specific partition where the first class consists of students
        // with skill levels a_0, a_1, ..., a_{n-1} and the second class consists of students
        // with skill levels a_n, a_{n+1}, ..., a_{2n-1}.
        // This partition is not valid because both classes would have size n, which might be even.
        //
        // The key insight is that to minimize the difference between medians,
        // the medians themselves should be as close as possible in the sorted list.
        //
        // Consider the two middle elements in the sorted array: a[n-1] and a[n].
        //
        // Can we always form two odd-sized classes such that a[n-1] is the median of one class
        // and a[n] is the median of the other class?
        //
        // Let's try to make a[n-1] the median of Class 1 and a[n] the median of Class 2.
        //
        // Class 1: {a[n-1]} (size 1, median a[n-1])
        // Class 2: {a[0], ..., a[n-2], a[n], ..., a[2n-1]} (size 2n-1, median a[n])
        //
        // For Class 1 to have median a[n-1], it must have an odd number of elements, say 2k_1+1.
        // a[n-1] must be the (k_1+1)-th element.
        // This means there are k_1 elements smaller than or equal to a[n-1] and k_1 elements greater than or equal to a[n-1] in Class 1.
        //
        // For Class 2 to have median a[n], it must have an odd number of elements, say 2k_2+1.
        // a[n] must be the (k_2+1)-th element.
        // This means there are k_2 elements smaller than or equal to a[n] and k_2 elements greater than or equal to a[n] in Class 2.
        //
        // The simplest way to achieve this is to put a[n-1] in one class and a[n] in the other.
        //
        // Consider the partition:
        // Class 1: {a[n-1]} (size 1, median a[n-1])
        // Class 2: {a[0], a[1], ..., a[n-2], a[n], a[n+1], ..., a[2n-1]}
        //
        // Class 2 has 2n - 1 elements. This is always odd.
        // The elements in Class 2 are sorted. Its median is the ((2n-1)+1)/2 = n-th element.
        // The n-th element of Class 2 (when sorted) is a[n].
        //
        // So, this partition is valid:
        // Class 1: {a[n-1]} (median a[n-1])
        // Class 2: {all other 2n-1 students} (median a[n])
        //
        // The absolute difference is |a[n] - a[n-1]|.
        //
        // Is it possible to get a smaller difference?
        // No, because any two medians must come from the sorted list.
        // If we pick any two elements a_i and a_j as medians, then |a_i - a_j| >= |a[n] - a[n-1]|
        // if i and j are on opposite sides of the n-1, n boundary.
        // If i and j are on the same side, say i, j < n-1, then we would have to move elements
        // to make them medians, which would likely involve elements further apart.
        //
        // The minimum possible difference between any two elements in a sorted array is between adjacent elements.
        // The elements a[n-1] and a[n] are the "most central" adjacent pair.
        //
        // This strategy always works and gives the minimum possible difference.
        // The problem statement implies that such a partition always exists.
        // The construction above proves it.

        long long diff = a[n] - a[n-1];
        std::cout << diff << "\n";
    }
    return 0;
}

