        int last_r_pos = 0; // Represents the position of the last 'R' or the starting point 0.
                            // If last_r_pos = 0, it means the frog is at cell 0.
                            // If last_r_pos = k > 0, it means the frog is at cell k, and s[k-1] was 'R'.

