int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    double h;
    std::cin >> n >> h;

    // The total area of the carrot is A = (1/2) * base * height = (1/2) * 1 * h = h/2.
    // Each of the n pieces must have an area of A_piece = A / n = (h/2) / n = h / (2n).

    // Consider a cut at distance x from the apex.
    // This cut forms a smaller triangle similar to the original one.
    // Let the base of this smaller triangle be b_x.
    // By similar triangles, x / b_x = h / 1, so b_x = x / h.
    // The area of this smaller triangle is A_x = (1/2) * b_x * x = (1/2) * (x/h) * x = x^2 / (2h).

    // We want to find x_k such that the area of the triangle formed by the k-th cut
    // (from the apex) is k times the area of a single piece.
    // That is, A_{x_k} = k * A_piece.
    // x_k^2 / (2h) = k * (h / (2n))
    // x_k^2 = k * h^2 / n
    // x_k = sqrt(k * h^2 / n)
    // x_k = h * sqrt(k / n)

    // We need to find n-1 cuts, for k = 1, 2, ..., n-1.
    for (int k = 1; k < n; ++k) {
        double x_k = h * std::sqrt(static_cast<double>(k) / n);
        std::cout << std::fixed << std::setprecision(12) << x_k << (k == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

