int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        long long c, m, x;
        std::cin >> c >> m >> x;
        // The maximum number of teams 'k' must satisfy:
        // 1. k <= c (at least k coders needed)
        // 2. k <= m (at least k mathematicians needed)
        // 3. 3 * k <= c + m + x (total students available)
        //
        // From 1 and 2, k <= min(c, m).
        // From 3, k <= (c + m + x) / 3.
        //
        // So, k <= min(c, m, (c + m + x) / 3).
        // This condition is also sufficient.
        // Let k_max = min(c, m, (c + m + x) / 3).
        // We can always form k_max teams.
        // We use k_max coders and k_max mathematicians.
        // Remaining coders: c - k_max
        // Remaining mathematicians: m - k_max
        // Remaining no-specialization: x
        // Total remaining students: (c - k_max) + (m - k_max) + x
        // Each team needs 3 members. We've used 2 members (1 coder, 1 mathematician) for each of the k_max teams.
        // So we need k_max more members to fill the teams.
        // The total remaining students must be at least k_max.
        // (c - k_max) + (m - k_max) + x = c + m + x - 2 * k_max.
        // We need c + m + x - 2 * k_max >= k_max, which simplifies to c + m + x >= 3 * k_max.
        // This is exactly the third condition k_max <= (c + m + x) / 3.
        // Since k_max is chosen to satisfy this, we always have enough remaining students to fill the teams.

        long long ans = std::min({c, m, (c + m + x) / 3});
        std::cout << ans << "\n";
    }
    return 0;
}

#include <iostream>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long x;
        std::cin >> x;
        long long count = 0;
        long long current_cost = 1; // Cost for a 1-stair staircase
        long long k = 0; // k for 2^k - 1 stairs
        while (true) {
            // Cost for a staircase with (2^(k+1) - 1) stairs
            // This is 2 * current_cost + (2^(k+1) - 1) * (2^(k+1) - 1)
            // Simplified: 2 * current_cost + (2^(k+1) - 1)^2
            // The number of stairs is 2^(k+1) - 1.
            // The cost is (2^(k+1) - 1) * (2^(k+1)) / 2.
            // This is the sum of cells for a staircase with N stairs.
            // The problem statement implies a specific structure for "nice" staircases.
            // A nice staircase with N stairs is covered by N disjoint squares.
            // The example shows squares of sizes 1x1, 2x2, 4x4 for a 7-stair staircase.
            // This implies that nice staircases have N = 2^k - 1 stairs.
            // The cost for a staircase with N = 2^k - 1 stairs is N * (N+1) / 2.
            // For N = 1 (k=1), cost = 1 * 2 / 2 = 1.
            // For N = 3 (k=2), cost = 3 * 4 / 2 = 6.
            // For N = 7 (k=3), cost = 7 * 8 / 2 = 28.
            // For N = 15 (k=4), cost = 15 * 16 / 2 = 120.
            // The pattern of costs is:
            // C(k) = (2^k - 1) * 2^k / 2
            // C(k) = (2^k - 1) * 2^(k-1)
            // Let's calculate the cost for the next nice staircase.
            // The number of stairs for the k-th nice staircase (0-indexed k) is 2^(k+1) - 1.
            // The cost for this staircase is (2^(k+1) - 1) * (2^(k+1)) / 2.
            // Let N_k = 2^(k+1) - 1.
            // Cost_k = N_k * (N_k + 1) / 2.
            // N_k + 1 = 2^(k+1).
            // Cost_k = (2^(k+1) - 1) * 2^(k+1) / 2 = (2^(k+1) - 1) * 2^k.
            // This is the cost of the (k+1)-th type of nice staircase.
            // Let's use `num_stairs` for 2^k - 1.
            // `num_stairs` starts at 1.
            // `cost_of_staircase` starts at 1.
            // Next `num_stairs` is `2 * num_stairs + 1`.
            // Next `cost_of_staircase` is `(2 * num_stairs + 1) * (2 * num_stairs + 2) / 2`.
            // This simplifies to `(2 * num_stairs + 1) * (num_stairs + 1)`.
            // Let's track `num_stairs` and `cost_of_staircase`.
            // Initial: num_stairs = 1, cost_of_staircase = 1.
            // Loop:
            // If x >= cost_of_staircase:
            //   x -= cost_of_staircase
            //   count++
            //   num_stairs = 2 * num_stairs + 1
            //   cost_of_staircase = (num_stairs) * (num_stairs + 1) / 2
            // Else: break

            // Let's use `current_num_stairs` for the number of stairs in the current type of nice staircase.
            // It starts at 1.
            // The cost for this staircase is `current_num_stairs * (current_num_stairs + 1) / 2`.
            // Let's call this `cost_for_this_type`.
            long long current_num_stairs = (1LL << (k + 1)) - 1; // 2^(k+1) - 1
            long long cost_for_this_type = current_num_stairs * (current_num_stairs + 1) / 2;

            if (x >= cost_for_this_type) {
                x -= cost_for_this_type;
                count++;
                k++;
            } else {
                break;
            }
        }
        std::cout << count << "\n";
    }
    return 0;
}

