int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n, k;
    std::cin >> n >> k;

    int left = 1;
    int right = k + 1; // The largest number we will use for the alternating part to generate k distinct differences

    // Generate k distinct differences: k, k-1, ..., 1
    // This is done by alternating between left and right pointers.
    // Example: k=4. left=1, right=5.
    // 1, 5, 2, 4, 3
    // Differences: |1-5|=4, |5-2|=3, |2-4|=2, |4-3|=1.
    // This generates k distinct differences (k, k-1, ..., 1).

    for (int i = 0; i < k + 1; ++i) {
        if (i % 2 == 0) { // Even index, take from left
            std::cout << left << " ";
            left++;
        } else { // Odd index, take from right
            std::cout << right << " ";
            right--;
        }
    }

    // After generating k distinct differences using numbers from 1 to k+1,
    // the remaining numbers are k+2, k+3, ..., n.
    // We can append these in increasing order to ensure the new differences are 1.
    // Since 1 is already one of the k distinct differences generated,
    // this does not introduce any new distinct differences.
    for (int i = k + 2; i <= n; ++i) {
        std::cout << i << (i == n ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

