int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        long long n, m;
        std::cin >> n >> m;

        if (m > n) {
            std::cout << 0 << "\n";
            continue;
        }

        long long k = n / m; // Number of multiples of m up to n

        // Calculate the sum of last digits for one cycle (10 multiples of m)
        long long cycle_sum = 0;
        for (int i = 1; i <= 10; ++i) {
            cycle_sum += (m * i) % 10;
        }

        // Number of full cycles
        long long num_full_cycles = k / 10;
        long long total_sum = num_full_cycles * cycle_sum;

        // Remaining multiples after full cycles
        long long remaining_multiples = k % 10;
        for (long long i = 1; i <= remaining_multiples; ++i) {
            total_sum += (m * i) % 10;
        }

        std::cout << total_sum << "\n";
    }
    return 0;
}

#include <iostream>
#include <cmath>
#include <iomanip>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        double d;
        std::cin >> d;
        if (d == 0.0) {
            std::cout << "Y 0.000000000 0.000000000\n";
        } else if (d < 4.0) {
            std::cout << "N\n";
        } else {
            // Discriminant: d^2 - 4d
            // For real solutions, d^2 - 4d >= 0
            // d(d - 4) >= 0
            // Since d >= 0, this means d - 4 >= 0, so d >= 4.
            // If d = 0, d^2 - 4d = 0, a = 0, b = 0.
            // If d >= 4, d^2 - 4d >= 0.

            double discriminant = d * d - 4 * d;
            double sqrt_discriminant = std::sqrt(discriminant);

            double a = (d + sqrt_discriminant) / 2.0;
            double b = (d - sqrt_discriminant) / 2.0;

            // Ensure a and b are non-negative.
            // Since d >= 4, d is positive.
            // sqrt_discriminant = sqrt(d(d-4)).
            // If d >= 4, then d-4 >= 0, so sqrt_discriminant is real and non-negative.
            // d + sqrt_discriminant is clearly non-negative.
            // d - sqrt_discriminant:
            // We need to check if d - sqrt(d^2 - 4d) >= 0
            // d >= sqrt(d^2 - 4d)
            // d^2 >= d^2 - 4d (since both sides are non-negative, we can square)
            // 0 >= -4d
            // 4d >= 0
            // This is true since d >= 4.
            // So both a and b are non-negative.

            std::cout << "Y " << std::fixed << std::setprecision(9) << a << " " << b << "\n";
        }
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    std::vector<int> pos(n + 1); // pos[x] stores the 0-indexed position of x in p
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
        pos[p[i]] = i;
    }

    std::string result = "";
    int current_min_idx = pos[1];
    int current_max_idx = pos[1];

    for (int m = 1; m <= n; ++m) {
        // For m=1, the segment is just [1] at pos[1].
        // min_idx and max_idx are initialized to pos[1].
        // Length is 1. Max value is 1.
        // So m=1 is always beautiful.

        // For m > 1, we expand the current segment [current_min_idx, current_max_idx]
        // to include 'm'.
        // The new segment must contain all numbers from 1 to m.
        // This means it must contain pos[1], pos[2], ..., pos[m].
        // The minimum index of these positions will be the new current_min_idx.
        // The maximum index of these positions will be the new current_max_idx.

        // Update current_min_idx and current_max_idx to cover all numbers from 1 to m.
        // This is done by taking the min/max of the current range and pos[m].
        current_min_idx = std::min(current_min_idx, pos[m]);
        current_max_idx = std::max(current_max_idx, pos[m]);

        // A number m is beautiful if there exists a subsegment p[l...r]
        // that is a permutation of 1, 2, ..., m.
        // This implies three conditions:
        // 1. The minimum value in p[l...r] is 1.
        // 2. The maximum value in p[l...r] is m.
        // 3. The length of the subsegment (r - l + 1) is m.

        // By maintaining current_min_idx and current_max_idx, we ensure that
        // the segment p[current_min_idx ... current_max_idx] contains all numbers
        // from 1 to m (and possibly others).
        // The minimum value in this segment is 1 (because it contains pos[1]).
        // The maximum value in this segment is at least m (because it contains pos[m]).
        // If the maximum value in this segment is exactly m, and its length is m,
        // then it must be a permutation of 1 to m.

        // The length of the segment p[current_min_idx ... current_max_idx] is
        // (current_max_idx - current_min_idx + 1).
        // If this length is equal to m, then all numbers from 1 to m must be present
        // in this segment, and no other numbers (because the length is exactly m).
        // Also, since we are expanding the range to include pos[m], the maximum value
        // in this specific segment will be m.

        if (current_max_idx - current_min_idx + 1 == m) {
            result += '1';
        } else {
            result += '0';
        }
    }
    std::cout << result << "\n";
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 2) {
        std::cout << 0 << std::endl;
        return;
    }

    // Find the rightmost peak of a decreasing suffix
    // This is the first element from the right that breaks the non-decreasing suffix
    // Example: [1, 3, 1, 4, 5, 3, 2]
    // Suffix: [2] (non-decreasing)
    // Suffix: [3, 2] (decreasing) -> 3 is the peak
    // Suffix: [5, 3, 2] (decreasing) -> 5 is the peak
    // Suffix: [4, 5, 3, 2] (decreasing) -> 4 is the peak
    // Suffix: [1, 4, 5, 3, 2] (decreasing) -> 1 is the peak
    // Suffix: [3, 1, 4, 5, 3, 2] (decreasing) -> 3 is the peak
    // Suffix: [1, 3, 1, 4, 5, 3, 2] (decreasing) -> 1 is the peak

    // Find the end of the non-decreasing suffix
    int i = n - 1;
    while (i > 0 && a[i-1] >= a[i]) {
        i--;
    }
    // Now, a[i...n-1] is a non-decreasing suffix.
    // If i is 0, the whole array is non-decreasing.
    // If i > 0, then a[i-1] < a[i]. This is the first element from the left that breaks the non-decreasing property.
    // Example: [1, 2, 3, 4] -> i=0
    // Example: [1, 2, 3, 2] -> i=3 (a[2]=3, a[3]=2, a[2] > a[3])
    // Example: [1, 3, 1, 4, 5, 3, 2]
    // i=6: a[5]=3, a[6]=2. a[5] > a[6]. i stops at 6.
    // So, a[6] is the start of the non-decreasing suffix [2].
    // This is not what we want. We want the rightmost peak of a decreasing suffix.

    // Let's re-evaluate.
    // The array `b` is good if it can be split into a non-decreasing prefix and a non-increasing suffix.
    // Example: [1, 2, 3, 4, 4, 2, 1]
    // The split point is after 4 (the second 4).
    // Prefix: [1, 2, 3, 4, 4] (non-decreasing)
    // Suffix: [2, 1] (non-increasing)
    // The elements are taken from ends.
    // The elements taken from the left form a non-decreasing sequence.
    // The elements taken from the right form a non-decreasing sequence.
    // The last element taken from the left must be <= the first element taken from the right.

    // The condition for a good array `b` is that it can be represented as
    // `[b_1, ..., b_k, b_{k+1}, ..., b_m]`
    // where `b_1 <= b_2 <= ... <= b_k` (non-decreasing prefix)
    // AND `b_m <= b_{m-1} <= ... <= b_{k+1}` (non-increasing suffix)
    // This is equivalent to saying that there exists an index `k` (0-indexed) such that
    // `b[0...k]` is non-decreasing and `b[k...m-1]` is non-increasing.
    // This means `b[0] <= b[1] <= ... <= b[k]` and `b[k] >= b[k+1] >= ... >= b[m-1]`.
    // This is a "mountain" or "bitonic" array, but with the peak at `b[k]`.
    // The problem statement example `[1, 2, 3, 4, 4, 2, 1]` is good.
    // Here, `k=4` (0-indexed). `b[0...4]` is `[1, 2, 3, 4, 4]` (non-decreasing).
    // `b[4...6]` is `[4, 2, 1]` (non-increasing).
    // This is the standard definition of a bitonic array.

    // We need to find the smallest `p` such that `a[p...n-1]` is good.
    // Let `b = a[p...n-1]`.
    // We need to find the smallest `p` such that `b` is bitonic.

    // First, find the rightmost index `j` such that `a[j...n-1]` is non-increasing.
    // This means `a[j] >= a[j+1] >= ... >= a[n-1]`.
    // Start from `n-1` and move left.
    int j = n - 1;
    while (j > 0 && a[j-1] >= a[j]) {
        j--;
    }
    // After this loop, `a[j...n-1]` is non-increasing.
    // `j` is the first index from the left of this non-increasing suffix.
    // Example: `[1, 3, 1, 4, 5, 3, 2]`
    // `j=6`: `a[5]=3, a[6]=2`. `a[5] >= a[6]`. `j` becomes 5.
    // `j=5`: `a[4]=5, a[5]=3`. `a[4] >= a[5]`. `j` becomes 4.
    // `j=4`: `a[3]=4, a[4]=5`. `a[3] < a[4]`. Loop stops.
    // So `j=4`. `a[4...6]` is `[5, 3, 2]`, which is non-increasing.
    // The "peak" of this non-increasing suffix is `a[4]=5`.

    // Now, we need to find the rightmost index `i` such that `a[i...j]` is non-decreasing.
    // This means `a[i] <= a[i+1] <= ... <= a[j]`.
    // Start from `j` and move left.
    int i_peak = j; // This is the peak of the bitonic sequence.
    while (i_peak > 0 && a[i_peak-1] <= a[i_peak]) {
        i_peak--;
    }
    // After this loop, `a[i_peak...j]` is non-decreasing.
    // `i_peak` is the first index from the left of this non-decreasing prefix.
    // Example: `[1, 3, 1, 4, 5, 3, 2]` with `j=4`.
    // `i_peak=4`: `a[3]=4, a[4]=5`. `a[3] <= a[4]`. `i_peak` becomes 3.
    // `i_peak=3`: `a[2]=1, a[3]=4`. `a[2] <= a[3]`. `i_peak` becomes 2.
    // `i_peak=2`: `a[1]=3, a[2]=1`. `a[1] > a[2]`. Loop stops.
    // So `i_peak=2`. `a[2...4]` is `[1, 4, 5]`, which is non-decreasing.

    // The subarray `a[i_peak...n-1]` is good.
    // The length of the prefix to erase is `i_peak`.
    std::cout << i_peak << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

