    // Row 2: max(2,4,1,3) = 4. So p[2]=4.
    // Row 3: max(1,1,1,1) = 1. So p[3]=1.
    // Row 4: max(2,3,3,1) = 3. So p[4]=3.
    // Initial p = {2,4,4,1,3}.
    // Is n=5 present in p? No.
    // Find first occurrence of n-1=4 in p. It's p[1]. Change p[1] to n=5.
    // Result: p = {2,5,4,1,3}. This matches example output.

    // This refined logic seems correct and robust.

    // Implementation:
    // 1. Read n.
    // 2. Create vector<int> p(n).
    // 3. Loop i from 0 to n-1:
    //    a. Read row i of matrix a.
    //    b. Calculate max_val_in_row (excluding a[i][i]).
    //    c. Set p[i] = max_val_in_row.
    // 4. Check if n is in p.
    //    a. Use a boolean flag `n_is_present`.
    //    b. Loop through p. If p[i] == n, set `n_is_present = true` and break.
    // 5. If `!n_is_present`:
    //    a. Loop through p. If p[i] == n-1, set p[i] = n and break.
    // 6. Print p.

    // Let's implement this.

    bool n_is_present = false;
    for (int i = 0; i < n; ++i) {
        int max_val_in_row = 0;
        for (int j = 0; j < n; ++j) {
            std::cin >> a[i][j]; // Read a_i,j
            if (i != j) {
                max_val_in_row = std::max(max_val_in_row, a[i][j]);
            }
        }
        p[i] = max_val_in_row;
        if (p[i] == n) { // Check if n is already assigned by this rule
            n_is_present = true;
        }
    }

    if (!n_is_present) {
        // If n was not assigned, it means that for the actual p_k = n,
        // max_val_in_row for k was n-1. So p[k] was set to n-1.
        // We need to find one such n-1 and change it to n.
        // Since any solution is fine, we can pick the first one.
        for (int i = 0; i < n; ++i) {
            if (p[i] == n - 1) {
                p[i] = n;
                break; // Only one such change is needed
            }
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

