// Function to determine if a box can be the special box
// A, B, C, D are initial counts of toys in boxes 1, 2, 3, 4 respectively.
// target_box is the box we are checking (0-indexed: 0 for Box 1, 1 for Box 2, etc.)
bool can_be_special(long long A, long long B, long long C, long long D, int target_box) {
    long long total_toys = A + B + C + D;
    if (total_toys == 0) return false; // Should not happen based on constraints A+B+C+D > 0

    // If there's only one toy, it must be the super toy.
    // The special box is the one it's currently in.
    if (total_toys == 1) {
        if (A == 1 && target_box == 0) return true;
        if (B == 1 && target_box == 1) return true;
        if (C == 1 && target_box == 2) return true;
        if (D == 1 && target_box == 3) return true;
        return false;
    }

    // Case 1: Box 1 (fun value <= -1)
    // Requires a negative final product with magnitude >= 1.
    if (target_box == 0) {
        // To get a negative product, we need an odd number of negative factors.
        // To get magnitude >= 1, we need to be able to achieve it.
        // The total number of negative toys is A + B.
        // If (A + B) is odd, the final product can be negative.
        if ((A + B) % 2 == 1) {
            // If there's at least one toy in Box 1 or Box 4, we can potentially make magnitude >= 1.
            // If all toys are in Box 2 and Box 3, the magnitude will always be < 1.
            // So, if A+D > 0, we can achieve magnitude >= 1.
            // Exception: if A+D=0, then all toys are in B and C.
            // In this case, the final product will always have magnitude < 1.
            // So, if A+D == 0, it's impossible to end up in Box 1.
            if (A + D > 0) {
                return true;
            }
        }
        return false;
    }

    // Case 2: Box 2 (fun value in (-1, 0))
    // Requires a negative final product with magnitude < 1.
    if (target_box == 1) {
        // To get a negative product, we need an odd number of negative factors.
        // If (A + B) is odd, the final product can be negative.
        if ((A + B) % 2 == 1) {
            // To get magnitude < 1, we need to be able to achieve it.
            // If there's at least one toy in Box 2 or Box 3, we can potentially make magnitude < 1.
            // If all toys are in Box 1 and Box 4, the magnitude will always be >= 1.
            // So, if B+C > 0, we can achieve magnitude < 1.
            // Exception: if B+C == 0, then all toys are in A and D.
            // In this case, the final product will always have magnitude >= 1.
            // So, if B+C == 0, it's impossible to end up in Box 2.
            if (B + C > 0) {
                return true;
            }
        }
        return false;
    }

    // Case 3: Box 3 (fun value in (0, 1))
    // Requires a positive final product with magnitude < 1.
    if (target_box == 2) {
        // To get a positive product, we need an even number of negative factors.
        // If (A + B) is even, the final product can be positive.
        if ((A + B) % 2 == 0) {
            // To get magnitude < 1, we need to be able to achieve it.
            // If there's at least one toy in Box 2 or Box 3, we can potentially make magnitude < 1.
            // If all toys are in Box 1 and Box 4, the magnitude will always be >= 1.
            // So, if B+C > 0, we can achieve magnitude < 1.
            // Exception: if B+C == 0, then all toys are in A and D.
            // In this case, the final product will always have magnitude >= 1.
            // So, if B+C == 0, it's impossible to end up in Box 3.
            if (B + C > 0) {
                return true;
            }
        }
        return false;
    }

    // Case 4: Box 4 (fun value >= 1)
    // Requires a positive final product with magnitude >= 1.
    if (target_box == 3) {
        // To get a positive product, we need an even number of negative factors.
        // If (A + B) is even, the final product can be positive.
        if ((A + B) % 2 == 0) {
            // To get magnitude >= 1, we need to be able to achieve it.
            // If there's at least one toy in Box 1 or Box 4, we can potentially make magnitude >= 1.
            // If all toys are in Box 2 and Box 3, the magnitude will always be < 1.
            // So, if A+D > 0, we can achieve magnitude >= 1.
            // Exception: if A+D == 0, then all toys are in B and C.
            // In this case, the final product will always have magnitude < 1.
            // So, if A+D == 0, it's impossible to end up in Box 4.
            if (A + D > 0) {
                return true;
            }
        }
        return false;
    }

    return false; // Should not be reached
}

