#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n == 1) {
        std::cout << "Yes\n";
        return;
    }

    // Calculate the minimum possible values for the increasing prefix
    // b_i >= i-1 for 0-indexed array
    // b_i >= i for 1-indexed array
    // b_i <= a_i
    // So, we need a_i >= i for the increasing part to be possible up to index i.
    // Specifically, for a_0, a_1, ..., a_{k-1}
    // b_0 >= 0
    // b_1 >= 1
    // ...
    // b_{k-1} >= k-1
    // This means we must have a_i >= i for all i from 0 to k-1.
    // The first index `i` where `a_i < i` breaks this possibility.
    int first_bad_left = -1;
    for (int i = 0; i < n; ++i) {
        if (a[i] < i) {
            first_bad_left = i;
            break;
        }
    }

    // Calculate the minimum possible values for the decreasing suffix
    // For a_k, a_{k+1}, ..., a_{n-1}
    // b_{n-1} >= 0
    // b_{n-2} >= 1
    // ...
    // b_i >= (n-1) - i
    // This means we must have a_i >= (n-1) - i for all i from k to n-1.
    // The first index `i` (from right) where `a_i < (n-1) - i` breaks this possibility.
    int first_bad_right = -1;
    for (int i = n - 1; i >= 0; --i) {
        if (a[i] < (n - 1) - i) {
            first_bad_right = i;
            break;
        }
    }

    // If first_bad_left is -1, it means a_i >= i for all i from 0 to n-1.
    // This implies we can form an increasing sequence 0, 1, ..., n-1.
    // If first_bad_right is -1, it means a_i >= (n-1)-i for all i from 0 to n-1.
    // This implies we can form a decreasing sequence n-1, n-2, ..., 0.

    // A sharpened array requires a peak k (0-indexed: 0 to n-1).
    // The increasing part is a_0 < a_1 < ... < a_k.
    // The decreasing part is a_k > a_{k+1} > ... > a_{n-1}.
    //
    // For the increasing part up to k:
    // We need b_i >= i for i <= k.
    // This means a_i must be at least i for i <= k.
    //
    // For the decreasing part from k:
    // We need b_i >= (n-1) - i for i >= k.
    // This means a_i must be at least (n-1) - i for i >= k.
    //
    // So, we need to find if there exists a k such that:
    // (a_i >= i for all i from 0 to k) AND (a_i >= (n-1) - i for all i from k to n-1).
    //
    // This is equivalent to checking if there is any index `k` such that
    // `k` is not "bad from left" AND `k` is not "bad from right".
    //
    // An index `i` is "bad from left" if `a_i < i`.
    // An index `i` is "bad from right" if `a_i < (n-1) - i`.
    //
    // If `first_bad_left` is -1, it means all `a_i >= i`.
    // If `first_bad_right` is -1, it means all `a_i >= (n-1)-i`.
    //
    // If `first_bad_left` is -1, then any `k` from 0 to n-1 satisfies the left condition.
    // If `first_bad_right` is -1, then any `k` from 0 to n-1 satisfies the right condition.
    //
    // If `first_bad_left` is `x`, then for any `k >= x`, the left condition `a_i >= i` for `i <= k` fails at `i=x`.
    // So, `k` must be less than `x`.
    //
    // If `first_bad_right` is `y`, then for any `k <= y`, the right condition `a_i >= (n-1)-i` for `i >= k` fails at `i=y`.
    // So, `k` must be greater than `y`.
    //
    // Combining these: we need to find a `k` such that `k < first_bad_left` AND `k > first_bad_right`.
    // Such a `k` exists if and only if `first_bad_left > first_bad_right + 1`.
    // (Because if `first_bad_left = x` and `first_bad_right = y`, we need `y < k < x`.
    // The smallest `k` is `y+1`, largest is `x-1`. We need `y+1 <= x-1`, or `y+2 <= x`, or `x > y+1`).
    //
    // If `first_bad_left` is -1, it means all `a_i >= i`. So `first_bad_left` can be considered `n`.
    // If `first_bad_right` is -1, it means all `a_i >= (n-1)-i`. So `first_bad_right` can be considered `-1`.

    int effective_first_bad_left = (first_bad_left == -1) ? n : first_bad_left;
    int effective_first_bad_right = (first_bad_right == -1) ? -1 : first_bad_right;

    if (effective_first_bad_left > effective_first_bad_right) {
        std::cout << "Yes\n";
    } else {
        std::cout << "No\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

