struct ElementA {
    long long value;
    int original_index;
};

struct ElementB {
    long long value;
    int original_index;
};

bool compareA(const ElementA& a, const ElementA& b) {
    return a.value < b.value;
}

bool compareB(const ElementB& a, const ElementB& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int m;
    std::cin >> m;

    std::vector<ElementA> A(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> A[i].value;
        A[i].original_index = i;
    }

    std::vector<ElementB> B(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> B[i].value;
        B[i].original_index = i;
    }

    std::sort(A.begin(), A.end(), compareA);
    std::sort(B.begin(), B.end(), compareB);

    std::vector<long long> result_A_prime(m);
    for (int i = 0; i < m; ++i) {
        // The i-th smallest B value (B[i].value) should be paired with
        // the (m-1-i)-th largest A value (A[m-1-i].value)
        // which is equivalent to the i-th smallest A value from the end.
        result_A_prime[B[i].original_index] = A[m - 1 - i].value;
    }

    for (int i = 0; i < m; ++i) {
        std::cout << result_A_prime[i] << (i == m - 1 ? "" : " ");
    }
    std::cout << std::endl;

