    std::cin >> n;
    long long current_sum = 0;
    long long current_xor = 0;
    for (int i = 0; i < n; ++i) {
        long long a;
        std::cin >> a;
        current_sum += a;
        current_xor ^= a;
    }

    // We need to find b1, b2, b3 such that (current_sum + b1 + b2 + b3) = 2 * (current_xor ^ b1 ^ b2 ^ b3)
    // Let X = current_xor and S = current_sum.
    // We need S' = 2 * X', where S' = S + sum(b_i) and X' = X ^ xor(b_i).
    //
    // Consider appending two numbers: X and S + X.
    // New XOR: X' = current_xor ^ X ^ (S + X)
    // Since current_xor is X, X' = X ^ X ^ (S + X) = 0 ^ (S + X) = S + X.
    // New SUM: S' = current_sum + X + (S + X) = S + X + S + X = 2S + 2X.
    //
    // Check condition: S' = 2 * X'
    // 2S + 2X = 2 * (S + X)
    // This is always true.
    //
    // So, we can always append two numbers: current_xor and current_sum + current_xor.
    // The problem states we can append at most 3 elements.
    // This strategy uses 2 elements.

    // Output 2 elements
    std::cout << 2 << std::endl;
    std::cout << current_xor << " " << current_sum + current_xor << std::endl;
}

