char get_winning_move(char bot_move) {
    if (bot_move == 'R') return 'P';
    if (bot_move == 'S') return 'R';
    if (bot_move == 'P') return 'S';
    return ' '; // Should not happen
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        std::string s;
        std::cin >> s;

        std::map<char, int> counts;
        for (char c : s) {
            counts[c]++;
        }

        char most_frequent_bot_move = ' ';
        int max_count = -1;

        // Iterate in a fixed order to ensure consistent tie-breaking
        // R, P, S is arbitrary but consistent.
        // The problem statement implies any optimal answer is fine.
        // If R is most frequent, we play P.
        // If P is most frequent, we play S.
        // If S is most frequent, we play R.

        if (counts['R'] > max_count) {
            max_count = counts['R'];
            most_frequent_bot_move = 'R';
        }
        if (counts['P'] > max_count) {
            max_count = counts['P'];
            most_frequent_bot_move = 'P';
        }
        if (counts['S'] > max_count) {
            max_count = counts['S'];
            most_frequent_bot_move = 'S';
        }

        char our_optimal_move = get_winning_move(most_frequent_bot_move);

        for (int i = 0; i < s.length(); ++i) {
            std::cout << our_optimal_move;
        }
        std::cout << "\n";
    }
    return 0;
}

#include <iostream>

long long solve() {
    long long n;
    std::cin >> n;

    long long chanek_score = 0;

    // Strategy:
    // If N is odd, Chanek must take 1. N becomes even.
    // If N is even:
    //   If N is a power of 2 (and N > 2), Chanek takes N/2.
    //   If N is even but not a power of 2, Chanek takes 1.
    // This strategy aims to leave the opponent with an odd number of coins
    // or a power of 2, which limits their options.

    while (n > 0) {
        if (n % 2 != 0) { // N is odd
            chanek_score += 1;
            n -= 1;
        } else { // N is even
            // Check if N is a power of 2
            // A number is a power of 2 if (n > 0) and (n & (n - 1)) == 0
            if ((n & (n - 1)) == 0) { // N is a power of 2
                // If N is a power of 2, taking N/2 is optimal for Chanek
                // if it's his turn and N > 2.
                // If N=2, taking 1 or N/2=1 leads to the same result (Chanek gets 1).
                // If N=4, Chanek takes 2. Opponent faces 2. Opponent takes 1. Chanek faces 1. Chanek takes 1.
                // Chanek: 2+1=3. Opponent: 1.
                // If N=4, Chanek takes 1. Opponent faces 3. Opponent takes 1. Chanek faces 2. Chanek takes 1. Opponent faces 1. Opponent takes 1.
                // Chanek: 1+1=2. Opponent: 1+1=2.
                // So for N=4, taking N/2 is better.
                // This logic holds for all powers of 2.
                chanek_score += n / 2;
                n /= 2;
            } else { // N is even but not a power of 2
                // If N is even and not a power of 2, it means N has at least one odd factor > 1.
                // Taking 1 makes N odd, forcing opponent to take 1.
                // Taking N/2 makes N smaller.
                // Example: N=6.
                // Chanek takes 1: N=5. Opponent takes 1. N=4. Chanek takes 1. N=3. Opponent takes 1. N=2. Chanek takes 1. N=1. Opponent takes 1. N=0.
                // Chanek: 1+1+1=3. Opponent: 1+1+1=3.
                // Example: N=6.
                // Chanek takes N/2=3: N=3. Opponent takes 1. N=2. Chanek takes 1. N=1. Opponent takes 1. N=0.
                // Chanek: 3+1=4. Opponent: 1+1=2.
                // Taking N/2 is better for N=6.
                // This suggests that if N is even, Chanek should always take N/2.
                // Let's re-evaluate the strategy.
                // The optimal strategy for Chanek is to always take N/2 if N is even,
                // unless N is a power of 2 and N > 2, in which case taking N/2 is also good.
                // The only case where taking 1 might be better is if N is a power of 2 and N=2.
                // But for N=2, taking 1 or N/2=1 yields the same result for Chanek (1 coin).
                // So, if N is even, Chanek always takes N/2.
                chanek_score += n / 2;
                n /= 2;
            }
        }

        // Opponent's turn
        if (n > 0) {
            if (n % 2 != 0) { // N is odd
                n -= 1;
            } else { // N is even
                // Opponent also plays optimally to maximize their score.
                // This means they will also take N/2 if N is even.
                n /= 2;
            }
        }
    }
    return chanek_score;
}

