int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;

    long long total_steps = 0;
    long long count_a = 0;
    long long mod = 1e9 + 7;

    // Iterate the string from right to left
    for (int i = s.length() - 1; i >= 0; --i) {
        if (s[i] == 'b') {
            // If we encounter a 'b', it means this 'b' can be paired with
            // all 'a's to its left that are currently active.
            // Each such 'a' will cause an 'ab' -> 'bba' transformation.
            // The 'a' moves past this 'b', and a new 'b' is created.
            // The number of steps for this 'b' is equal to the current count_a.
            // After this 'b' is processed, it effectively doubles the number
            // of 'a's that will be processed by subsequent 'b's to its left.
            // This is because each 'a' that passes this 'b' creates a new 'b'.
            // So, for every 'a' that passes this 'b', there will be two 'b's
            // for the 'a's further left to interact with.
            // This means the count_a effectively doubles for the next 'b' to its left.
            total_steps = (total_steps + count_a) % mod;
            count_a = (count_a * 2) % mod;
        } else { // s[i] == 'a'
            // If we encounter an 'a', it simply adds to the count of 'a's
            // that are available to be processed by 'b's to its left.
            count_a = (count_a + 1) % mod;
        }
    }

    std::cout << total_steps << std::endl;

    return 0;
}

