    int n;
    long long l, r, Ql, Qr;
    std::cin >> n >> l >> r >> Ql >> Qr;

    std::vector<long long> w(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> w[i];
    }

    std::vector<long long> prefix_sum(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        prefix_sum[i + 1] = prefix_sum[i] + w[i];
    }

    long long min_energy = -1;

    // Iterate through all possible counts of items taken from the left
    // `i` represents the number of items taken from the left (0 to n)
    for (int i = 0; i <= n; ++i) {
        int j = n - i; // Number of items taken from the right

        long long current_energy = 0;

        // Energy for items taken from the left
        current_energy += prefix_sum[i] * l;

        // Energy for items taken from the right
        current_energy += (prefix_sum[n] - prefix_sum[n - j]) * r;

        // Penalties
        if (i > j) { // More items from left than right
            current_energy += (i - j - 1) * Ql;
        } else if (j > i) { // More items from right than left
            current_energy += (j - i - 1) * Qr;
        }
        // If i == j, no penalty

        if (min_energy == -1 || current_energy < min_energy) {
            min_energy = current_energy;
        }
    }

    std::cout << min_energy << std::endl;

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <numeric>

void solve() {
    std::string s;
    std::cin >> s;
    int x;
    std::cin >> x;

    int n = s.length();
    std::string w(n, '1'); // Initialize w with all '1's

    // First pass: Use s[i] == '0' to determine '0's in w
    for (int i = 0; i < n; ++i) {
        if (s[i] == '0') {
            // If s[i] is '0', then w[i-x] must be '0' (if it exists)
            if (i - x >= 0) {
                w[i - x] = '0';
            }
            // And w[i+x] must be '0' (if it exists)
            if (i + x < n) {
                w[i + x] = '0';
            }
        }
    }

    // Second pass: Verify if the constructed w can produce s
    std::string s_reconstructed(n, '0');
    for (int i = 0; i < n; ++i) {
        // Check w[i-x]
        if (i - x >= 0 && w[i - x] == '1') {
            s_reconstructed[i] = '1';
        }
        // Check w[i+x]
        if (i + x < n && w[i + x] == '1') {
            s_reconstructed[i] = '1';
        }
    }

    if (s_reconstructed == s) {
        std::cout << w << std::endl;
    } else {
        std::cout << -1 << std::endl;
    }
}

