#include <iostream>
#include <string>
#include <vector>
#include <algorithm> // For std::abs

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::string s;
    std::cin >> s;

    int n = s.length();

    // Prefix sums for counts of 'x', 'y', 'z'
    // counts[0][i] = count of 'x' in s[0...i-1]
    // counts[1][i] = count of 'y' in s[0...i-1]
    // counts[2][i] = count of 'z' in s[0...i-1]
    std::vector<std::vector<int>> counts(3, std::vector<int>(n + 1, 0));

    for (int i = 0; i < n; ++i) {
        counts[0][i + 1] = counts[0][i];
        counts[1][i + 1] = counts[1][i];
        counts[2][i + 1] = counts[2][i];
        if (s[i] == 'x') {
            counts[0][i + 1]++;
        } else if (s[i] == 'y') {
            counts[1][i + 1]++;
        } else { // s[i] == 'z'
            counts[2][i + 1]++;
        }
    }

    int m;
    std::cin >> m;

    for (int k = 0; k < m; ++k) {
        int l, r;
        std::cin >> l >> r; // 1-indexed

        // Convert to 0-indexed
        int start_idx = l - 1;
        int end_idx = r - 1;

        if (end_idx - start_idx + 1 < 3) {
            // Substring length is less than 3, no 3-char subsequence exists.
            // The algorithm terminates immediately.
            std::cout << "YES\n";
        } else {
            // Calculate counts of 'x', 'y', 'z' in the substring s[start_idx...end_idx]
            int count_x = counts[0][end_idx + 1] - counts[0][start_idx];
            int count_y = counts[1][end_idx + 1] - counts[1][start_idx];
            int count_z = counts[2][end_idx + 1] - counts[2][start_idx];

            // The algorithm works correctly if the counts of 'x', 'y', 'z'
            // in the substring are "balanced" enough, meaning that
            // the difference between any two counts is at most 1.
            // This ensures that it's possible to form a 3-character substring
            // that is not a permutation of 'x', 'y', 'z' (e.g., "xxx", "xyy")
            // or a permutation that is not one of the forbidden ones ("xyz", "yzx", "zxy").
            // If the counts are too skewed (e.g., 3,0,0 or 2,1,0), it's always possible
            // to find a 3-char substring that is not "zyx", "xzy", "yxz" and rearrange it.
            // The only case where it might run infinitely is if all 3-char substrings
            // are permutations of 'x', 'y', 'z' AND are one of "zyx", "xzy", "yxz".
            // This implies that the counts of 'x', 'y', 'z' in the *entire* substring
            // must be very close to each other.
            // Specifically, if max_count - min_count <= 1, then it's possible to terminate.
            // Otherwise, if max_count - min_count >= 2, it's impossible to terminate.

            int max_c = std::max({count_x, count_y, count_z});
            int min_c = std::min({count_x, count_y, count_z});

            if (max_c - min_c <= 1) {
                std::cout << "YES\n";
            } else {
                std::cout << "NO\n";
            }
        }
    }

    return 0;
}

