// Function to find prime factors of a number
std::vector<long long> get_prime_factors(long long n) {
    std::vector<long long> factors;
    for (long long i = 2; i * i <= n; ++i) {
        if (n % i == 0) {
            factors.push_back(i);
            while (n % i == 0) {
                n /= i;
            }
        }
    }
    if (n > 1) {
        factors.push_back(n);
    }
    return factors;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long p, q;
        std::cin >> p >> q;

        if (p % q != 0) {
            std::cout << p << "\n";
            continue;
        }

        // p is divisible by q. We need to find the largest x < p such that x | p and x % q != 0.
        // This means x must be p / (some factor d) such that (p/d) % q != 0.
        // To maximize x, we need to minimize d.
        // The condition x % q != 0 means that x must be missing at least one prime factor of q,
        // or have a lower power of some prime factor of q, compared to q itself.

        // Get prime factors of q
        std::vector<long long> q_prime_factors = get_prime_factors(q);

        long long max_x = 1;

        for (long long factor : q_prime_factors) {
            // For each prime factor 'factor' of q, we want to remove just enough 'factor's from p
            // such that the resulting number is no longer divisible by q.
            // We do this by dividing p by 'factor' repeatedly until it's no longer divisible by q.
            // The resulting number p_temp will be a candidate for x.

            long long p_temp = p;
            while (p_temp % factor == 0 && (p_temp / factor) % q == 0) {
                p_temp /= factor;
            }
            // After the loop, p_temp is the largest divisor of p that is not divisible by q,
            // *if* the only reason p_temp is not divisible by q is because it has fewer 'factor's.
            // This p_temp is a candidate for max_x.
            max_x = std::max(max_x, p_temp);
        }
        std::cout << max_x << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::string s;
    std::cin >> s;

    for (int pivot = 0; pivot <= 9; ++pivot) {
        std::string coloring(n, ' ');
        std::vector<int> s1_digits;
        std::vector<int> s2_digits;
        bool possible_pivot = true;

        for (int i = 0; i < n; ++i) {
            int digit = s[i] - '0';
            if (digit < pivot) {
                coloring[i] = '1';
                s1_digits.push_back(digit);
            } else if (digit > pivot) {
                coloring[i] = '2';
                s2_digits.push_back(digit);
            }
        }

        // Check if s1_digits is sorted
        for (size_t i = 0; i + 1 < s1_digits.size(); ++i) {
            if (s1_digits[i] > s1_digits[i+1]) {
                possible_pivot = false;
                break;
            }
        }
        if (!possible_pivot) continue;

        // Check if s2_digits is sorted
        for (size_t i = 0; i + 1 < s2_digits.size(); ++i) {
            if (s2_digits[i] > s2_digits[i+1]) {
                possible_pivot = false;
                break;
            }
        }
        if (!possible_pivot) continue;

        // Handle digits equal to pivot
        // First, assign all pivot digits to color 2, then try to assign some to color 1
        std::string temp_coloring = coloring;
        std::vector<int> temp_s1_digits = s1_digits;
        std::vector<int> temp_s2_digits = s2_digits;

        int last_s1_val = -1;
        if (!temp_s1_digits.empty()) {
            last_s1_val = temp_s1_digits.back();
        }

        for (int i = 0; i < n; ++i) {
            int digit = s[i] - '0';
            if (digit == pivot) {
                if (digit >= last_s1_val) { // Can potentially be part of S1
                    temp_coloring[i] = '1';
                    temp_s1_digits.push_back(digit);
                    last_s1_val = digit;
                } else { // Must be part of S2
                    temp_coloring[i] = '2';
                    temp_s2_digits.push_back(digit);
                }
            }
        }

        // Final check for temp_s1_digits and temp_s2_digits
        bool current_coloring_valid = true;
        for (size_t i = 0; i + 1 < temp_s1_digits.size(); ++i) {
            if (temp_s1_digits[i] > temp_s1_digits[i+1]) {
                current_coloring_valid = false;
                break;
            }
        }
        if (!current_coloring_valid) continue;

        for (size_t i = 0; i + 1 < temp_s2_digits.size(); ++i) {
            if (temp_s2_digits[i] > temp_s2_digits[i+1]) {
                current_coloring_valid = false;
                break;
            }
        }
        if (!current_coloring_valid) continue;

        if (!temp_s1_digits.empty() && !temp_s2_digits.empty()) {
            if (temp_s1_digits.back() > temp_s2_digits.front()) {
                current_coloring_valid = false;
            }
        }

        if (current_coloring_valid) {
            std::cout << temp_coloring << "\n";
            return;
        }
    }

    std::cout << "-\n";
}

