    long long a, b;
    std::cin >> a >> b;

    long long MOD = 1000000007;

    // Calculate sum_r = sum_{r=1}^{b-1} r
    // sum_r = (b-1) * b / 2
    long long sum_r_val = (b - 1);
    if (sum_r_val < 0) sum_r_val = 0; // Handle b=1 case where b-1 is 0
    sum_r_val = (sum_r_val % MOD * (b % MOD)) % MOD;
    sum_r_val = (sum_r_val * ((MOD + 1) / 2)) % MOD; // Multiply by 2^-1 mod MOD

    // Calculate sum_k = sum_{k=1}^{a} k
    // sum_k = a * (a+1) / 2
    long long sum_k_val = (a % MOD * ((a + 1) % MOD)) % MOD;
    sum_k_val = (sum_k_val * ((MOD + 1) / 2)) % MOD; // Multiply by 2^-1 mod MOD

    // The total sum is (sum_k * b * sum_r) + (a * sum_r)
    // Sum = (sum_k_val * (b % MOD) % MOD * sum_r_val % MOD) + (a % MOD * sum_r_val % MOD)
    // Sum = (sum_k_val * (b % MOD) + (a % MOD)) % MOD * sum_r_val % MOD

    long long term1 = (sum_k_val * (b % MOD)) % MOD;
    long long term2 = a % MOD;

    long long total_sum = ((term1 + term2) % MOD * sum_r_val) % MOD;

    std::cout << total_sum << std::endl;

    return 0;
}

