int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;
    int L = s.length();

    std::vector<std::vector<int>> char_indices(26);
    for (int i = 0; i < L; ++i) {
        char_indices[s[i] - 'a'].push_back(i);
    }

    double total_win_probability = 0.0;

    for (int first_char_code = 0; first_char_code < 26; ++first_char_code) {
        const std::vector<int>& possible_k_for_char = char_indices[first_char_code];
        int num_possible_k = possible_k_for_char.size();

        if (num_possible_k == 0) {
            continue;
        }
        if (num_possible_k == 1) {
            total_win_probability += 1.0; // If only one k matches t[0], Vasya wins for sure.
            continue;
        }

        // If num_possible_k > 1, Vasya needs to pick a second position.
        // He wants to maximize the probability of winning for this specific t[0].
        double max_win_prob_for_this_char = 0.0;

        // Iterate through all possible second positions p (from 1 to L-1)
        for (int p = 1; p < L; ++p) {
            // For a fixed p, count how many k values are uniquely determined.
            int uniquely_determined_count = 0;

            // Group possible_k values by the pair (s[k], s[(k+p)%L])
            // A map from pair<char, char> to vector<int> (list of k's)
            std::vector<std::vector<int>> groups_by_second_char(26);

            for (int k_val : possible_k_for_char) {
                groups_by_second_char[s[(k_val + p) % L] - 'a'].push_back(k_val);
            }

            for (int second_char_code = 0; second_char_code < 26; ++second_char_code) {
                if (groups_by_second_char[second_char_code].size() == 1) {
                    uniquely_determined_count++;
                }
            }

            max_win_prob_for_this_char = std::max(max_win_prob_for_this_char, (double)uniquely_determined_count / num_possible_k);
        }
        total_win_probability += max_win_prob_for_this_char;
    }

    std::cout << std::fixed << std::setprecision(15) << total_win_probability / L << std::endl;

    return 0;
}

