#include <iostream>
#include <string>
#include <vector>
#include <numeric>
#include <algorithm>
#include <set>
#include <map>

void solve() {
    std::string s;
    std::cin >> s;

    std::map<char, std::set<char>> adj;
    for (size_t i = 0; i < s.length() - 1; ++i) {
        adj[s[i]].insert(s[i+1]);
        adj[s[i+1]].insert(s[i]);
    }

    bool possible = true;
    for (const auto& pair : adj) {
        if (pair.second.size() > 2) {
            possible = false;
            break;
        }
    }

    if (!possible) {
        std::cout << "NO\n";
        return;
    }

    std::string keyboard_layout = "";
    std::vector<bool> used(26, false); // 'a' -> 0, 'b' -> 1, ...

    char start_char = '\0';
    for (char c = 'a'; c <= 'z'; ++c) {
        if (adj.count(c) && adj[c].size() == 1) {
            start_char = c;
            break;
        }
    }

    if (start_char == '\0') { // All connected components are cycles or single nodes
        // Find any character that is part of an adjacency (degree 2 or 0)
        for (char c = 'a'; c <= 'z'; ++c) {
            if (adj.count(c)) { // If it has any adjacencies, it's part of a component
                start_char = c;
                break;
            }
        }
    }

    if (start_char != '\0') { // If there's at least one character with adjacencies
        char current_char = start_char;
        char prev_char = '\0'; // Sentinel for the first character

        while (current_char != '\0' && !used[current_char - 'a']) {
            keyboard_layout += current_char;
            used[current_char - 'a'] = true;

            char next_char = '\0';
            if (adj.count(current_char)) {
                for (char neighbor : adj[current_char]) {
                    if (neighbor != prev_char) {
                        next_char = neighbor;
                        break;
                    }
                }
            }
            prev_char = current_char;
            current_char = next_char;
        }

        // Check if we formed a cycle that includes the start_char and all its neighbors
        // This happens if current_char is start_char and start_char has degree 2
        if (current_char != '\0' && current_char == start_char && adj[start_char].size() == 2) {
            // This means we completed a cycle. All characters in this cycle are used.
            // This is a valid component.
        } else if (current_char != '\0' && !used[current_char - 'a']) {
            // This means we tried to add a character that was already used, but it wasn't the start_char
            // and it wasn't a cycle completion. This implies a character has degree > 2 effectively
            // or a complex structure not allowed.
            possible = false;
        }
    }

    if (!possible) {
        std::cout << "NO\n";
        return;
    }

    // Add remaining unused characters
    for (char c = 'a'; c <= 'z'; ++c) {
        if (!used[c - 'a']) {
            keyboard_layout += c;
        }
    }

    // Final check: ensure all characters that had adjacencies are included in the layout
    // and that the layout length is 26.
    if (keyboard_layout.length() != 26) {
        // This case should ideally not be reached if logic is correct,
        // as we add all unused characters.
        // It might indicate an issue if a component was not fully traversed.
        possible = false; // Defensive check
    }

    // One more check for validity:
    // If any character in `adj` was not included in the `keyboard_layout`
    // or if the `keyboard_layout` has duplicates (which `used` array prevents)
    // or if `keyboard_layout` is not 26 chars (which the final loop prevents)
    // The main issue would be if the graph structure was invalid (e.g., a character with degree > 2)
    // which is already checked.
    // The only remaining failure case is if the traversal logic failed to correctly
    // build a path for a valid component.
    // The current logic correctly handles paths and cycles.
    // If `start_char` was `\0`, it means all characters in `s` had degree 0.
    // This implies `s` was empty or `s` had only one character.
    // In this case, `keyboard_layout` would be empty and then filled with all 26 chars.
    // This is fine.

    // The only way `possible` could be false at this point is if the initial degree check failed.
    // Or if the traversal logic somehow failed to build a valid path for a valid component.
    // The traversal logic for paths and cycles is standard.
    // The only way it could fail is if a character was visited twice in a path (not a cycle)
    // which implies degree > 2, already checked.

    std::cout << "YES\n";
    std::cout << keyboard_layout << "\n";
}

