#include <algorithm>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 2) { // Sequences of length 1 or 2 are always stable
        std::cout << 0 << std::endl;
        for (int i = 0; i < n; ++i) {
            std::cout << a[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << std::endl;
        return 0;
    }

    std::vector<int> left_zero_run(n);
    std::vector<int> right_zero_run(n);
    std::vector<int> left_one_run(n);
    std::vector<int> right_one_run(n);

    // Calculate left_zero_run and left_one_run
    left_zero_run[0] = (a[0] == 0 ? 1 : 0);
    left_one_run[0] = (a[0] == 1 ? 1 : 0);
    for (int i = 1; i < n; ++i) {
        if (a[i] == 0) {
            left_zero_run[i] = left_zero_run[i - 1] + 1;
            left_one_run[i] = 0;
        } else {
            left_one_run[i] = left_one_run[i - 1] + 1;
            left_zero_run[i] = 0;
        }
    }

    // Calculate right_zero_run and right_one_run
    right_zero_run[n - 1] = (a[n - 1] == 0 ? 1 : 0);
    right_one_run[n - 1] = (a[n - 1] == 1 ? 1 : 0);
    for (int i = n - 2; i >= 0; --i) {
        if (a[i] == 0) {
            right_zero_run[i] = right_zero_run[i + 1] + 1;
            right_one_run[i] = 0;
        } else {
            right_one_run[i] = right_one_run[i + 1] + 1;
            right_zero_run[i] = 0;
        }
    }

    int max_k = 0;
    std::vector<int> final_a = a;

    for (int i = 1; i < n - 1; ++i) {
        if (a[i] == 0) { // Current element is 0
            if (a[i - 1] == 1 && a[i + 1] == 1) { // 1 0 1 pattern
                int k_val = std::min(left_one_run[i - 1], right_one_run[i + 1]);
                max_k = std::max(max_k, k_val);
                // This 0 will become 1 after k_val steps
                // The final state of this position will be 1
                final_a[i] = 1;
            } else {
                // This 0 will remain 0
                final_a[i] = 0;
            }
        } else { // Current element is 1
            if (a[i - 1] == 0 && a[i + 1] == 0) { // 0 1 0 pattern
                int k_val = std::min(left_zero_run[i - 1], right_zero_run[i + 1]);
                max_k = std::max(max_k, k_val);
                // This 1 will become 0 after k_val steps
                // The final state of this position will be 0
                final_a[i] = 0;
            } else {
                // This 1 will remain 1
                final_a[i] = 1;
            }
        }
    }

    std::cout << max_k << std::endl;
    for (int i = 0; i < n; ++i) {
        std::cout << final_a[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    // Initialize two numbers:
    // val0: what the result would be if the initial input was 0
    // val1: what the result would be if the initial input was 1023 (all bits set to 1 for relevant bits 0-9)
    int val0 = 0;
    int val1 = 1023; // All bits 0-9 are 1

    for (int i = 0; i < n; ++i) {
        char op_char;
        int x;
        std::cin >> op_char >> x;

        if (op_char == '&') {
            val0 &= x;
            val1 &= x;
        } else if (op_char == '|') {
            val0 |= x;
            val1 |= x;
        } else if (op_char == '^') {
            val0 ^= x;
            val1 ^= x;
        }
    }

    // Now, val0 is the result for input 0, and val1 is the result for input 1023.
    // We need to find a sequence of at most 5 operations that transforms 0 to val0 and 1023 to val1.
    // Let the new operations be:
    // & A
    // | B
    // ^ C
    //
    // For input 0:
    // (0 & A | B) ^ C = val0
    // (0 | B) ^ C = val0
    // B ^ C = val0
    //
    // For input 1023 (all 1s for bits 0-9):
    // (1023 & A | B) ^ C = val1
    //
    // Let's determine A, B, C bit by bit.
    // For each bit position j (0 to 9):
    // Let b0_j be the j-th bit of val0.
    // Let b1_j be the j-th bit of val1.
    //
    // We need to find a_j, b_j, c_j such that:
    // (0 & a_j | b_j) ^ c_j = b0_j  =>  b_j ^ c_j = b0_j
    // (1 & a_j | b_j) ^ c_j = b1_j  =>  (a_j | b_j) ^ c_j = b1_j
    //
    // Let's try to construct A, B, C.
    //
    // A_final, B_final, C_final will be the constants for the new operations.
    int A_final = 1023; // Initialize A_final to all 1s (identity for &)
    int B_final = 0;    // Initialize B_final to all 0s (identity for |)
    int C_final = 0;    // Initialize C_final to all 0s (identity for ^)

    for (int j = 0; j < 10; ++j) {
        int b0_j = (val0 >> j) & 1;
        int b1_j = (val1 >> j) & 1;

        // Case 1: Input bit 0 maps to b0_j, Input bit 1 maps to b1_j
        //
        // We want to find a_j, b_j, c_j such that:
        // (0 & a_j | b_j) ^ c_j = b0_j
        // (1 & a_j | b_j) ^ c_j = b1_j
        //
        // This simplifies to:
        // b_j ^ c_j = b0_j
        // (a_j | b_j) ^ c_j = b1_j
        //
        // Let's analyze the 4 possible (b0_j, b1_j) pairs:
        //
        // If (b0_j, b1_j) = (0, 0):
        //   b_j ^ c_j = 0  => b_j = c_j
        //   (a_j | b_j) ^ c_j = 0 => (a_j | b_j) = c_j
        //   So, a_j | b_j = b_j. This implies a_j must be 0.
        //   We can choose a_j=0, b_j=0, c_j=0.
        //   This means for bit j, the output is always 0, regardless of input.
        //   This is achieved by `& 0` (a_j=0).
        //   So, A_final_j = 0. B_final_j = 0. C_final_j = 0.
        //
        // If (b0_j, b1_j) = (0, 1):
        //   b_j ^ c_j = 0  => b_j = c_j
        //   (a_j | b_j) ^ c_j = 1 => (a_j | b_j) = 1 ^ c_j = 1 ^ b_j
        //   If b_j = 0, then c_j = 0. (a_j | 0) = 1 => a_j = 1.
        //     So, a_j=1, b_j=0, c_j=0.
        //     This means for bit j, output is input_j.
        //     This is achieved by `& 1` (a_j=1).
        //     So, A_final_j = 1. B_final_j = 0. C_final_j = 0.
        //
        // If (b0_j, b1_j) = (1, 0):
        //   b_j ^ c_j = 1  => b_j != c_j
        //   (a_j | b_j) ^ c_j = 0 => (a_j | b_j) = c_j
        //   If b_j = 0, then c_j = 1. (a_j | 0) = 1 => a_j = 1.
        //     So, a_j=1, b_j=0, c_j=1.
        //     This means for bit j, output is NOT input_j.
        //     This is achieved by `^ 1` (c_j=1).
        //     So, A_final_j = 1. B_final_j = 0. C_final_j = 1.
        //
        // If (b0_j, b1_j) = (1, 1):
        //   b_j ^ c_j = 1  => b_j != c_j
        //   (a_j | b_j) ^ c_j = 1 => (a_j | b_j) = 1 ^ c_j
        //   If b_j = 1, then c_j = 0. (a_j | 1) = 1 ^ 0 = 1. This is always true.
        //     So, a_j=0 (or 1), b_j=1, c_j=0.
        //     This means for bit j, output is always 1, regardless of input.
        //     This is achieved by `| 1` (b_j=1).
        //     So, A_final_j = 1. B_final_j = 1. C_final_j = 0.

        if (b0_j == 0 && b1_j == 0) { // Output always 0
            A_final &= ~(1 << j); // Set a_j to 0
            // B_final_j = 0, C_final_j = 0 (already initialized)
        } else if (b0_j == 0 && b1_j == 1) { // Output is input_j
            // A_final_j = 1 (already initialized)
            // B_final_j = 0, C_final_j = 0 (already initialized)
        } else if (b0_j == 1 && b1_j == 0) { // Output is NOT input_j
            // A_final_j = 1 (already initialized)
            // B_final_j = 0 (already initialized)
            C_final |= (1 << j); // Set c_j to 1
        } else { // (b0_j == 1 && b1_j == 1) Output always 1
            B_final |= (1 << j); // Set b_j to 1
            // A_final_j = 1 (already initialized)
            // C_final_j = 0 (already initialized)
        }
    }

    std::vector<std::pair<char, int>> result_ops;
    if (A_final != 1023) { // If A_final is not all 1s, we need an AND operation
        result_ops.push_back({'&', A_final});
    }
    if (B_final != 0) { // If B_final is not all 0s, we need an OR operation
        result_ops.push_back({'|', B_final});
    }
    if (C_final != 0) { // If C_final is not all 0s, we need an XOR operation
        result_ops.push_back({'^', C_final});
    }

    std::cout << result_ops.size() << std::endl;
    for (const auto& op : result_ops) {
        std::cout << op.first << " " << op.second << std::endl;
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <map>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(2 * n);
    for (int i = 0; i < 2 * n; ++i) {
        std::cin >> a[i];
    }

    // Calculate prefix sums for the left side (jars 1 to n)
    // and suffix sums for the right side (jars n+1 to 2n).
    // For balance, strawberry=1, blueberry=-1.

    // Balances for the left side (jars 1 to n)
    // left_balances[k] stores the balance of jars 1 to k.
    // We are interested in balances of jars 1 to n-k, which means k jars are eaten from the left.
    // So, left_balances[k] is the balance of jars 1 to k.
    // When k jars are eaten from the left, the remaining jars are 1 to n-k.
    // The balance of these remaining jars is prefix_balance[n-k].
    // To make it easier, let's store the balance of jars 1 to i for i from 0 to n.
    // left_prefix_balance[i] = balance of jars 1 to i.
    // left_prefix_balance[0] = 0.
    // left_prefix_balance[i] = balance of jars 1 to i.
    std::vector<int> left_prefix_balance(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        left_prefix_balance[i + 1] = left_prefix_balance[i] + (a[i] == 1 ? 1 : -1);
    }

    // Balances for the right side (jars n+1 to 2n)
    // right_suffix_balance[k] stores the balance of jars k to 2n.
    // We are interested in balances of jars n+k+1 to 2n, which means k jars are eaten from the right.
    // So, right_suffix_balance[k] is the balance of jars k to 2n.
    // To make it easier, let's store the balance of jars i to 2n for i from n+1 to 2n+1.
    // right_suffix_balance[i] = balance of jars i to 2n.
    // right_suffix_balance[2n+1] = 0.
    // right_suffix_balance[i] = balance of jars i to 2n.
    std::vector<int> right_suffix_balance(n + 1, 0); // Stores balance of jars n+1+i to 2n
                                                     // right_suffix_balance[0] is balance of jars n+1 to 2n
                                                     // right_suffix_balance[k] is balance of jars n+1+k to 2n
    for (int i = 0; i < n; ++i) {
        right_suffix_balance[i + 1] = right_suffix_balance[i] + (a[2 * n - 1 - i] == 1 ? 1 : -1);
    }
    // Reverse right_suffix_balance so right_suffix_balance[k] is balance of jars n+1+k to 2n
    // No, let's just use it as is: right_suffix_balance[k] is balance of jars 2n-k+1 to 2n.
    // This means right_suffix_balance[0] is 0 (no jars from right), right_suffix_balance[1] is balance of jar 2n, etc.
    // The actual jars are a[n]...a[2n-1].
    // Let's re-index:
    // right_prefix_balance[k] = balance of jars n+1 to n+k.
    std::vector<int> right_prefix_balance(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        right_prefix_balance[i + 1] = right_prefix_balance[i] + (a[n + i] == 1 ? 1 : -1);
    }

    // Map to store the minimum number of jars eaten from the left (L)
    // to achieve a certain balance for the remaining left jars.
    // key: balance, value: number of jars eaten from left (L)
    std::map<int, int> left_eaten_map;
    // Iterate through all possible numbers of jars eaten from the left (L)
    // L can range from 0 to n.
    // If L jars are eaten, jars 1 to n-L remain.
    // The balance of these remaining jars is left_prefix_balance[n-L].
    for (int L = 0; L <= n; ++L) {
        int remaining_left_balance = left_prefix_balance[n - L];
        if (left_eaten_map.find(remaining_left_balance) == left_eaten_map.end()) {
            left_eaten_map[remaining_left_balance] = L;
        } else {
            left_eaten_map[remaining_left_balance] = std::min(left_eaten_map[remaining_left_balance], L);
        }
    }

    int min_total_eaten = 2 * n; // Max possible jars eaten

    // Iterate through all possible numbers of jars eaten from the right (R)
    // R can range from 0 to n.
    // If R jars are eaten, jars n+R+1 to 2n remain.
    // The balance of these remaining jars is (total balance of jars n+1 to 2n) - (balance of jars n+1 to n+R).
    // This is (right_prefix_balance[n]) - (right_prefix_balance[R]).
    for (int R = 0; R <= n; ++R) {
        int remaining_right_balance = right_prefix_balance[n] - right_prefix_balance[R];

        // We need the total balance of remaining jars to be 0.
        // So, remaining_left_balance + remaining_right_balance = 0.
        // This means remaining_left_balance = -remaining_right_balance.
        int target_left_balance = -remaining_right_balance;

        if (left_eaten_map.count(target_left_balance)) {
            int L = left_eaten_map[target_left_balance];
            min_total_eaten = std::min(min_total_eaten, L + R);
        }
    }

    std::cout << min_total_eaten << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <climits>

struct Operation {
    int type;
    int l, r;
    long long val; // d for type 1, m for type 2
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<Operation> ops(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> ops[i].type >> ops[i].l >> ops[i].r >> ops[i].val;
        ops[i].l--; // 0-indexed
        ops[i].r--; // 0-indexed
    }

    std::vector<long long> initial_a(n, LLONG_MAX); // Stores upper bounds for initial a[i]

    // First pass: Determine upper bounds for initial_a[i]
    // For each type 2 query (2 l r m), we know that for all j in [l, r], a_j + current_add_j <= m.
    // This means a_j <= m - current_add_j.
    // We want to find the tightest upper bound for each initial_a[j].
    std::vector<long long> current_add(n, 0); // Total additions to a[i] up to current operation
    for (int i = 0; i < m; ++i) {
        if (ops[i].type == 1) {
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                current_add[j] += ops[i].val;
            }
        } else { // type 2
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                initial_a[j] = std::min(initial_a[j], ops[i].val - current_add[j]);
            }
        }
    }

    // If any initial_a[j] is still LLONG_MAX, it means it was never constrained by a type 2 query.
    // We can set it to 0 (or any value within bounds, 0 is simplest and satisfies |a_i| <= 10^9).
    for (int i = 0; i < n; ++i) {
        if (initial_a[i] == LLONG_MAX) {
            initial_a[i] = 0;
        }
    }

    // Second pass: Verify the solution
    // Simulate operations with the determined initial_a and check if type 2 queries match.
    std::vector<long long> simulated_a = initial_a; // This will store the current state of the array
    current_add.assign(n, 0); // Reset current_add for this pass

    for (int i = 0; i < m; ++i) {
        if (ops[i].type == 1) {
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                simulated_a[j] += ops[i].val;
                current_add[j] += ops[i].val; // Keep track of total additions for verification
            }
        } else { // type 2
            long long max_val = LLONG_MIN;
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                max_val = std::max(max_val, simulated_a[j]);
            }
            if (max_val != ops[i].val) {
                std::cout << "NO\n";
                return 0;
            }
        }
    }

    std::cout << "YES\n";
    for (int i = 0; i < n; ++i) {
        std::cout << initial_a[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

