struct Child {
    int id;
    long long v, d, p;
    bool in_line;
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<Child> children(n);
    for (int i = 0; i < n; ++i) {
        children[i].id = i + 1;
        std::cin >> children[i].v >> children[i].d >> children[i].p;
        children[i].in_line = true;
    }

    std::vector<int> cured_children_ids;

    for (int i = 0; i < n; ++i) {
        if (!children[i].in_line) {
            continue;
        }

        cured_children_ids.push_back(children[i].id);
        children[i].in_line = false;

        long long current_cry_volume = children[i].v;
        long long hall_cry_sum = 0; // Sum of d_j from children who left due to low confidence

        for (int j = i + 1; j < n; ++j) {
            if (!children[j].in_line) {
                continue;
            }

            // Apply crying from child i
            if (current_cry_volume > 0) {
                children[j].p -= current_cry_volume;
                current_cry_volume--;
            }

            // Apply crying from children who left the hall
            children[j].p -= hall_cry_sum;

            // Check if child j leaves the line
            if (children[j].p < 0) {
                children[j].in_line = false;
                hall_cry_sum += children[j].d;
            }
        }
    }

    std::cout << cured_children_ids.size() << "\n";
    for (size_t i = 0; i < cured_children_ids.size(); ++i) {
        std::cout << cured_children_ids[i] << (i == cured_children_ids.size() - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

