#include <iostream>
#include <string>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;
    int n = s.length();

    std::vector<int> next_bad_idx(n + 1, n + 1); // 1-indexed for convenience

    for (int i = 0; i < n; ++i) { // i is 0-indexed
        // Check for k=1: s[i] == s[i+1] == s[i+2]
        if (i + 2 < n && s[i] == s[i+1] && s[i+1] == s[i+2]) {
            next_bad_idx[i + 1] = std::min(next_bad_idx[i + 1], i + 3); // x=i+1, x+2k=i+3
        }
        // Check for k=2: s[i] == s[i+2] == s[i+4]
        if (i + 4 < n && s[i] == s[i+2] && s[i+2] == s[i+4]) {
            next_bad_idx[i + 1] = std::min(next_bad_idx[i + 1], i + 5); // x=i+1, x+2k=i+5
        }
        // Check for k=3: s[i] == s[i+3] == s[i+6]
        if (i + 6 < n && s[i] == s[i+3] && s[i+3] == s[i+6]) {
            next_bad_idx[i + 1] = std::min(next_bad_idx[i + 1], i + 7); // x=i+1, x+2k=i+7
        }
    }

    // Propagate minimums: next_bad_idx[i] should be min(next_bad_idx[i], next_bad_idx[i+1])
    // This means for a given l, the smallest r that satisfies the condition is min(next_bad_idx[l], next_bad_idx[l+1], ...)
    // Or, more simply, if a pattern starts at x, it affects all l <= x.
    // So, next_bad_idx[i] stores the minimum r for any pattern starting at or after i.
    // This is equivalent to: next_bad_idx[i] = min(next_bad_idx[i], next_bad_idx[i+1])
    // for i from n-1 down to 1.
    for (int i = n - 1; i >= 1; --i) {
        next_bad_idx[i] = std::min(next_bad_idx[i], next_bad_idx[i+1]);
    }

    long long total_pairs = 0;
    for (int l = 1; l <= n; ++l) {
        if (next_bad_idx[l] <= n) { // If there is at least one pattern starting at or after l
            // For a fixed l, any r from next_bad_idx[l] to n will satisfy the condition.
            // The number of such r's is n - next_bad_idx[l] + 1.
            total_pairs += (n - next_bad_idx[l] + 1);
        }
    }

    std::cout << total_pairs << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

struct Element {
    long long value;
    int original_index;
};

bool compareElements(const Element& a, const Element& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long h;
    std::cin >> n >> h;

    std::vector<Element> elements(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> elements[i].value;
        elements[i].original_index = i;
    }

    std::sort(elements.begin(), elements.end(), compareElements);

    // Case 1: All elements in one subsequence (e.g., all in S1).
    // All f values are a_i + a_j.
    // min_f = a_1 + a_2
    // max_f = a_{n-1} + a_n
    // Goodness = (a_{n-1} + a_n) - (a_1 + a_2)
    long long goodness1 = (elements[n - 1].value + elements[n - 2].value) - (elements[0].value + elements[1].value);
    std::vector<int> partition1(n, 1); // All in subsequence 1

    // Case 2: At least one element in S1 and at least one in S2.
    // This means there will be f values of type a_i + a_j and a_i + a_j + h.
    // The minimum possible f value is a_1 + a_2.
    // The maximum possible f value is a_{n-1} + a_n + h.
    // Goodness = (a_{n-1} + a_n + h) - (a_1 + a_2).
    // This is the general case if both subsequences are non-empty.
    // However, we can try to make a_1 and a_n be in different subsequences to minimize max_f and maximize min_f.

    // Consider a partition where elements[0] is in S1 and elements[1]...elements[n-1] are in S2.
    // Or elements[0]...elements[n-2] in S1 and elements[n-1] in S2.
    // This is equivalent to having one element in one group and n-1 elements in the other.
    // Let's say elements[0] is in S1, and elements[1]...elements[n-1] are in S2.
    // min_f:
    //   - a_i + a_j (both in S2): min is elements[1].value + elements[2].value
    //   - a_i + a_j + h (one in S1, one in S2): min is elements[0].value + elements[1].value + h
    //   So, min_f = std::min(elements[1].value + elements[2].value, elements[0].value + elements[1].value + h)
    // max_f:
    //   - a_i + a_j (both in S2): max is elements[n-1].value + elements[n-2].value
    //   - a_i + a_j + h (one in S1, one in S2): max is elements[0].value + elements[n-1].value + h
    //   So, max_f = std::max(elements[n-1].value + elements[n-2].value, elements[0].value + elements[n-1].value + h)
    // This specific partition strategy is: put elements[0] in S1, and all others in S2.
    // The minimum f value will be elements[0].value + elements[1].value + h (since elements[0] is only in S1, it must pair with an S2 element).
    // The maximum f value will be elements[n-1].value + elements[n-2].value (if n > 2, otherwise it's elements[0].value + elements[1].value + h).
    // Or elements[0].value + elements[n-1].value + h.
    // The maximum f value will be max(elements[n-1].value + elements[n-2].value, elements[0].value + elements[n-1].value + h).
    // The minimum f value will be min(elements[1].value + elements[2].value, elements[0].value + elements[1].value + h).
    // This is not quite right. The minimum f value is always a_1 + a_2 if they are in the same group, or a_1 + a_2 + h if they are in different groups.
    // The maximum f value is always a_{n-1} + a_n if they are in the same group, or a_{n-1} + a_n + h if they are in different groups.

    // Let's consider the general case where both subsequences are non-empty.
    // The minimum possible value for a_i + a_j is elements[0].value + elements[1].value.
    // The maximum possible value for a_i + a_j is elements[n-1].value + elements[n-2].value.
    // The minimum possible value for a_i + a_j + h is elements[0].value + elements[1].value + h.
    // The maximum possible value for a_i + a_j + h is elements[n-1].value + elements[n-2].value + h.

    // If both types of f values (with and without h) exist:
    // min_f = min(elements[0].value + elements[1].value, elements[0].value + elements[1].value + h) = elements[0].value + elements[1].value
    // max_f = max(elements[n-1].value + elements[n-2].value, elements[n-1].value + elements[n-2].value + h) = elements[n-1].value + elements[n-2].value + h
    // Goodness = (elements[n-1].value + elements[n-2].value + h) - (elements[0].value + elements[1].value)
    // This is the goodness if we have at least two elements in one group and at least two elements in the other group.
    // Or if we have one element in one group and n-1 in the other, and n-1 >= 2.
    // This is the "worst case" goodness if both types of f values exist.

    // What if we put elements[0] in S1, and all other elements[1]...elements[n-1] in S2?
    // S1 = {elements[0]}
    // S2 = {elements[1], ..., elements[n-1]}
    // All pairs involving elements[0] will be (elements[0], elements[k]) with k > 0. These are different subsequences.
    // f values: elements[0].value + elements[k].value + h for k=1...n-1.
    // If n > 2, there are also pairs (elements[k], elements[j]) with k,j > 0. These are same subsequence.
    // f values: elements[k].value + elements[j].value for k,j > 0.
    //
    // min_f:
    //   - From S2 pairs: elements[1].value + elements[2].value (if n > 2)
    //   - From S1-S2 pairs: elements[0].value + elements[1].value + h
    //   So, min_f = (n > 2) ? std::min(elements[1].value + elements[2].value, elements[0].value + elements[1].value + h) : (elements[0].value + elements[1].value + h)
    // max_f:
    //   - From S2 pairs: elements[n-1].value + elements[n-2].value (if n > 2)
    //   - From S1-S2 pairs: elements[0].value + elements[n-1].value + h
    //   So, max_f = (n > 2) ? std::max(elements[n-1].value + elements[n-2].value, elements[0].value + elements[n-1].value + h) : (elements[0].value + elements[1].value + h)
    //
    // Goodness for this partition: max_f - min_f.
    // Let's call this goodness2.
    long long min_f_val_2, max_f_val_2;
    if (n == 2) {
        // S1 = {elements[0]}, S2 = {elements[1]}
        // Only one pair: (elements[0], elements[1]), different subsequences.
        // f = elements[0].value + elements[1].value + h
        min_f_val_2 = elements[0].value + elements[1].value + h;
        max_f_val_2 = elements[0].value + elements[1].value + h;
    } else {
        // S1 = {elements[0]}, S2 = {elements[1], ..., elements[n-1]}
        min_f_val_2 = std::min(elements[1].value + elements[2].value, elements[0].value + elements[1].value + h);
        max_f_val_2 = std::max(elements[n-1].value + elements[n-2].value, elements[0].value + elements[n-1].value + h);
    }
    long long goodness2 = max_f_val_2 - min_f_val_2;
    std::vector<int> partition2(n);
    partition2[elements[0].original_index] = 1;
    for (int i = 1; i < n; ++i) {
        partition2[elements[i].original_index] = 2;
    }

    // What if we put elements[n-1] in S1, and all other elements[0]...elements[n-2] in S2?
    // This is symmetric to the previous case, and will yield the same goodness.
    // S1 = {elements[n-1]}
    // S2 = {elements[0], ..., elements[n-2]}
    // min_f:
    //   - From S2 pairs: elements[0].value + elements[1].value (if n > 2)
    //   - From S1-S2 pairs: elements[0].value + elements[n-1].value + h
    //   So, min_f = (n > 2) ? std::min(elements[0].value + elements[1].value, elements[0].value + elements[n-1].value + h) : (elements[0].value + elements[1].value + h)
    // max_f:
    //   - From S2 pairs: elements[n-2].value + elements[n-3].value (if n > 2)
    //   - From S1-S2 pairs: elements[n-2].value + elements[n-1].value + h
    //   So, max_f = (n > 2) ? std::max(elements[n-2].value + elements[n-3].value, elements[n-2].value + elements[n-1].value + h) : (elements[0].value + elements[1].value + h)
    //
    // Goodness for this partition: max_f - min_f.
    // Let's call this goodness3.
    long long min_f_val_3, max_f_val_3;
    if (n == 2) {
        min_f_val_3 = elements[0].value + elements[1].value + h;
        max_f_val_3 = elements[0].value + elements[1].value + h;
    } else {
        min_f_val_3 = std::min(elements[0].value + elements[1].value, elements[0].value + elements[n-1].value + h);
        max_f_val_3 = std::max(elements[n-2].value + elements[n-3].value, elements[n-2].value + elements[n-1].value + h);
    }
    long long goodness3 = max_f_val_3 - min_f_val_3;
    std::vector<int> partition3(n);
    partition3[elements[n-1].original_index] = 1;
    for (int i = 0; i < n - 1; ++i) {
        partition3[elements[i].original_index] = 2;
    }

    // Compare the goodness values and print the best one.
    long long min_goodness = goodness1;
    std::vector<int> best_partition = partition1;

    if (goodness2 < min_goodness) {
        min_goodness = goodness2;
        best_partition = partition2;
    }
    if (goodness3 < min_goodness) {
        min_goodness = goodness3;
        best_partition = partition3;
    }

    std::cout << min_goodness << "\n";
    for (int i = 0; i < n; ++i) {
        std::cout << best_partition[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <cmath>

bool check(long long T, int n, int m, const std::vector<long long>& h, const std::vector<long long>& p) {
    int head_idx = 0;
    int p_idx = 0;

    while (p_idx < m) {
        if (head_idx >= n) {
            return false; // Ran out of heads but still have tracks to cover
        }

        // Find the first head that can reach p_idx
        // A head at h[head_idx] can reach p[p_idx] if |h[head_idx] - p[p_idx]| <= T
        // This means h[head_idx] - T <= p[p_idx] <= h[head_idx] + T
        // Or, p[p_idx] - T <= h[head_idx] <= p[p_idx] + T

        // We need to find a head h[k] such that h[k] <= p[p_idx] + T
        // and h[k] is as small as possible but still >= p[p_idx] - T

        // The current head h[head_idx] can cover p[p_idx] if h[head_idx] <= p[p_idx] + T.
        // If h[head_idx] is too far to the left (h[head_idx] < p[p_idx] - T),
        // this head cannot cover p[p_idx] even by moving right for T time.
        // In this case, we need to move to the next head.
        if (h[head_idx] < p[p_idx] - T) {
            head_idx++;
            continue;
        }

        // If we reach here, h[head_idx] >= p[p_idx] - T.
        // This means h[head_idx] can potentially cover p[p_idx].
        // The head h[head_idx] can move to any track x in [h[head_idx] - T, h[head_idx] + T].
        // To cover p[p_idx], it must be that p[p_idx] is in this range.
        // We already know p[p_idx] >= h[head_idx] - T.
        // So we only need to check if p[p_idx] <= h[head_idx] + T.

        // If h[head_idx] can cover p[p_idx]:
        // The head h[head_idx] can cover tracks from p[p_idx] up to some maximum.
        // The maximum track it can cover is max_reach = h[head_idx] + T.
        // However, it must first reach p[p_idx].
        // The time taken to reach p[p_idx] is |h[head_idx] - p[p_idx]|.
        // The remaining time is T - |h[head_idx] - p[p_idx]|.
        // With this remaining time, it can move further right.
        // So, the rightmost track it can cover is p[p_idx] + (T - |h[head_idx] - p[p_idx]|).
        // This simplifies to p[p_idx] + T - (p[p_idx] - h[head_idx]) = h[head_idx] + T if h[head_idx] <= p[p_idx]
        // This simplifies to p[p_idx] + T - (h[head_idx] - p[p_idx]) = 2*p[p_idx] - h[head_idx] + T if h[head_idx] > p[p_idx]

        // Let's use a simpler logic:
        // The head h[head_idx] can cover any track in [h[head_idx] - T, h[head_idx] + T].
        // We need to cover p[p_idx].
        // If h[head_idx] is too far right (h[head_idx] > p[p_idx] + T), then this head cannot cover p[p_idx].
        // This case should not happen if we process heads from left to right and tracks from left to right.
        // If h[head_idx] is at p[p_idx] or to its left, i.e., h[head_idx] <= p[p_idx]:
        // The head moves to p[p_idx] (cost p[p_idx] - h[head_idx]).
        // Remaining time: T - (p[p_idx] - h[head_idx]).
        // It can then cover tracks up to p[p_idx] + (T - (p[p_idx] - h[head_idx])) = h[head_idx] + T.
        // If h[head_idx] is to the right of p[p_idx], i.e., h[head_idx] > p[p_idx]:
        // The head moves to p[p_idx] (cost h[head_idx] - p[p_idx]).
        // Remaining time: T - (h[head_idx] - p[p_idx]).
        // It can then cover tracks up to p[p_idx] + (T - (h[head_idx] - p[p_idx])) = 2*p[p_idx] - h[head_idx] + T.

        // The maximum rightmost point this head can cover is:
        long long current_head_reach_right;
        if (h[head_idx] <= p[p_idx]) { // Head is at or to the left of the current target track
            current_head_reach_right = h[head_idx] + T;
        } else { // Head is to the right of the current target track
            // It must move left to p[p_idx]. Cost: h[head_idx] - p[p_idx].
            // Remaining time: T - (h[head_idx] - p[p_idx]).
            // It can then move right from p[p_idx] by this remaining time.
            current_head_reach_right = p[p_idx] + (T - (h[head_idx] - p[p_idx]));
        }

        // Now, advance p_idx as far as possible using this head
        while (p_idx < m && p[p_idx] <= current_head_reach_right) {
            p_idx++;
        }
        head_idx++; // Use the next head for the remaining tracks
    }
    return true;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<long long> h(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> h[i];
    }

    std::vector<long long> p(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> p[i];
    }

    long long low = 0;
    long long high = 2e10 + 7; // Max possible difference between tracks is 10^10, so 2*10^10 is a safe upper bound for T.
    long long ans = high;

    while (low <= high) {
        long long mid = low + (high - low) / 2;
        if (check(mid, n, m, h, p)) {
            ans = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    std::cout << ans << std::endl;

    return 0;
}

