#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
    }

    // The problem statement guarantees that a solution exists.
    // For n=2, reversing [p1, p2] to [p2, p1] works.
    // F([p1, p2]) = [p1+p2]
    // F([p2, p1]) = [p2+p1]
    // These are the same.

    // For n > 2, reversing the permutation p to p_rev also works.
    // Let p = [p_1, p_2, ..., p_n].
    // The sums are S = {p_1+p_2, p_2+p_3, ..., p_{n-1}+p_n}.
    // Let p_rev = [p_n, p_{n-1}, ..., p_1].
    // The sums for p_rev are S_rev = {p_n+p_{n-1}, p_{n-1}+p_{n-2}, ..., p_2+p_1}.
    // Notice that S_rev is just S with elements in reverse order.
    // For example, p_n+p_{n-1} is the last sum of p, p_{n-1}+p_{n-2} is the second to last, etc.
    // Since F(p) and F(p_rev) are sorted arrays of these sums, they will be identical.
    // The only case where p_rev might be equal to p is if p is a palindrome.
    // However, a permutation of distinct integers from 1 to n cannot be a palindrome for n > 1.
    // For example, if p_1 = p_n, then p_1 and p_n are the same value, but they must be distinct elements of the permutation.
    // This is only possible if n=1, but n >= 2.
    // So p_rev is always different from p for n >= 2.

    std::reverse(p.begin(), p.end());
    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";
}

