#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n, d;
    std::cin >> n >> d;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    long long current_a1 = a[0];
    long long remaining_days = d;

    for (int i = 1; i < n; ++i) {
        int pile_index = i; // 0-indexed pile index
        int haybales_in_pile = a[pile_index];

        // Cost to move one haybale from pile_index to pile 0
        // (pile_index + 1) is the 1-based index, so cost is (pile_index + 1) - 1 = pile_index
        long long cost_per_haybale = pile_index; 

        if (cost_per_haybale == 0) { // This should only happen for pile 0 itself, which is skipped
            continue;
        }

        if (remaining_days >= cost_per_haybale) {
            // Calculate how many haybales can be moved from this pile
            long long max_movable_from_this_pile = remaining_days / cost_per_haybale;
            long long actual_moved = std::min((long long)haybales_in_pile, max_movable_from_this_pile);

            current_a1 += actual_moved;
            remaining_days -= actual_moved * cost_per_haybale;
        } else {
            // Not enough days to move even one haybale from this pile
            break; 
        }
    }
    std::cout << current_a1 << std::endl;
}

