            // Let's use this interpretation.
            // Cost for k=1 (n=1): 1^2 + 2^2 = 1+4 = 5. This contradicts example 1 (x=1, ans=1).
            // Example 1: x=1, ans=1. This means a staircase with 1 stair costs 1 cell.
            // This implies the cost for a staircase with (2^k - 1) stairs is sum_{i=1}^{k} i^2.
            // For k=1, n=1, cost = 1^2 = 1. This matches example 1.
            // For k=2, n=3, cost = 1^2 + 2^2 = 1+4 = 5.
            // For k=3, n=7, cost = 1^2 + 2^2 + 3^2 = 1+4+9 = 14.
            // This interpretation matches the example output for x=8, ans=2.
            // If we build n=1 (cost 1), remaining x=7. Can build n=3 (cost 5). Total cost 1+5=6. Remaining x=2.
            // Total 2 staircases.
            // This interpretation also matches x=6, ans=1.
            // If we build n=1 (cost 1), remaining x=5. Cannot build n=3 (cost 5).
            // If we build n=3 (cost 5), remaining x=1. Cannot build n=1 (cost 1).
            // So, the cost of a nice staircase with (2^k - 1) stairs is sum_{i=1}^{k} i^2.
            // This sum is k * (k + 1) * (2k + 1) / 6.

            long long cost_for_k = k * (k + 1) * (2 * k + 1) / 6;

            if (current_cost + cost_for_k <= x) {
                current_cost += cost_for_k;
                count++;
                k = 2 * k + 1; // Next staircase will have (2*(2^k-1)+1) stairs, which is (2^(k+1)-1) stairs.
                               // So the next k value for the sum of squares will be k+1.
                               // The number of stairs is 2^k - 1.
                               // The next number of stairs is 2^(k+1) - 1.
                               // So the next 'k' in the formula sum_{i=1}^{k} i^2 will be 'k+1'.
                               // Let's denote the 'k' in the formula as `stairs_k`.
                               // For stairs_k=1, cost=1.
                               // For stairs_k=2, cost=5.
                               // For stairs_k=3, cost=14.
                               // The sequence of `stairs_k` values is 1, 2, 3, ...
                               // The sequence of number of stairs is 1, 3, 7, ... (2^stairs_k - 1)
                               // So, `k` in my code represents `stairs_k`.
                               // The next `stairs_k` is `k+1`.
                k++; // Increment k for the next iteration to calculate cost_for_k+1
            } else {
                break;
            }
        }
        std::cout << count << "\n";
    }
    return 0;
}

