int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        long long n, m;
        std::cin >> n >> m;

        if (m > n) {
            std::cout << 0 << "\n";
            continue;
        }

        long long count = n / m;

        // Precompute the sum of last digits for one cycle (10 multiples of m)
        // The last digits of (k*m) repeat every 10 values of k.
        // E.g., last digits of m, 2m, ..., 10m are the same as 11m, 12m, ..., 20m.
        std::vector<long long> cycle_last_digits_sum(10);
        for (int i = 1; i <= 10; ++i) {
            cycle_last_digits_sum[i - 1] = (static_cast<long long>(i) * m) % 10;
        }

        long long sum_of_one_cycle = 0;
        for (long long digit : cycle_last_digits_sum) {
            sum_of_one_cycle += digit;
        }

        // Calculate how many full cycles of 10 multiples of m are there
        long long num_full_cycles = count / 10;
        long long total_sum = num_full_cycles * sum_of_one_cycle;

        // Add the sum for the remaining multiples
        long long remaining_multiples = count % 10;
        for (int i = 0; i < remaining_multiples; ++i) {
            total_sum += cycle_last_digits_sum[i];
        }

        std::cout << total_sum << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 1) {
        std::cout << 0 << std::endl;
        return;
    }

    // Find the rightmost index `i` such that a[i] < a[i-1]
    // This `i` is the start of the first decreasing sequence from the right.
    // All elements from `a[i]` to `a[n-1]` must be part of the "good" suffix.
    // The prefix to remove must end at `i-1` or earlier.
    int i = n - 1;
    while (i > 0 && a[i-1] >= a[i]) {
        i--;
    }
    // Now `i` is the first index from the right where `a[i-1] < a[i]` is false,
    // meaning `a[i-1] >= a[i]`.
    // If `i` is 0, the whole array is non-decreasing.

    // If `i` is not 0, then `a[i-1] < a[i]` is the first violation of non-decreasing from right.
    // So `a[i], a[i+1], ..., a[n-1]` is a non-decreasing suffix.
    // We need to find the rightmost index `j` such that a[j] > a[j+1]
    // This `j` is the start of the first increasing sequence from the right.
    // All elements from `a[j]` to `a[n-1]` must be part of the "good" suffix.
    // The prefix to remove must end at `j-1` or earlier.
    int j = i; // Start from `i` (the beginning of the non-decreasing suffix)
    while (j > 0 && a[j-1] <= a[j]) {
        j--;
    }
    // Now `j` is the first index from the right where `a[j-1] > a[j]` is false,
    // meaning `a[j-1] <= a[j]`.
    // If `j` is 0, the whole array is non-increasing.

    // The elements from `a[j]` to `a[n-1]` form the longest suffix that can potentially be "good".
    // The length of the prefix to remove is `j`.
    std::cout << j << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    std::vector<int> pos(n + 1); // pos[x] stores the 0-indexed position of x in p
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
        pos[p[i]] = i;
    }

    std::string ans(n, '0');

    int current_min_idx = pos[1];
    int current_max_idx = pos[1];

    for (int m = 1; m <= n; ++m) {
        // For m=1, the segment is just [1].
        // min_idx and max_idx are both pos[1].
        // Length is 1. Max value is 1. So m=1 is always beautiful.
        if (m == 1) {
            ans[0] = '1';
        } else {
            // For m > 1, we extend the range to include 'm'.
            // The new minimum index will be min(current_min_idx, pos[m]).
            // The new maximum index will be max(current_max_idx, pos[m]).
            current_min_idx = std::min(current_min_idx, pos[m]);
            current_max_idx = std::max(current_max_idx, pos[m]);

            // A number m is beautiful if the segment p[current_min_idx ... current_max_idx]
            // contains exactly numbers 1 to m.
            // This means its length must be m.
            if (current_max_idx - current_min_idx + 1 == m) {
                ans[m - 1] = '1';
            }
        }
    }
    std::cout << ans << std::endl;
}

