void solve() {
    long long A, B, C, D;
    std::cin >> A >> B >> C >> D;

    long long total_toys = A + B + C + D;

    std::string ans1 = "Tidak", ans2 = "Tidak", ans3 = "Tidak", ans4 = "Tidak";

    if (total_toys == 0) { // Should not happen based on constraints A+B+C+D > 0
        std::cout << "Tidak Tidak Tidak Tidak\n";
        return;
    }

    if (total_toys == 1) {
        if (A == 1) ans1 = "Ya";
        if (B == 1) ans2 = "Ya";
        if (C == 1) ans3 = "Ya";
        if (D == 1) ans4 = "Ya";
        std::cout << ans1 << " " << ans2 << " " << ans3 << " " << ans4 << "\n";
        return;
    }

    // Case 1: Final toy in Box 1 (Negative, Large magnitude)
    // This requires an odd number of negative toys in total.
    // And it requires at least one large magnitude toy (A or D) to be involved in the final product,
    // or if all toys are small magnitude, then the product must become large.
    // The latter is impossible if all initial toys are small magnitude.
    // If all initial toys are small magnitude (B+C > 0, A=D=0), then the final product will always be small magnitude.
    // So, if A=D=0, Box 1 is impossible.
    // If A+D > 0, then a large magnitude is possible.
    // The sign is determined by the parity of negative toys.
    // To get negative, (A+B) must be odd.
    // To get large magnitude, (A+D) must be > 0.
    if ((A + B) % 2 == 1 && (A + D > 0)) {
        ans1 = "Ya";
    }

    // Case 2: Final toy in Box 2 (Negative, Small magnitude)
    // This requires an odd number of negative toys in total.
    // And it requires the final product to have small magnitude.
    // This is always possible if A+B is odd.
    // If A+D > 0, we can always arrange operations to make the final product small.
    // For example, multiply a large toy by a very small toy from B or C.
    // If A+D == 0, then all initial toys are small magnitude (B+C > 0).
    // In this case, the final product will always be small magnitude.
    // So, if A+B is odd, Box 2 is always possible.
    if ((A + B) % 2 == 1) {
        ans2 = "Ya";
    }

    // Case 3: Final toy in Box 3 (Positive, Small magnitude)
    // This requires an even number of negative toys in total.
    // And it requires the final product to have small magnitude.
    // This is always possible if A+B is even.
    // If A+D > 0, we can always arrange operations to make the final product small.
    // If A+D == 0, then all initial toys are small magnitude (B+C > 0).
    // In this case, the final product will always be small magnitude.
    // So, if A+B is even, Box 3 is always possible.
    if ((A + B) % 2 == 0) {
        ans3 = "Ya";
    }

    // Case 4: Final toy in Box 4 (Positive, Large magnitude)
    // This requires an even number of negative toys in total.
    // And it requires at least one large magnitude toy (A or D) to be involved in the final product.
    // If A+D == 0, then all initial toys are small magnitude (B+C > 0), so the final product will always be small magnitude.
    // So, if A=D=0, Box 4 is impossible.
    // If A+D > 0, then a large magnitude is possible.
    // The sign is determined by the parity of negative toys.
    // To get positive, (A+B) must be even.
    // To get large magnitude, (A+D) must be > 0.
    if ((A + B) % 2 == 0 && (A + D > 0)) {
        ans4 = "Ya";
    }

    std::cout << ans1 << " " << ans2 << " " << ans3 << " " << ans4 << "\n";
}

