char get_winning_move(char bot_move) {
    if (bot_move == 'R') return 'P';
    if (bot_move == 'S') return 'R';
    if (bot_move == 'P') return 'S';
    return ' '; // Should not happen
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        std::string s;
        std::cin >> s;
        int n = s.length();

        std::map<char, int> counts;
        for (char c : s) {
            counts[c]++;
        }

        char most_frequent_bot_move = ' ';
        int max_count = -1;

        // Check 'R'
        if (counts['R'] > max_count) {
            max_count = counts['R'];
            most_frequent_bot_move = 'R';
        }
        // Check 'S'
        if (counts['S'] > max_count) {
            max_count = counts['S'];
            most_frequent_bot_move = 'S';
        }
        // Check 'P'
        if (counts['P'] > max_count) {
            max_count = counts['P'];
            most_frequent_bot_move = 'P';
        }
        // If counts are equal, any choice among them is fine.
        // The order of checks (R, S, P) ensures a consistent tie-breaking.

        char optimal_player_move = get_winning_move(most_frequent_bot_move);

        for (int i = 0; i < n; ++i) {
            std::cout << optimal_player_move;
        }
        std::cout << "\n";
    }
    return 0;
}

