    long long current_xor_sum = 0;
    for (int i = 0; i < n; ++i) {
        long long a;
        std::cin >> a;
        current_sum += a;
        current_xor_sum ^= a;
    }

    // We want to find b1, b2, b3 such that (current_sum + b1 + b2 + b3) = 2 * (current_xor_sum ^ b1 ^ b2 ^ b3)
    // A simple strategy is to append at most 3 elements.
    // Let's try to append two elements: X and S.
    // New sum = current_sum + X + S
    // New xor_sum = current_xor_sum ^ X ^ S
    // We want current_sum + X + S = 2 * (current_xor_sum ^ X ^ S)

    // Consider appending two elements: current_xor_sum and current_sum.
    // This doesn't quite work because current_sum can be very large.
    // The problem states that appended elements can be up to 10^18.

    // Let's try to append two elements: X and S_prime.
    // Where X is the current_xor_sum.
    // After appending X, the new xor_sum becomes current_xor_sum ^ X = 0.
    // The new sum becomes current_sum + X.
    // Now we need to append one more element, say Y, such that:
    // (current_sum + X + Y) = 2 * (0 ^ Y)
    // (current_sum + X + Y) = 2 * Y
    // current_sum + X = Y
    // So, Y = current_sum + current_xor_sum.

    // This strategy appends two elements:
    // 1. current_xor_sum (let's call it X_val)
    // 2. current_sum + current_xor_sum (let's call it Y_val)

    // Let's verify this:
    // Initial sum = S, initial xor_sum = X.
    // Append X_val = X.
    // Append Y_val = S + X.
    // New array sum S' = S + X + (S + X) = 2S + 2X.
    // New array xor_sum X' = X ^ X ^ (S + X) = 0 ^ (S + X) = S + X.
    // Is S' = 2 * X'?
    // 2S + 2X = 2 * (S + X). Yes, it is.

    // This strategy always works and uses exactly 2 elements.
    // The problem allows up to 3 elements, and doesn't require minimization.
    // The values can be large, up to 10^18.
