int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long l, r, Ql, Qr;
    std::cin >> n >> l >> r >> Ql >> Qr;

    std::vector<long long> w(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> w[i];
    }

    std::vector<long long> prefix_sum(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        prefix_sum[i + 1] = prefix_sum[i] + w[i];
    }

    long long min_energy = -1;

    // Iterate through all possible counts of items taken from the left
    // `i` represents the number of items taken from the left (0 to n)
    for (int i = 0; i <= n; ++i) {
        long long current_energy = 0;

        // Cost for items taken from the left
        // These are w[0]...w[i-1]
        current_energy += prefix_sum[i] * l;

        // Cost for items taken from the right
        // These are w[i]...w[n-1]
        // The number of items taken from the right is (n - i)
        current_energy += (prefix_sum[n] - prefix_sum[i]) * r;

        // Add penalty for consecutive actions
        int left_count = i;
        int right_count = n - i;

        if (left_count > right_count) {
            // More items taken from left.
            // The last (left_count - right_count - 1) items taken from left
            // will incur Ql penalty because they are taken after all right items are exhausted.
            // Example: LLLLRR. left_count=4, right_count=2.
            // The sequence could be LRLRL L L. The last two L's are consecutive.
            // The number of extra L's is left_count - right_count.
            // If left_count - right_count = 1, no penalty. (e.g., LLLRRL)
            // If left_count - right_count > 1, then (left_count - right_count - 1) penalties.
            current_energy += (left_count - right_count - 1) * Ql;
        } else if (right_count > left_count) {
            // More items taken from right.
            // The last (right_count - left_count - 1) items taken from right
            // will incur Qr penalty.
            current_energy += (right_count - left_count - 1) * Qr;
        }

        if (min_energy == -1 || current_energy < min_energy) {
            min_energy = current_energy;
        }
    }

    std::cout << min_energy << std::endl;

    return 0;
}

