long long get_max_divisor_not_divisible_by_q(long long p, long long q) {
    if (p % q != 0) {
        return p;
    }

    std::vector<long long> prime_factors_q;
    long long temp_q = q;
    for (long long i = 2; i * i <= temp_q; ++i) {
        if (temp_q % i == 0) {
            prime_factors_q.push_back(i);
            while (temp_q % i == 0) {
                temp_q /= i;
            }
        }
    }
    if (temp_q > 1) {
        prime_factors_q.push_back(temp_q);
    }

    long long max_x = 1;

    for (long long r : prime_factors_q) {
        long long current_p = p;
        while (current_p % q == 0) {
            current_p /= r;
        }
        max_x = std::max(max_x, current_p);
    }

    return max_x;
}

