int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;
    int n = s.length();

    std::vector<std::vector<int>> pos_char(26);
    for (int i = 0; i < n; ++i) {
        pos_char[s[i] - 'a'].push_back(i);
    }

    double total_prob = 0.0;

    for (int k_actual = 0; k_actual < n; ++k_actual) {
        char first_char_t = s[k_actual]; // This is t[0]

        // Find all possible k' values that could result in this t[0]
        const std::vector<int>& possible_k_indices = pos_char[first_char_t - 'a'];

        if (possible_k_indices.size() == 1) {
            // If only one k' matches t[0], Vasya wins immediately.
            total_prob += 1.0;
            continue;
        }

        // Vasya needs to choose an optimal j (1 to n-1)
        double max_win_prob_for_this_t0 = 0.0;

        for (int j = 1; j < n; ++j) { // Iterate through all possible j (1 to n-1)
            int num_unique_pairs = 0;

            // For each possible k' that matches t[0], calculate t[j]
            // and count how many unique (t[0], t[j]) pairs are formed.
            // If all (t[0], t[j]) pairs are unique, Vasya wins.

            std::vector<char> t_j_values;
            for (int k_prime : possible_k_indices) {
                t_j_values.push_back(s[(k_prime + j) % n]);
            }

            std::sort(t_j_values.begin(), t_j_values.end());

            // Count unique values in t_j_values
            if (!t_j_values.empty()) {
                num_unique_pairs = 1;
                for (size_t i = 1; i < t_j_values.size(); ++i) {
                    if (t_j_values[i] != t_j_values[i-1]) {
                        num_unique_pairs++;
                    }
                }
            }

            // The probability of winning for this specific j is num_unique_pairs / possible_k_indices.size()
            max_win_prob_for_this_t0 = std::max(max_win_prob_for_this_t0, 
                                                 static_cast<double>(num_unique_pairs) / possible_k_indices.size());
        }
        total_prob += max_win_prob_for_this_t0;
    }

    std::cout << std::fixed << std::setprecision(15) << total_prob / n << std::endl;

    return 0;
}

