    for (char c_char : used_in_s) {
        int c = c_char - 'a';
        if (!visited[c] && adj[c].size() <= 1) { // Start a new chain
            char current_char = c_char;
            while (true) {
                int current_idx = current_char - 'a';
                if (visited[current_idx]) break; // Already part of a chain

                visited[current_idx] = true;
                layout += current_char;

                char next_char = 0;
                for (char neighbor : adj[current_idx]) {
                    if (!visited[neighbor - 'a']) {
                        next_char = neighbor;
                        break;
                    }
                }
                if (next_char == 0) break; // End of chain
                current_char = next_char;
            }
        }
    }

    // Check if all characters from 's' are included and form a valid path
    if (layout.length() != used_in_s.size()) {
        // This means there's a cycle or a character with degree 2 that wasn't picked up
        // because it's not an endpoint of a chain.
        // For example, if s = "abcda", a-b-c-d-a forms a cycle.
        // Or if s = "abacaba", a-b, a-c. 'a' has degree 2.
        // The logic for starting chains from degree <= 1 should cover all valid cases.
        // If layout.length() != used_in_s.size(), it implies a problem.
        // The only way this can happen is if there's a cycle among the characters in 's'.
        // A cycle means a character has degree 2, but it's not an endpoint.
        // E.g., a-b-c-d-a. 'a' has degree 2, 'b' has degree 2, etc.
        // If we start from 'a', we go a-b-c-d. Then 'd' has 'a' as neighbor, but 'a' is visited.
        // So the chain stops at 'd'. 'a' is visited, but 'd' is not.
        // This means we need to check if all characters in `used_in_s` are visited.
        bool all_used_in_s_visited = true;
        for(char c : used_in_s) {
            if (!visited[c - 'a']) {
                all_used_in_s_visited = false;
                break;
            }
        }
        if (!all_used_in_s_visited) {
            std::cout << "NO\n";
            return;
        }
    }


    // Add remaining characters not in 's'
    for (int i = 0; i < 26; ++i) {
        if (!visited[i]) {
            layout += (char)('a' + i);
        }
    }

    std::cout << "YES\n";
    std::cout << layout << "\n";
}

