int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 2) { // Sequences of length 1 or 2 are always stable
        std::cout << 0 << std::endl;
        for (int i = 0; i < n; ++i) {
            std::cout << a[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << std::endl;
        return 0;
    }

    std::vector<int> left_zero_run(n);
    std::vector<int> right_zero_run(n);
    std::vector<int> left_one_run(n);
    std::vector<int> right_one_run(n);

    // Calculate left_zero_run and left_one_run
    left_zero_run[0] = (a[0] == 0 ? 1 : 0);
    left_one_run[0] = (a[0] == 1 ? 1 : 0);
    for (int i = 1; i < n; ++i) {
        if (a[i] == 0) {
            left_zero_run[i] = left_zero_run[i - 1] + 1;
            left_one_run[i] = 0;
        } else {
            left_one_run[i] = left_one_run[i - 1] + 1;
            left_zero_run[i] = 0;
        }
    }

    // Calculate right_zero_run and right_one_run
    right_zero_run[n - 1] = (a[n - 1] == 0 ? 1 : 0);
    right_one_run[n - 1] = (a[n - 1] == 1 ? 1 : 0);
    for (int i = n - 2; i >= 0; --i) {
        if (a[i] == 0) {
            right_zero_run[i] = right_zero_run[i + 1] + 1;
            right_one_run[i] = 0;
        } else {
            right_one_run[i] = right_one_run[i + 1] + 1;
            right_zero_run[i] = 0;
        }
    }

    int max_k = 0;
    for (int i = 0; i < n; ++i) {
        if (a[i] == 0) {
            int min_run_len = std::min(left_one_run[i], right_one_run[i]);
            if (min_run_len > 0) { // Only consider 0s that are part of a 010 or 101 pattern
                max_k = std::max(max_k, (min_run_len + 1) / 2);
            }
        } else { // a[i] == 1
            int min_run_len = std::min(left_zero_run[i], right_zero_run[i]);
            if (min_run_len > 0) { // Only consider 1s that are part of a 101 or 010 pattern
                max_k = std::max(max_k, (min_run_len + 1) / 2);
            }
        }
    }

    std::cout << max_k << std::endl;

    std::vector<int> b = a;
    for (int i = 0; i < n; ++i) {
        if (a[i] == 0) {
            int min_run_len = std::min(left_one_run[i], right_one_run[i]);
            if (min_run_len > 0 && min_run_len <= 2 * max_k - 1) {
                b[i] = 1;
            }
        } else { // a[i] == 1
            int min_run_len = std::min(left_zero_run[i], right_zero_run[i]);
            if (min_run_len > 0 && min_run_len <= 2 * max_k - 1) {
                b[i] = 0;
            }
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << b[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <map>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(2 * n);
    for (int i = 0; i < 2 * n; ++i) {
        std::cin >> a[i];
    }

    // Calculate initial total difference (strawberry_count - blueberry_count)
    int initial_diff = 0;
    for (int x : a) {
        if (x == 1) {
            initial_diff++;
        } else {
            initial_diff--;
        }
    }

    // Precompute prefix sums for the left side (jars 1 to n)
    // diff_L[i] = (strawberry_count - blueberry_count) for jars n, n-1, ..., n-i+1
    // This is equivalent to (strawberry_count - blueberry_count) for jars 1 to i
    // if we consider the left side as a separate array and iterate from right to left.
    // Let's use the problem's indexing: jars 1 to n.
    // We are interested in removing jars from n down to 1.
    // So, we calculate diffs for suffixes of the left part: a[n-1], a[n-2], ..., a[0]
    // diff_L[k] = (s_count - b_count) for jars a[n-1], a[n-2], ..., a[n-k]
    std::map<int, int> diff_L_map; // Stores diff -> k (number of jars removed from left)
    diff_L_map[0] = 0; // 0 jars removed from left, diff is 0
    int current_diff_L = 0;
    for (int k = 1; k <= n; ++k) {
        int jar_idx = n - k; // a[n-k] is the k-th jar from the right of the left half
        if (a[jar_idx] == 1) {
            current_diff_L++;
        } else {
            current_diff_L--;
        }
        if (diff_L_map.find(current_diff_L) == diff_L_map.end()) {
            diff_L_map[current_diff_L] = k;
        }
    }

    // Precompute prefix sums for the right side (jars n+1 to 2n)
    // diff_R[i] = (strawberry_count - blueberry_count) for jars n+1, n+2, ..., n+i
    // diff_R[k] = (s_count - b_count) for jars a[n], a[n+1], ..., a[n+k-1]
    std::map<int, int> diff_R_map; // Stores diff -> k (number of jars removed from right)
    diff_R_map[0] = 0; // 0 jars removed from right, diff is 0
    int current_diff_R = 0;
    for (int k = 1; k <= n; ++k) {
        int jar_idx = n + k - 1; // a[n+k-1] is the k-th jar from the left of the right half
        if (a[jar_idx] == 1) {
            current_diff_R++;
        } else {
            current_diff_R--;
        }
        if (diff_R_map.find(current_diff_R) == diff_R_map.end()) {
            diff_R_map[current_diff_R] = k;
        }
    }

    int min_removed_jars = 2 * n; // Initialize with max possible

    // Iterate through all possible numbers of jars removed from the left (L)
    // and their corresponding difference `diff_L`.
    // We need `initial_diff - diff_L - diff_R = 0`
    // which means `diff_R = initial_diff - diff_L`
    for (auto const& [diff_L_val, k_L] : diff_L_map) {
        int target_diff_R = initial_diff - diff_L_val;
        if (diff_R_map.count(target_diff_R)) {
            int k_R = diff_R_map[target_diff_R];
            min_removed_jars = std::min(min_removed_jars, k_L + k_R);
        }
    }

    std::cout << min_removed_jars << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    // For each bit position (0 to 9), track how 0 and 1 transform.
    // initial_val_0[bit_idx] stores the final value of bit_idx if it started as 0.
    // initial_val_1[bit_idx] stores the final value of bit_idx if it started as 1.
    std::vector<int> initial_val_0(10); // All bits start as 0
    std::vector<int> initial_val_1(10); // All bits start as 1

    for (int i = 0; i < 10; ++i) {
        initial_val_0[i] = 0;
        initial_val_1[i] = 1;
    }

    for (int i = 0; i < n; ++i) {
        char op_char;
        int x;
        std::cin >> op_char >> x;

        for (int bit_idx = 0; bit_idx < 10; ++bit_idx) {
            int bit_x = (x >> bit_idx) & 1;

            if (op_char == '&') {
                initial_val_0[bit_idx] &= bit_x;
                initial_val_1[bit_idx] &= bit_x;
            } else if (op_char == '|') {
                initial_val_0[bit_idx] |= bit_x;
                initial_val_1[bit_idx] |= bit_x;
            } else if (op_char == '^') {
                initial_val_0[bit_idx] ^= bit_x;
                initial_val_1[bit_idx] ^= bit_x;
            }
        }
    }

    // Now, we have the final transformation for each bit.
    // We need to find A, B, C such that:
    // (input & A | B) ^ C = final_value
    // This is equivalent to:
    // (input_bit & A_bit | B_bit) ^ C_bit = final_bit_value

    // Let's determine A_bit, B_bit, C_bit for each bit_idx.
    // We know:
    // (0 & A_bit | B_bit) ^ C_bit = initial_val_0[bit_idx]
    // (1 & A_bit | B_bit) ^ C_bit = initial_val_1[bit_idx]

    // Case 1: A_bit = 0
    // (0 & 0 | B_bit) ^ C_bit = B_bit ^ C_bit = initial_val_0[bit_idx]
    // (1 & 0 | B_bit) ^ C_bit = B_bit ^ C_bit = initial_val_1[bit_idx]
    // This implies initial_val_0[bit_idx] must be equal to initial_val_1[bit_idx].
    // If they are equal, then B_bit ^ C_bit = initial_val_0[bit_idx].
    // We can choose B_bit = 0, then C_bit = initial_val_0[bit_idx].
    // Or choose B_bit = 1, then C_bit = 1 ^ initial_val_0[bit_idx].
    // Let's try A_bit = 0, B_bit = 0, C_bit = initial_val_0[bit_idx].
    // This means the bit is always C_bit, regardless of input.
    // This is equivalent to (input_bit & 0 | C_bit) ^ 0 = C_bit.
    // Or (input_bit & 0 | 0) ^ C_bit = C_bit.

    // Case 2: A_bit = 1
    // (0 & 1 | B_bit) ^ C_bit = B_bit ^ C_bit = initial_val_0[bit_idx]
    // (1 & 1 | B_bit) ^ C_bit = (1 | B_bit) ^ C_bit = 1 ^ C_bit = initial_val_1[bit_idx]
    // From the second equation, C_bit = 1 ^ initial_val_1[bit_idx].
    // Substitute C_bit into the first equation: B_bit ^ (1 ^ initial_val_1[bit_idx]) = initial_val_0[bit_idx].
    // B_bit = initial_val_0[bit_idx] ^ 1 ^ initial_val_1[bit_idx].
    // So, A_bit=1, B_bit=initial_val_0[bit_idx] ^ 1 ^ initial_val_1[bit_idx], C_bit=1 ^ initial_val_1[bit_idx].

    // Let's try to construct the three constants for AND, OR, XOR.
    // We want to find `and_const`, `or_const`, `xor_const`.
    // The final program will be: `& and_const`, `| or_const`, `^ xor_const`.
    // The order matters. Let's assume this order.
    // (x & and_const | or_const) ^ xor_const

    int final_and_const = 0; // All bits 1 initially, then ANDed down
    int final_or_const = 0;  // All bits 0 initially, then ORed up
    int final_xor_const = 0; // All bits 0 initially, then XORed

    for (int bit_idx = 0; bit_idx < 10; ++bit_idx) {
        int val0 = initial_val_0[bit_idx];
        int val1 = initial_val_1[bit_idx];

        if (val0 == 0 && val1 == 0) {
            // Input bit 0 -> 0, Input bit 1 -> 0
            // This means the output bit is always 0.
            // (x_bit & 0 | 0) ^ 0 = 0
            // So, for this bit: and_const_bit = 0, or_const_bit = 0, xor_const_bit = 0
            // This means we need to force the bit to 0.
            // (x_bit & 0) will make it 0.
            // So, final_and_const's bit_idx should be 0.
            // final_or_const's bit_idx should be 0.
            // final_xor_const's bit_idx should be 0.
            // (x_bit & 0 | 0) ^ 0 = 0
            final_and_const &= ~(1 << bit_idx); // Set bit to 0
            final_or_const &= ~(1 << bit_idx);  // Set bit to 0
            final_xor_const &= ~(1 << bit_idx); // Set bit to 0
        } else if (val0 == 0 && val1 == 1) {
            // Input bit 0 -> 0, Input bit 1 -> 1
            // This means the output bit is the same as the input bit.
            // (x_bit & 1 | 0) ^ 0 = x_bit
            // So, for this bit: and_const_bit = 1, or_const_bit = 0, xor_const_bit = 0
            final_and_const |= (1 << bit_idx); // Set bit to 1
            final_or_const &= ~(1 << bit_idx);  // Set bit to 0
            final_xor_const &= ~(1 << bit_idx); // Set bit to 0
        } else if (val0 == 1 && val1 == 0) {
            // Input bit 0 -> 1, Input bit 1 -> 0
            // This means the output bit is the inverse of the input bit.
            // (x_bit & 1 | 0) ^ 1 = ~x_bit
            // So, for this bit: and_const_bit = 1, or_const_bit = 0, xor_const_bit = 1
            final_and_const |= (1 << bit_idx); // Set bit to 1
            final_or_const &= ~(1 << bit_idx);  // Set bit to 0
            final_xor_const |= (1 << bit_idx); // Set bit to 1
        } else if (val0 == 1 && val1 == 1) {
            // Input bit 0 -> 1, Input bit 1 -> 1
            // This means the output bit is always 1.
            // (x_bit & 0 | 1) ^ 0 = 1
            // So, for this bit: and_const_bit = 0, or_const_bit = 1, xor_const_bit = 0
            final_and_const &= ~(1 << bit_idx); // Set bit to 0
            final_or_const |= (1 << bit_idx);  // Set bit to 1
            final_xor_const &= ~(1 << bit_idx); // Set bit to 0
        }
    }

    std::vector<std::pair<char, int>> result_ops;
    if (final_and_const != 1023) { // If not all bits are 1, then & operation is needed
        result_ops.push_back({'&', final_and_const});
    }
    if (final_or_const != 0) { // If not all bits are 0, then | operation is needed
        result_ops.push_back({'|', final_or_const});
    }
    if (final_xor_const != 0) { // If not all bits are 0, then ^ operation is needed
        result_ops.push_back({'^', final_xor_const});
    }

    std::cout << result_ops.size() << "\n";
    for (const auto& op : result_ops) {
        std::cout << op.first << " " << op.second << "\n";
    }

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <cmath>
#include <algorithm>

void solve() {
    std::string s;
    std::cin >> s;
    int n = s.length();
    long long good_substrings_count = 0;

    // Max possible value for f(t) is N (length of s), which is 2e5.
    // 2^17 = 131072
    // 2^18 = 262144
    // So, the maximum length of a binary string whose decimal value is <= 2e5 is 18.
    // We can iterate through all possible starting positions `i`.
    // For each `i`, we can extend the substring to the right.
    // The maximum length of substring we need to check is 18 (or slightly more to be safe, say 20).
    // Let's use a constant `MAX_CHECK_LEN` for this.
    // A safe upper bound for MAX_CHECK_LEN would be 18 + 1 (for 0s) + 1 (safety) = 20.
    // Or simply, if the value exceeds N, we can stop.
    // The maximum value of N is 2e5.
    // The maximum length of a substring we need to consider is 18 (for 1xxxx... pattern).
    // If the substring starts with '0', it can have many leading zeros.
    // The actual length of the substring can be up to N.
    // The value f(t) is at most N.
    // The number of bits required to represent N is log2(N).
    // For N = 2e5, log2(2e5) is about 17.6. So, at most 18 bits.
    // This means the '1' in the binary representation cannot be further than 18 positions from the right end of the substring.
    // If a substring is s[l...r], its length is len = r - l + 1.
    // The value f(s[l...r]) must be equal to len.
    // If s[l] is '1', then the value is at least 2^(len-1).
    // If s[l] is '0', then we need to find the first '1' to calculate the value.
    // Let's iterate through all possible starting positions `i`.
    // For each `i`, we iterate through possible ending positions `j`.
    // The length of the substring s[i...j] is `len = j - i + 1`.
    // We need to calculate `val = f(s[i...j])`.
    // If `val == len`, it's a good substring.

    // The crucial observation is that if s[i] is '1', then `val` grows exponentially with `len`.
    // If `len` is large, `val` will quickly exceed `n`.
    // Specifically, if `s[i] == '1'`, then `val >= 2^(len-1)`.
    // If `2^(len-1) > n`, then `val > n`, so `val` cannot be equal to `len` (since `len <= n`).
    // `2^(len-1) > n` implies `len-1 > log2(n)`.
    // For `n = 2e5`, `log2(n)` is approx 17.6. So `len-1 > 17.6`, meaning `len > 18.6`.
    // So, if `s[i] == '1'`, we only need to check `len` up to about 19.
    // Let's set a practical limit, say `MAX_BITS = 20`.
    // This means for `s[i] == '1'`, we only need to check `j` such that `j - i + 1 <= MAX_BITS`.

    // What if `s[i]` is '0'?
    // Then `f(s[i...j])` is the value of `s[k...j]` where `k` is the first index >= `i` such that `s[k] == '1'`.
    // If all characters from `s[i...j]` are '0', then `f(s[i...j]) = 0`.
    // In this case, `len = j - i + 1`. If `len = 0`, it's a good substring. But `len` is always at least 1.
    // So `f(00...0) = 0` can never be equal to `len >= 1`.
    // Thus, a substring consisting only of '0's is never good.
    // This means we only care about substrings that contain at least one '1'.

    // Let's iterate `i` from `0` to `n-1`.
    // For each `i`, we iterate `j` from `i` to `n-1`.
    // We maintain the current binary value `current_val` and current length `current_len`.
    // We also need to handle leading zeros.

    for (int i = 0; i < n; ++i) {
        long long current_val = 0;
        // We need to find the first '1' to start calculating the value.
        // Let's say `first_one_idx` is the index of the first '1' in `s[i...j]`.
        // If `s[i]` is '0', we can skip it and count how many leading zeros there are.
        // The actual binary value starts from the first '1'.
        // The length of the substring is `j - i + 1`.
        // The value `f(s[i...j])` is the decimal value of `s[first_one_idx ... j]`.

        // Strategy: Iterate `i` from `0` to `n-1`.
        // For each `i`, iterate `j` from `i` to `n-1`.
        // Calculate `val = f(s[i...j])`.
        // If `val == j - i + 1`, increment count.
        // This is too slow (O(N^2 * logN) or O(N^2)). N=2e5, N^2=4e10.

        // Optimized strategy:
        // Iterate `i` from `0` to `n-1`.
        // Maintain `current_val` for `s[k...j]` where `k` is the first '1' in `s[i...j]`.
        // Maintain `leading_zeros_count` for `s[i...k-1]`.
        // The total length is `leading_zeros_count + (j - k + 1)`.

        // Let's fix the starting position `i`.
        // We need to find the first '1' at or after `i`.
        int first_one_idx = -1;
        for (int k = i; k < n; ++k) {
            if (s[k] == '1') {
                first_one_idx = k;
                break;
            }
        }

        if (first_one_idx == -1) {
            // No '1's from `i` to `n-1`. All remaining substrings are '0's.
            // f(00...0) = 0. Length is always >= 1. So no good substrings.
            break; // No more '1's in the rest of the string.
        }

        // Now `first_one_idx` is the index of the first '1' at or after `i`.
        // The number of leading zeros for a substring starting at `i` and having its first '1' at `first_one_idx` is `first_one_idx - i`.
        int leading_zeros = first_one_idx - i;
        current_val = 0;

        // Iterate `j` from `first_one_idx` to `n-1`.
        // This `j` is the right endpoint of the substring `s[i...j]`.
        // The actual binary value is formed by `s[first_one_idx ... j]`.
        // The length of this binary value part is `j - first_one_idx + 1`.
        // The total length of the substring `s[i...j]` is `leading_zeros + (j - first_one_idx + 1)`.

        for (int j = first_one_idx; j < n; ++j) {
            // Update current_val
            current_val = (current_val << 1) | (s[j] - '0');

            // Check if current_val exceeds a reasonable limit.
            // If current_val > n + MAX_BITS (e.g., 2e5 + 20), it's too large.
            // The maximum possible length is n.
            // If current_val > n, it cannot be equal to the length.
            // The length of the binary part is `j - first_one_idx + 1`.
            // The total length of the substring is `leading_zeros + (j - first_one_idx + 1)`.
            // If `current_val` becomes very large, it will exceed `n` and also `total_length`.
            // A safe upper bound for `current_val` to check is `n + MAX_BITS`.
            // `MAX_BITS` is roughly 18. So `n + 18`.
            // If `current_val` exceeds `n + 18`, then it's definitely too large to be equal to `total_length`.
            // This is because `total_length` is at most `n`.
            // So, if `current_val > n + 18`, we can break from this inner loop.
            // This is the key optimization.
            if (current_val > n + 20) { // Using 20 as a slightly larger safe constant
                break;
            }

            long long total_length = leading_zeros + (j - first_one_idx + 1);

            if (current_val == total_length) {
                good_substrings_count++;
            }
        }
    }

    std::cout << good_substrings_count << std::endl;
}

