struct Operation {
    int type;
    int l, r;
    long long val; // d for type 1, m for type 2
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<Operation> ops(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> ops[i].type >> ops[i].l >> ops[i].r >> ops[i].val;
        ops[i].l--; // 0-indexed
        ops[i].r--; // 0-indexed
    }

    // Initialize b[i] to a very large value.
    // b[i] will store the maximum possible initial value for a[i].
    // If a[i] + sum_d_up_to_op_k(i) <= m_k, then a[i] <= m_k - sum_d_up_to_op_k(i).
    // We want a[i] to be as large as possible to satisfy max constraints,
    // but also as small as possible to satisfy max constraints.
    // This is a bit confusing. Let's rephrase.
    // For each type 2 operation (l, r, m_k), we know that for any j in [l, r],
    // initial_a[j] + current_delta[j] <= m_k.
    // This implies initial_a[j] <= m_k - current_delta[j].
    // So, for each j, initial_a[j] must be less than or equal to the minimum
    // of (m_k - current_delta[j]) over all type 2 operations k where j is in [l_k, r_k].
    std::vector<long long> b(n, std::numeric_limits<long long>::max());

    // current_delta[j] stores the sum of d values applied to a[j] up to the current operation.
    std::vector<long long> current_delta(n, 0);

    for (int i = 0; i < m; ++i) {
        if (ops[i].type == 1) {
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                current_delta[j] += ops[i].val;
            }
        } else { // type 2
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                b[j] = std::min(b[j], ops[i].val - current_delta[j]);
            }
        }
    }

    // Now we have the candidate initial array `b`.
    // We need to verify if this `b` satisfies all type 2 operations.
    // The initial array `a` is `b`.
    // We need to simulate all operations with `b` as the initial array
    // and check if all type 2 constraints are met.

    // Reset current_delta for simulation
    std::fill(current_delta.begin(), current_delta.end(), 0);

    for (int i = 0; i < m; ++i) {
        if (ops[i].type == 1) {
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                current_delta[j] += ops[i].val;
            }
        } else { // type 2
            long long max_val_in_range = std::numeric_limits<long long>::min();
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                max_val_in_range = std::max(max_val_in_range, b[j] + current_delta[j]);
            }
            if (max_val_in_range != ops[i].val) {
                std::cout << "NO\n";
                return 0;
            }
        }
    }

    std::cout << "YES\n";
    for (int i = 0; i < n; ++i) {
        // If b[i] remained at max_long_long, it means it was never constrained by a type 2 op.
        // We can set it to 0, as 0 satisfies |a_i| <= 10^9.
        // The problem statement says "all numbers in his array didn't exceed 10^9 in their absolute value".
        // Our construction ensures b[i] <= m_k - current_delta[j].
        // m_k is up to 5*10^7. current_delta[j] can be up to 5000 * 10^4 = 5*10^7.
        // So b[i] can be around 0.
        // If b[i] is unconstrained, setting it to 0 is fine.
        // If it's constrained, it will be <= 5*10^7 - (-5*10^7) = 10^8, which is within 10^9.
        // The minimum value for b[i] could be -5*10^7 - (5*10^7) = -10^8.
        // So b[i] will always be within [-10^8, 10^8] if constrained, or max_long_long if not.
        // Setting max_long_long to 0 is safe.
        if (b[i] == std::numeric_limits<long long>::max()) {
            std::cout << 0 << (i == n - 1 ? "" : " ");
        } else {
            std::cout << b[i] << (i == n - 1 ? "" : " ");
        }
    }
    std::cout << "\n";

    return 0;
}

