    // If n=2, only one pair (a_1, a_2). If they are in different groups, f = a_1 + a_2 + h.
    // If they are in the same group, f = a_1 + a_2.
    // So for n=2, goodness is always 0.
    // The problem states 2 <= n <= 10^5.
    // If n=2, elements[0].value and elements[1].value.
    // Goodness1 = (elements[1].value + elements[0].value) - (elements[0].value + elements[1].value) = 0.
    //
    // For n=2, the only pair is (a_1, a_2).
    // If same group: f = a_1 + a_2. min_f = max_f = a_1 + a_2. Goodness = 0.
    // If different groups: f = a_1 + a_2 + h. min_f = max_f = a_1 + a_2 + h. Goodness = 0.
    // So for n=2, goodness is always 0.
    // The code for n=2 should output 0 and 1 1 (or 1 2).
    // My current code for n=2: goodness1 = 0. partition1 = {1,1}. This is correct.

    // For n > 2:
    // Consider the partition where a_1 is in group 1, and a_2, ..., a_n are in group 2.
    long long min_f_case2, max_f_case2;
    if (n == 2) { // This case is already handled by goodness1 = 0.
        min_f_case2 = elements[0].value + elements[1].value + h;
        max_f_case2 = elements[0].value + elements[1].value + h;
    } else {
        min_f_case2 = std::min(elements[1].value + elements[2].value, elements[0].value + elements[1].value + h);
        max_f_case2 = std::max(elements[n - 2].value + elements[n - 1].value, elements[0].value + elements[n - 1].value + h);
    }
    long long goodness2 = max_f_case2 - min_f_case2;
    std::vector<int> partition2(n);
    partition2[elements[0].original_index] = 1;
    for (int i = 1; i < n; ++i) {
        partition2[elements[i].original_index] = 2;
    }

    // Compare goodness1 and goodness2
    if (goodness1 <= goodness2) {
        std::cout << goodness1 << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << partition1[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    } else {
        std::cout << goodness2 << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << partition2[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <cmath>

bool check(long long T, int n, int m, const std::vector<long long>& h, const std::vector<long long>& p) {
    int p_idx = 0;
    for (int h_idx = 0; h_idx < n; ++h_idx) {
        if (p_idx == m) { // All tracks covered
            return true;
        }

        long long current_h = h[h_idx];

        // If current head can cover p[p_idx]
        if (std::abs(current_h - p[p_idx]) <= T) {
            // This head can cover p[p_idx] and potentially more tracks to its right.
            // The rightmost track this head can cover is current_h + T.
            long long cover_limit = current_h + T;

            // Advance p_idx past all tracks covered by this head.
            while (p_idx < m && p[p_idx] <= cover_limit) {
                p_idx++;
            }
        }
    }
    return p_idx == m; // True if all tracks are covered
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<long long> h(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> h[i];
    }

    std::vector<long long> p(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> p[i];
    }

    long long low = 0;
    long long high = 20000000000LL; // Max possible distance is 10^10, so 2*10^10 is a safe upper bound for T.
    long long ans = high;

    while (low <= high) {
        long long mid = low + (high - low) / 2;
        if (check(mid, n, m, h, p)) {
            ans = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    std::cout << ans << std::endl;

    return 0;
}

