#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n, d;
        std::cin >> n >> d;
        std::vector<int> a(n);
        for (int i = 0; i < n; ++i) {
            std::cin >> a[i];
        }

        long long haybales_in_pile1 = a[0]; // Start with initial haybales in pile 1

        // Iterate through piles from 2 to n (index 1 to n-1)
        for (int i = 1; i < n; ++i) {
            int cost_per_haybale = i; // Cost to move one haybale from pile (i+1) to pile 1
                                      // Pile index i in 0-based array corresponds to pile (i+1) in 1-based problem description
                                      // Cost is (i+1) - 1 = i days

            if (d == 0) { // If no days left, can't move any more haybales
                break;
            }

            // Calculate how many haybales can be moved from current pile 'i'
            // based on available days 'd' and cost 'cost_per_haybale'.
            // Each haybale costs 'cost_per_haybale' days.
            // We have 'a[i]' haybales in this pile.

            int max_haybales_to_move_from_this_pile = d / cost_per_haybale;

            // The actual number of haybales we can move is limited by
            // either the haybales available in the pile (a[i])
            // or the haybales we can afford to move (max_haybales_to_move_from_this_pile).
            int haybales_moved = std::min(a[i], max_haybales_to_move_from_this_pile);

            haybales_in_pile1 += haybales_moved;
            d -= haybales_moved * cost_per_haybale;
        }
        std::cout << haybales_in_pile1 << std::endl;
    }
    return 0;
}

