#include <iostream>
#include <string>
#include <vector>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n, k;
    std::cin >> n >> k;
    std::string s;
    std::cin >> s;

    std::string result = "";
    int open_needed = k / 2;
    int close_needed = k / 2;

    for (char c : s) {
        if (c == '(' && open_needed > 0) {
            result += '(';
            open_needed--;
        } else if (c == ')' && close_needed > 0) {
            // Only add ')' if we have already added more '(' than ')'
            // or if we have added enough '(' and still need ')'
            // The condition `result.length() - (k/2 - open_needed) > (k/2 - close_needed)`
            // ensures that the current balance of '(' and ')' in `result` is positive
            // before adding a ')'
            // A simpler way is to just add ')' if we still need them and we have enough '('
            // to balance them eventually.
            // The problem guarantees a solution exists.
            // A greedy approach of taking first k/2 '(' and first k/2 ')' that appear after them
            // will work because the original string is regular.
            // We just need to ensure we don't add more ')' than '(' at any point.
            // The `open_needed` and `close_needed` counts are for the final string.
            // `k/2 - open_needed` is the count of '(' already added.
            // `k/2 - close_needed` is the count of ')' already added.
            // We can add ')' if `(k/2 - open_needed) > (k/2 - close_needed)`
            // This means `open_count_in_result > close_count_in_result`
            if ((k / 2 - open_needed) > (k / 2 - close_needed) && close_needed > 0) {
                result += ')';
                close_needed--;
            }
        }
        if (open_needed == 0 && close_needed == 0) {
            break;
        }
    }

    std::cout << result << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 1) {
        std::cout << 0 << std::endl;
        return;
    }

    // Find the rightmost index `p` such that a[p...n-1] is a non-increasing suffix.
    // This means a[p] >= a[p+1] >= ... >= a[n-1].
    // We start from n-1 and move left.
    int p = n - 1;
    while (p > 0 && a[p-1] >= a[p]) {
        p--;
    }

    // Now, a[p...n-1] is non-increasing.
    // We need to find the rightmost index `q` such that a[q...p-1] is a non-decreasing suffix.
    // This means a[q] <= a[q+1] <= ... <= a[p-1].
    // We start from p-1 and move left.
    // If p is 0, this loop won't run, which is correct.
    int q = p; // q is the start of the non-decreasing part.
    while (q > 0 && a[q-1] <= a[q]) {
        q--;
    }

    // The prefix to erase has length `q`.
    // The remaining array is a[q...n-1].
    // This remaining array has the structure:
    // [non-decreasing part] [non-increasing part]
    // a[q...p-1] is non-decreasing.
    // a[p...n-1] is non-increasing.
    // This structure is exactly what makes an array "good".
    // For example, if a[q...p-1] is [1,2,3] and a[p...n-1] is [5,4,3],
    // the combined array is [1,2,3,5,4,3].
    // We can pick 1, then 2, then 3 (from left), then 3, then 4, then 5 (from right).
    // This forms [1,2,3,3,4,5], which is non-decreasing.

    std::cout << q << std::endl;
}

