#include <iostream>
#include <vector>
#include <string>
#include <algorithm> // For std::min and std::max

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    std::vector<int> pos(n + 1); // pos[x] stores the 0-indexed position of x in p
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
        pos[p[i]] = i;
    }

    std::string ans(n, '0');

    // For m=1, the subsegment is just [1]. This is always possible.
    // The segment is p[pos[1]...pos[1]]. Its length is 1. Min is 1, Max is 1.
    ans[0] = '1';

    // Initialize current min_idx and max_idx for the segment containing 1
    int min_idx = pos[1];
    int max_idx = pos[1];

    // Iterate for m from 2 to n
    for (int m = 2; m <= n; ++m) {
        // Update min_idx and max_idx to include the number m
        min_idx = std::min(min_idx, pos[m]);
        max_idx = std::max(max_idx, pos[m]);

        // Check if the current segment [min_idx ... max_idx]
        // is a permutation of 1, ..., m.
        // This means its length must be exactly m.
        // The length of the segment is (max_idx - min_idx + 1).
        if (max_idx - min_idx + 1 == m) {
            ans[m - 1] = '1';
        } else {
            ans[m - 1] = '0';
        }
    }

    std::cout << ans << std::endl;
}

