    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }
    std::sort(a.begin(), a.end());
    int count = 0;
    int left_ptr = 0; // Pointer for elements to be placed (the 'B' array elements)
    int right_ptr = 0; // Pointer for original positions (the 'A' array elements)

    while (left_ptr < n && right_ptr < n) {
        // We want to find an element a[left_ptr] such that a[left_ptr] > a[right_ptr]
        // If a[left_ptr] is greater than a[right_ptr], we can make a match.
        // We increment both pointers and the count.
        if (a[left_ptr] > a[right_ptr]) {
            count++;
            left_ptr++;
            right_ptr++;
        } else {
            // If a[left_ptr] is not greater than a[right_ptr],
            // it means a[left_ptr] <= a[right_ptr].
            // This a[left_ptr] cannot be placed at position right_ptr to satisfy the condition.
            // We try the next larger element for the 'B' array, so we increment left_ptr.
            // The current a[right_ptr] position remains to be filled by a larger element.
            left_ptr++;
        }
    }
    std::cout << count << std::endl;
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n == 1) {
        std::cout << "Yes\n";
        return;
    }

    std::vector<long long> prefix_min_ops(n);
    prefix_min_ops[0] = 0; // a[0] must be >= 0. We can always make it 0.
    for (int i = 1; i < n; ++i) {
        // To satisfy a[i] > a[i-1], we need a[i] >= a[i-1] + 1.
        // The minimum value a[i-1] can take is i-1 (to satisfy a[0]=0, a[1]=1, ..., a[i-1]=i-1).
        // So, a[i] must be at least i.
        // The number of operations needed for a[i] to be at least i is max(0, i - a[i]).
        // We want to find the minimum number of operations to make a[i] >= i.
        // This is equivalent to checking if a[i] is large enough to be at least i.
        // If a[i] < i, it's impossible to make it i by only decreasing.
        // So, we need a[i] >= i for the prefix.
        if (a[i] < i) {
            prefix_min_ops[i] = -1; // Mark as impossible
        } else {
            prefix_min_ops[i] = 0; // Possible, no additional ops needed for this element to meet minimum
        }
    }

    std::vector<long long> suffix_min_ops(n);
    suffix_min_ops[n - 1] = 0; // a[n-1] must be >= 0. We can always make it 0.
    for (int i = n - 2; i >= 0; --i) {
        // To satisfy a[i] > a[i+1], we need a[i] >= a[i+1] + 1.
        // The minimum value a[i+1] can take is 0.
        // The minimum value a[i] can take is n-1-i (to satisfy a[n-1]=0, a[n-2]=1, ..., a[i]=n-1-i).
        // So, a[i] must be at least n-1-i.
        // If a[i] < n-1-i, it's impossible.
        if (a[i] < (n - 1 - i)) {
            suffix_min_ops[i] = -1; // Mark as impossible
        } else {
            suffix_min_ops[i] = 0; // Possible
        }
    }

    bool possible = false;
    for (int k = 0; k < n; ++k) {
        // For a peak at index k (0-indexed):
        // Left part: a[0] < a[1] < ... < a[k].
        // This requires a[i] >= i for all i <= k.
        // Right part: a[k] > a[k+1] > ... > a[n-1].
        // This requires a[i] >= (n-1-i) for all i >= k.

        // Check if prefix up to k is possible
        bool prefix_ok = true;
        for (int i = 0; i <= k; ++i) {
            if (prefix_min_ops[i] == -1) {
                prefix_ok = false;
                break;
            }
        }
        if (!prefix_ok) continue;

        // Check if suffix from k is possible
        bool suffix_ok = true;
        for (int i = k; i < n; ++i) {
            if (suffix_min_ops[i] == -1) {
                suffix_ok = false;
                break;
            }
        }
        if (!suffix_ok) continue;

        // If both prefix and suffix conditions are met for the minimum values,
        // then it's possible to form a sharpened array.
        // Specifically, we can make a[i] = i for i <= k, and a[i] = n-1-i for i >= k.
        // The value at a[k] would be k from the prefix requirement and n-1-k from the suffix requirement.
        // We need a[k] to be at least max(k, n-1-k).
        // Since we can decrease elements, if a[k] is large enough to satisfy both (i.e., a[k] >= k AND a[k] >= n-1-k),
        // then we can pick a value for a[k] that is greater than a[k-1] (which is k-1) and greater than a[k+1] (which is n-1-(k+1)).
        // The minimum value for a[k] to satisfy both chains is max(k, n-1-k).
        // Since we already checked a[k] >= k (via prefix_min_ops[k]) and a[k] >= n-1-k (via suffix_min_ops[k]),
        // this means a[k] is large enough to be the peak.
        possible = true;
        break;
    }

    if (possible) {
        std::cout << "Yes\n";
    } else {
        std::cout << "No\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

struct Element {
    long long value;
    int original_index;
};

bool compareA(const Element& a, const Element& b) {
    return a.value < b.value;
}

bool compareB(const Element& a, const Element& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int m;
    std::cin >> m;

    std::vector<Element> a_elements(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> a_elements[i].value;
        a_elements[i].original_index = i;
    }

    std::vector<Element> b_elements(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> b_elements[i].value;
        b_elements[i].original_index = i;
    }

    // Sort A in ascending order
    std::sort(a_elements.begin(), a_elements.end(), compareA);

    // Sort B in ascending order
    std::sort(b_elements.begin(), b_elements.end(), compareB);

    // The optimal strategy is to pair the largest A_i with the largest B_j,
    // the second largest A_i with the second largest B_j, and so on.
    // This means if A is sorted ascending, and B is sorted ascending,
    // we pair A[i] with B[i].
    // However, we need to output A' in the original order of B.
    // So, if B_sorted[i] was originally at index b_elements[i].original_index,
    // then A_sorted[i] should be placed at that index in the result array.

    std::vector<long long> result_a_prime(m);
    for (int i = 0; i < m; ++i) {
        // a_elements[m - 1 - i].value is the i-th largest value from A
        // b_elements[i].original_index is the original index of the i-th smallest value from B
        // We want to pair the i-th largest A with the i-th largest B.
        // Since B is sorted ascending, b_elements[i] is the i-th smallest B value.
        // So, b_elements[m - 1 - i] is the i-th largest B value.
        // We assign the i-th largest A value to the original position of the i-th largest B value.
        result_a_prime[b_elements[m - 1 - i].original_index] = a_elements[m - 1 - i].value;
    }

    for (int i = 0; i < m; ++i) {
        std::cout << result_a_prime[i] << (i == m - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

