}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>
#include <set>

// Function to check if a sub-array is a permutation of 1 to its length
bool is_permutation(const std::vector<int>& arr, int start_idx, int end_idx) {
    int len = end_idx - start_idx + 1;
    if (len <= 0) return false; // Should not happen with 1-based indexing for length

    std::vector<bool> seen(len + 1, false);
    int max_val = 0;

    for (int i = start_idx; i <= end_idx; ++i) {
        if (arr[i] < 1 || arr[i] > len) {
            return false; // Value out of range [1, len]
        }
        if (seen[arr[i]]) {
            return false; // Duplicate value
        }
        seen[arr[i]] = true;
        if (arr[i] > max_val) {
            max_val = arr[i];
        }
    }

    // Check if all numbers from 1 to len were seen
    // This is implicitly covered if max_val == len and no duplicates and all values are in [1, len]
    // But explicitly checking seen array is safer.
    for (int i = 1; i <= len; ++i) {
        if (!seen[i]) {
            return false;
        }
    }

    return max_val == len;
}

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    std::vector<int> prefix_max(n);
    std::vector<bool> prefix_is_perm(n, false);
    std::vector<bool> seen_prefix(n + 1, false);
    int current_max = 0;
    bool current_is_perm = true;
    int distinct_count = 0;

    for (int i = 0; i < n; ++i) {
        if (a[i] < 1 || a[i] > i + 1) { // Value must be within [1, current_length]
            current_is_perm = false;
        }
        if (seen_prefix[a[i]]) { // Duplicate found
            current_is_perm = false;
        } else {
            seen_prefix[a[i]] = true;
            distinct_count++;
        }
        if (a[i] > current_max) {
            current_max = a[i];
        }

        prefix_max[i] = current_max;
        if (current_is_perm && distinct_count == i + 1 && current_max == i + 1) {
            prefix_is_perm[i] = true;
        }
    }

    std::vector<int> suffix_max(n);
    std::vector<bool> suffix_is_perm(n, false);
    std::fill(seen_prefix.begin(), seen_prefix.end(), false); // Reuse seen_prefix for suffix
    current_max = 0;
    current_is_perm = true;
    distinct_count = 0;

    for (int i = n - 1; i >= 0; --i) {
        int len = n - i;
        if (a[i] < 1 || a[i] > len) { // Value must be within [1, current_length]
            current_is_perm = false;
        }
        if (seen_prefix[a[i]]) { // Duplicate found
            current_is_perm = false;
        } else {
            seen_prefix[a[i]] = true;
            distinct_count++;
        }
        if (a[i] > current_max) {
            current_max = a[i];
        }

        suffix_max[i] = current_max;
        if (current_is_perm && distinct_count == len && current_max == len) {
            suffix_is_perm[i] = true;
        }
    }

    std::vector<std::pair<int, int>> results;
    for (int l1 = 1; l1 < n; ++l1) {
        int l2 = n - l1;
        if (prefix_is_perm[l1 - 1] && suffix_is_perm[l1]) {
            results.push_back({l1, l2});
        }
    }

    std::cout << results.size() << "\n";
    for (const auto& p : results) {
        std::cout << p.first << " " << p.second << "\n";
    }
}

