int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;

    long long total_steps = 0;
    long long b_count = 0;
    long long MOD = 1e9 + 7;

    // Iterate through the string from right to left
    for (int i = s.length() - 1; i >= 0; --i) {
        if (s[i] == 'b') {
            b_count = (b_count + 1) % MOD;
        } else { // s[i] == 'a'
            // Each 'a' needs to move past all 'b's to its right.
            // When an 'a' moves past a 'b', it consumes one 'b' and creates two 'b's.
            // Effectively, it doubles the number of 'b's it needs to pass.
            // The number of steps for this 'a' is equal to the current b_count.
            // After this 'a' moves past all 'b's, it effectively adds b_count new 'b's
            // to the left of the original 'b's it passed.
            // These new 'b's will be available for 'a's further to the left.
            total_steps = (total_steps + b_count) % MOD;
            b_count = (b_count * 2) % MOD;
        }
    }

    std::cout << total_steps << std::endl;

    return 0;
}

