#include <iostream>
#include <vector>
#include <string>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::string s;
    std::cin >> s;

    std::string result(n, ' ');

    for (int x = 0; x <= 9; ++x) {
        bool possible = true;
        char last1 = '0'; // Last digit in S1
        char last2 = '0'; // Last digit in S2
        bool first_x_in_S2_found = false; // Flag to ensure all x's before the first x in S2 go to S1

        for (int i = 0; i < n; ++i) {
            char current_digit = s[i];
            if (current_digit < (x + '0')) {
                // Must be in S1
                if (current_digit < last1) {
                    possible = false;
                    break;
                }
                result[i] = '1';
                last1 = current_digit;
            } else if (current_digit > (x + '0')) {
                // Must be in S2
                if (current_digit < last2) {
                    possible = false;
                    break;
                }
                result[i] = '2';
                last2 = current_digit;
                first_x_in_S2_found = true; // Any x encountered after this must also go to S2
            } else { // current_digit == (x + '0')
                if (!first_x_in_S2_found) {
                    // Try to put it in S2 first, if it maintains sorted order
                    if (current_digit >= last2) {
                        result[i] = '2';
                        last2 = current_digit;
                        first_x_in_S2_found = true;
                    } else {
                        // Cannot put in S2, must put in S1
                        if (current_digit < last1) {
                            possible = false;
                            break;
                        }
                        result[i] = '1';
                        last1 = current_digit;
                    }
                } else {
                    // All subsequent 'x's must go to S2
                    if (current_digit < last2) {
                        possible = false;
                        break;
                    }
                    result[i] = '2';
                    last2 = current_digit;
                }
            }
        }

        if (possible) {
            // Final check: last digit of S1 <= first digit of S2
            // This is implicitly handled by the logic:
            // last1 is the maximum digit assigned to S1.
            // last2 is the minimum digit assigned to S2.
            // If last1 > last2, it means a digit smaller than last1 was assigned to S2,
            // or a digit larger than last2 was assigned to S1, which would have been caught.
            // The only case where last1 could be > last2 is if last1 was an 'x' and last2 was an 'x',
            // but the split point logic ensures that all 'x's after the first 'x' in S2 go to S2.
            // If last1 is an 'x' and last2 is an 'x', then last1 == last2.
            // If last1 is < 'x' and last2 is 'x', then last1 < last2.
            // If last1 is 'x' and last2 is > 'x', then last1 < last2.
            // The only problematic case is if last1 > last2, which means a digit from S1 is greater than a digit from S2.
            // This is impossible with the current logic because digits < x go to S1, digits > x go to S2.
            // Digits == x are split such that those before the split go to S1 and those after go to S2.
            // So, max(S1) <= x and min(S2) >= x. Thus max(S1) <= min(S2) is always true.
            std::cout << result << "\n";
            return;
        }
    }

    std::cout << "-\n";
}

