                // Chanek: 3+1=4. Opponent: 1+1=2. (Example output says Chanek gets 4)

                // The greedy strategy seems to be:
                // If N is odd, take 1.
                // If N is even:
                //   If N/2 is odd (i.e., N = 2 * odd_number), take N/2.
                //   If N/2 is even (i.e., N = 4 * any_number), take 1.
                // Let's re-test with this refined strategy.

                // N=5 (odd): Chanek takes 1. N=4. Chanek: 1.
                // N=4 (even, N/2=2 is even): Opponent takes 1. N=3. Opponent: 1.
                // N=3 (odd): Chanek takes 1. N=2. Chanek: 1+1=2.
                // N=2 (even, N/2=1 is odd): Opponent takes 1. N=1. Opponent: 1+1=2.
                // N=1 (odd): Chanek takes 1. N=0. Chanek: 2+1=3.
                // Result: Chanek: 3, Opponent: 2. This contradicts example (Chanek 2).

                // The example output implies a different strategy.
                // For N=5: Chanek takes 1. N=4. Opponent takes 2. N=2. Chanek takes 1. N=1. Opponent takes 1.
                // Chanek: 1+1=2. Opponent: 2+1=3.
                // This implies:
                // Chanek (N=5, odd): takes 1. N=4.
                // Opponent (N=4, even): takes N/2=2. N=2.
                // Chanek (N=2, even): takes 1. N=1.
                // Opponent (N=1, odd): takes 1. N=0.
                // This strategy for N=2 (take 1 instead of N/2) is crucial.

                // Let's analyze N=2.
                // If player takes 1: N=1. Next player takes 1. Current player: 1, Next player: 1.
                // If player takes N/2 (1): N=1. Next player takes 1. Current player: 1, Next player: 1.
                // Both moves yield 1 coin for the current player. So taking 1 is fine.

                // What if N is even, and N/2 is even (N=4k)?
                // Current player's turn, N=4k.
                // Option 1: Take 1. N becomes 4k-1 (odd). Opponent takes 1. N becomes 4k-2.
                // Option 2: Take N/2 (2k). N becomes 2k.
                // The opponent will also play optimally.
                // If N is a power of 2, say N = 2^k.
                // If k=1, N=2. Take 1.
                // If k=2, N=4. Take 2.
                // If k=3, N=8. Take 4.
                // It seems for N=2^k, the current player always takes N/2.
                // This is because taking N/2 leaves 2^(k-1) for the opponent, who will also take half.
                // This results in a sequence of N/2, N/4, N/8, ... coins for the players.
                // Player 1 gets N/2 + N/8 + N/32 + ...
                // Player 2 gets N/4 + N/16 + N/64 + ...
                // Total for P1: N * (1/2 + 1/8 + 1/32 + ...) = N * ( (1/2) / (1 - 1/4) ) = N * ( (1/2) / (3/4) ) = N * (2/3)
                // Total for P2: N * (1/4 + 1/16 + 1/64 + ...) = N * ( (1/4) / (1 - 1/4) ) = N * ( (1/4) / (3/4) ) = N * (1/3)
                // This is for N being a power of 2.

                // What if N is even but not a power of 2? N = 2^k * M, where M is odd and M > 1.
                // Example N=6. k=1, M=3.
                // Chanek (N=6):
                //   Option 1: Take 1. N=5. Chanek gets 1.
                //     Opponent (N=5): takes 1. N=4. Opponent gets 1.
                //       Chanek (N=4): takes 2. N=2. Chanek gets 2.
                //         Opponent (N=2): takes 1. N=1. Opponent gets 1.
                //           Chanek (N=1): takes 1. N=0. Chanek gets 1.
                //     Total Chanek: 1+2+1=4. Total Opponent: 1+1=2.
                //   Option 2: Take N/2 (3). N=3. Chanek gets 3.
                //     Opponent (N=3): takes 1. N=2. Opponent gets 1.
                //       Chanek (N=2): takes 1. N=1. Chanek gets 1.
                //         Opponent (N=1): takes 1. N=0. Opponent gets 1.
                //     Total Chanek: 3+1=4. Total Opponent: 1+1=2.
                // In this case (N=6), both options yield 4 for Chanek. The example output says 4.
                // This implies that for N=6, taking N/2 is a valid optimal move.

                // The strategy seems to be:
                // If N is odd: take 1.
                // If N is even:
                //   If N is a power of 2: take N/2.
                //   If N is even but not a power of 2: take N/2.
                // This simplifies to: if N is even, take N/2.
                // This is the greedy strategy. Let's re-test it.

                // N=5: Chanek takes 1. N=4. Chanek: 1.
                // N=4: Opponent takes 2. N=2. Opponent: 2.
                // N=2: Chanek takes 1. N=1. Chanek: 1+1=2.
                // N=1: Opponent takes 1. N=0. Opponent: 2+1=3.
                // Result: Chanek: 2, Opponent: 3. This matches example for N=5.

                // N=6: Chanek takes 3. N=3. Chanek: 3.
                // N=3: Opponent takes 1. N=2. Opponent: 1.
                // N=2: Chanek takes 1. N=1. Chanek: 3+1=4.
                // N=1: Opponent takes 1. N=0. Opponent: 1+1=2.
                // Result: Chanek: 4, Opponent: 2. This matches example for N=6.

                // So the strategy is:
                // If N is odd, take 1.
                // If N is even, take N/2.
                // This is a simple greedy strategy. Let's verify why it works.
                // When it's your turn and N is odd, you must take 1.
                // When it's your turn and N is even:
                //   You can take 1 or N/2.
                //   If you take N/2, you get N/2 coins. The opponent faces N/2.
                //   If you take 1, you get 1 coin. The opponent faces N-1 (odd).
                //   The opponent will then take 1, leaving N-2.
                //   Consider the total coins you can get.
                //   If N is even, and N/2 is odd (e.g., N=6, N=10, N=14, ...):
                //     Take N/2. You get N/2. Opponent faces N/2 (odd). Opponent takes 1.
                //     You get N/2. Opponent gets 1. Remaining N/2 - 1.
                //     This is clearly better than taking 1, getting 1, and opponent faces N-1 (odd), opponent takes 1.
                //   If N is even, and N/2 is also even (e.g., N=4, N=8, N=12, ...):
                //     Take N/2. You get N/2. Opponent faces N/2 (even).
                //     Take 1. You get 1. Opponent faces N-1 (odd). Opponent takes 1.
                //     This is the tricky part.
                //     Let's say N = 2^k * M, where M is odd.
                //     If M=1, N is a power of 2. N=2^k.
                //       Take N/2. You get 2^(k-1). Opponent faces 2^(k-1).
                //       This leads to the 2/3, 1/3 split.
                //     If M>1, N is even but not a power of 2.
                //       Take N/2. You get 2^(k-1)*M. Opponent faces 2^(k-1)*M.
                //       Take 1. You get 1. Opponent faces 2^k*M - 1 (odd). Opponent takes 1.
                //       You get 1. Opponent gets 1. Remaining 2^k*M - 2.
                //       The greedy strategy of taking N/2 seems to be optimal.
                //       It maximizes the current gain and passes a smaller number to the opponent.
                //       The only time it might not be optimal is if taking 1 sets up a sequence of moves
                //       where the opponent is forced to take 1s, while taking N/2 allows the opponent to take N/2s.
                //       However, the opponent also plays optimally.
                //       The problem is essentially about splitting N coins.
                //       If N is odd, you take 1. N becomes even.
                //       If N is even, you take N/2. N becomes N/2.
                //       This strategy is simple and matches the examples.

                // Let's implement this simple greedy strategy.
                // If N is odd, take 1.
                // If N is even, take N/2.

                long long coins_to_take;
                if (N % 2 != 0) { // N is odd
                    coins_to_take = 1;
                } else { // N is even
                    // If N is even, we have two choices: take 1 or take N/2.
                    // The optimal strategy is to take N/2 if N/2 is odd.
                    // If N/2 is even, then taking 1 might be better.
                    // This is the case where N = 4k.
                    // If N = 2, N/2 = 1 (odd). Take 1.
                    // If N = 4, N/2 = 2 (even). Take 1.
                    // If N = 8, N/2 = 4 (even). Take 1.
                    // This is the strategy that matches the example.
                    // If N is even:
                    //   If N/2 is odd (N = 2 * odd_number), take N/2.
                    //   If N/2 is even (N = 4 * any_number), take 1.
                    // This is equivalent to:
                    // If N is even and N % 4 == 2 (N = 2, 6, 10, ...), take N/2.
                    // If N is even and N % 4 == 0 (N = 4, 8, 12, ...), take 1.
                    // This is the strategy that matches the example.

                    // Let's re-verify N=5 with this strategy:
                    // Chanek (N=5, odd): takes 1. N=4. Chanek: 1.
                    // Opponent (N=4, even, N%4==0): takes 1. N=3. Opponent: 1.
                    // Chanek (N=3, odd): takes 1. N=2. Chanek: 1+1=2.
                    // Opponent (N=2, even, N%4==2): takes N/2=1. N=1. Opponent: 1+1=2.
                    // Chanek (N=1, odd): takes 1. N=0. Chanek: 2+1=3.
                    // Result: Chanek: 3, Opponent: 2. Still not matching example (Chanek 2).

                    // The example output for N=5 (Chanek 2, Opponent 3) implies:
                    // Chanek (N=5, odd): takes 1. N=4. Chanek: 1.
                    // Opponent (N=4, even): takes N/2=2. N=2. Opponent: 2.
                    // Chanek (N=2, even): takes 1. N=1. Chanek: 1+1=2.
                    // Opponent (N=1, odd): takes 1. N=0. Opponent: 2+1=3.
                    // This means for N=4, the opponent took N/2.
                    // For N=2, Chanek took 1.
                    // This implies a strategy:
                    // If N is odd, take 1.
                    // If N is even:
                    //   If N is a power of 2, take N/2.
                    //   If N is even but not a power of 2, take N/2.
                    // This simplifies to: if N is even, take N/2.
                    // This is the simple greedy strategy.
                    // Let's re-run the simple greedy strategy for N=5 and N=6.

                    // N=5:
                    // Chanek (N=5, odd): takes 1. N=4. Chanek: 1.
                    // Opponent (N=4, even): takes N/2=2. N=2. Opponent: 2.
                    // Chanek (N=2, even): takes N/2=1. N=1. Chanek: 1+1=2.
                    // Opponent (N=1, odd): takes 1. N=0. Opponent: 2+1=3.
                    // Result: Chanek: 2, Opponent: 3. This matches example for N=5.

                    // N=6:
                    // Chanek (N=6, even): takes N/2=3. N=3. Chanek: 3.
                    // Opponent (N=3, odd): takes 1. N=2. Opponent: 1.
                    // Chanek (N=2, even): takes N/2=1. N=1. Chanek: 3+1=4.
                    // Opponent (N=1, odd): takes 1. N=0. Opponent: 1+1=2.
                    // Result: Chanek: 4, Opponent: 2. This matches example for N=6.

                    // So the simple greedy strategy is:
                    // If N is odd, take 1.
                    // If N is even, take N/2.
                    // This strategy seems to be correct.

                    coins_to_take = N / 2;
                }

                if (chanek_turn) {
                    chanek_coins += coins_to_take;
                } else {
                    opponent_coins += coins_to_take;
                }
                N -= coins_to_take;
            }
            chanek_turn = !chanek_turn;
        }
        std::cout << chanek_coins << "\n";
    }
    return 0;
}

#include <iostream>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    long long a, b;
    std::cin >> a >> b;
    long long MOD = 1000000007;

    // Calculate sum_{r=1 to b-1} r
    // This is (b-1) * b / 2
    // We need to handle division by 2 with modulo.
    // (b-1) * b is always even, so (b-1) * b / 2 is an integer.
    // We can multiply by modular inverse of 2, which is (MOD + 1) / 2.
    // For MOD = 10^9 + 7, (10^9 + 7 + 1) / 2 = 10^9 + 8 / 2 = 500000004.
    long long sum_r_term = (b - 1);
    sum_r_term = (sum_r_term * b) % MOD;
    sum_r_term = (sum_r_term * 500000004) % MOD; // Modular inverse of 2

    // Calculate sum_{k=1 to a} (k * b + 1)
    // This is sum_{k=1 to a} (k * b) + sum_{k=1 to a} 1
    // = b * sum_{k=1 to a} k + a
    // = b * (a * (a + 1) / 2) + a
    long long sum_k_term_part1 = (a * (a + 1)) % MOD;
    sum_k_term_part1 = (sum_k_term_part1 * 500000004) % MOD; // Modular inverse of 2
    sum_k_term_part1 = (sum_k_term_part1 * b) % MOD;

    long long sum_k_term_part2 = a % MOD;

    long long sum_k_term = (sum_k_term_part1 + sum_k_term_part2) % MOD;

    // Total sum is (sum_{k=1 to a} (k * b + 1)) * (sum_{r=1 to b-1} r)
    long long total_sum = (sum_k_term * sum_r_term) % MOD;

    std::cout << total_sum << std::endl;

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <set>
#include <algorithm>
#include <map>

void solve() {
    std::string s;
    std::cin >> s;

    std::map<char, std::set<char>> adj;
    for (char c = 'a'; c <= 'z'; ++c) {
        adj[c] = std::set<char>();
    }

    for (size_t i = 0; i < s.length() - 1; ++i) {
        adj[s[i]].insert(s[i+1]);
        adj[s[i+1]].insert(s[i]);
    }

    char start_char = '\0';
    for (char c = 'a'; c <= 'z'; ++c) {
        if (adj[c].size() > 2) {
            std::cout << "NO\n";
            return;
        }
        if (adj[c].size() == 1) {
            start_char = c;
        }
    }

    std::string layout = "";
    std::set<char> visited;

    if (s.length() == 1) {
        start_char = s[0];
    } else if (start_char == '\0') { // All characters in s have degree 2, implies a cycle or a single path that uses all chars
        // If all chars in s have degree 2, it means they form a cycle or a path where endpoints are not in s.
        // Since we need to form a linear layout, we must pick one character from s to be an endpoint.
        // Any character from s can be chosen as a starting point.
        // Let's pick the first character of s.
        start_char = s[0];
    }

    if (start_char != '\0') {
        char current = start_char;
        while (current != '\0') {
            layout += current;
            visited.insert(current);
            char next_char = '\0';
            for (char neighbor : adj[current]) {
                if (visited.find(neighbor) == visited.end()) {
                    next_char = neighbor;
                    break;
                }
            }
            current = next_char;
        }
    }

    // Check if all characters from s are included in the layout and form a valid path
    for (char c : s) {
        if (visited.find(c) == visited.end()) {
            std::cout << "NO\n";
            return;
        }
    }

    // Add remaining unvisited characters
    for (char c = 'a'; c <= 'z'; ++c) {
        if (visited.find(c) == visited.end()) {
            layout += c;
        }
    }

    std::cout << "YES\n";
    std::cout << layout << "\n";
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

