#include <iostream>
#include <vector>
#include <string>
#include <numeric>
#include <algorithm>
#include <iomanip>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;
    int L = s.length();

    // Precompute character occurrences for each character 'a' through 'z'
    // char_indices[c - 'a'] will store a vector of indices where character c appears in s
    std::vector<std::vector<int>> char_indices(26);
    for (int i = 0; i < L; ++i) {
        char_indices[s[i] - 'a'].push_back(i);
    }

    double total_expected_wins = 0.0;

    // Iterate over all possible first characters t[0]
    // This is equivalent to iterating over all possible initial shifts k_actual
    // and considering s[k_actual] as t[0].
    // Since k_actual is chosen uniformly at random, each k_actual has probability 1/L.
    for (int k_actual = 0; k_actual < L; ++k_actual) {
        char c0 = s[k_actual]; // The first character Vasya learns

        // Find all possible k' values such that s[k'] == c0
        // These are the candidate shifts after learning t[0]
        const std::vector<int>& possible_k_after_c0 = char_indices[c0 - 'a'];

        // If there's only one possible k, Vasya wins immediately for this k_actual.
        if (possible_k_after_c0.size() == 1) {
            total_expected_wins += 1.0;
            continue;
        }

        // Vasya needs to choose an optimal j (from 1 to L-1)
        double max_wins_for_this_k_actual = 0.0;

        // Iterate over all possible choices for j (the second position Vasya asks for)
        for (int j = 1; j < L; ++j) {
            // For a fixed k_actual and chosen j, what is t[j]?
            char cj = s[(k_actual + j) % L];

            // Count how many candidate k' values (from possible_k_after_c0)
            // would produce the same (c0, cj) pair.
            // A candidate k' is valid if s[k'] == c0 AND s[(k' + j) % L] == cj.
            // We are looking for k' such that s[k'] == c0 and s[(k'+j)%L] == s[(k_actual+j)%L].

            int count_matching_k_prime = 0;
            for (int k_prime : possible_k_after_c0) {
                if (s[(k_prime + j) % L] == cj) {
                    count_matching_k_prime++;
                }
            }

            // If only one k' matches (c0, cj), Vasya wins for this (k_actual, j) pair.
            // The probability of winning for this specific (k_actual, j) is 1.0 if count_matching_k_prime == 1, else 0.0.
            if (count_matching_k_prime == 1) {
                max_wins_for_this_k_actual = std::max(max_wins_for_this_k_actual, 1.0);
            }
        }
        total_expected_wins += max_wins_for_this_k_actual;
    }

    // The overall probability is the sum of probabilities for each k_actual,
    // divided by L (since each k_actual has 1/L probability).
    double final_probability = total_expected_wins / L;

    std::cout << std::fixed << std::setprecision(15) << final_probability << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <map>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(2 * n);
    int initial_diff = 0; // S - B
    for (int i = 0; i < 2 * n; ++i) {
        std::cin >> a[i];
        if (a[i] == 1) {
            initial_diff++;
        } else {
            initial_diff--;
        }
    }

    // Map to store the first index (from right) where a certain balance is achieved
    // For right side, balance is (S-B) from right to left.
    // Key: balance (S-B), Value: index (from right, 0-indexed)
    // Example: if balance 3 is achieved at index 2n-1-k, then map[3] = k
    std::map<int, int> right_balance_idx;
    right_balance_idx[0] = 0; // No jars removed from right, balance 0, 0 jars removed

    int current_balance_right = 0; // S - B for suffix
    for (int k = 0; k < n; ++k) { // k is number of jars removed from right (0 to n-1)
        int jar_idx = 2 * n - 1 - k; // Current jar being considered (from right)
        if (a[jar_idx] == 1) {
            current_balance_right++;
        } else {
            current_balance_right--;
        }
        if (right_balance_idx.find(current_balance_right) == right_balance_idx.end()) {
            right_balance_idx[current_balance_right] = k + 1;
        }
    }

    int min_removed = 2 * n; // Initialize with max possible

    // Case 0: No jars removed from left
    // We need the remaining jars to have S-B = 0.
    // The initial total S-B is `initial_diff`.
    // If we remove `k_R` jars from the right, their S-B sum is `current_balance_right`.
    // The remaining jars will have S-B = `initial_diff` - `current_balance_right`.
    // We want this to be 0, so `current_balance_right` must be equal to `initial_diff`.
    if (right_balance_idx.count(initial_diff)) {
        min_removed = std::min(min_removed, right_balance_idx[initial_diff]);
    }

    // Iterate through removing `k_L` jars from left (0 to n-1)
    int current_balance_left = 0; // S - B for prefix
    for (int k_L = 0; k_L < n; ++k_L) { // k_L is number of jars removed from left
        int jar_idx = k_L; // Current jar being considered (from left)
        if (a[jar_idx] == 1) {
            current_balance_left++;
        } else {
            current_balance_left--;
        }

        // We have removed `k_L + 1` jars from the left.
        // Their S-B sum is `current_balance_left`.
        // The remaining jars (excluding these `k_L+1` jars) have S-B = `initial_diff` - `current_balance_left`.
        // Let this target balance for the right-removed jars be `target_balance_right`.
        int target_balance_right = initial_diff - current_balance_left;

        if (right_balance_idx.count(target_balance_right)) {
            int k_R = right_balance_idx[target_balance_right];
            min_removed = std::min(min_removed, (k_L + 1) + k_R);
        }
    }

    std::cout << min_removed << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
