void solve() {
    std::string s;
    std::cin >> s;
    int n = s.length();
    long long good_substrings_count = 0;

    for (int i = 0; i < n; ++i) {
        // Case 1: Substrings starting with '0'
        // If s[i] is '0', then f(s[i...r]) can only be 0.
        // So, we need r - i + 1 = 0, which is impossible since length >= 1.
        // However, the problem statement example f(000) = 0.
        // If f(s_l...s_r) = 0, then all characters must be '0'.
        // In this case, r - l + 1 = 0, which is impossible.
        // This implies that a substring of all '0's cannot be good.
        // Example: s = "000", f("000") = 0. Length = 3. 3 != 0.
        // So, if s[i] is '0', we can skip it as a starting point for a good substring.
        // This is incorrect based on the example f(000) = 0.
        // The example "00001000" has 4 good substrings.
        // "0001000" has 3 good substrings.
        // Let's re-read: "f(000) = 0".
        // If s_l...s_r = "000", length is 3. f("000") = 0. 3 != 0. Not good.
        // This means a substring of all '0's can never be good.
        // So, if s[i] is '0', it cannot be the start of a good substring unless it's a leading zero
        // for a value > 0.
        // The condition is r - l + 1 = f(s_l...s_r).
        // If s[i] = '0', then f(s[i...r]) will be the value of s[i+1...r].
        // This is the key. The problem states "f(011) = 3", "f(00101) = 5".
        // This means leading zeros are part of the string whose value is computed.
        // So, f("011") means the binary string "011" has value 3. Length is 3. 3 == 3. Good.
        // f("00101") means the binary string "00101" has value 5. Length is 5. 5 == 5. Good.
        // f("000") means the binary string "000" has value 0. Length is 3. 3 != 0. Not good.
        // So, my initial interpretation was correct.
        // A substring $s_l \dots s_r$ is good if $r - l + 1 = \text{value}(s_l \dots s_r)$.

        // Iterate through all possible starting positions i
        // For each i, iterate through possible ending positions j
        // Calculate value and length.
        long long current_val = 0;
        for (int j = i; j < n; ++j) {
            int len = j - i + 1;

            // If current_val exceeds a certain threshold, it's impossible for len to catch up.
            // Max possible len is n (2e5).
            // If current_val > n, then it can't be equal to len.
            // Also, if current_val is already large, adding more bits will make it even larger.
            // The maximum value for len is N (2e5).
            // log2(2e5) is approx 17.6. So, a binary string of length 18 can already exceed 2e5.
            // If len > 18, and the first bit is '1', then current_val >= 2^(len-1).
            // If len = 18, current_val can be up to 2^18 - 1 = 262143.
            // If len = 19, current_val can be up to 2^19 - 1 = 524287.
            // So, if len > 18, current_val will be much larger than len.
            // We can cap the inner loop when len becomes too large or current_val becomes too large.
            // A safe upper bound for len to check is around 20.
            // If len > 20, and s[i] is '1', then current_val >= 2^(len-1) which is much larger than len.
            // If s[i] is '0', then current_val is calculated from s[i+1...j].
            // The maximum length of s is 2e5.
            // If len > 20, then current_val will be at least 2^(len-1) if s[i] is '1'.
            // If s[i] is '0', then current_val is calculated from s[i+1...j].
            // The maximum value of len is N.
            // If current_val > N, we can break.
            // If len > 20, and s[i] is '1', then current_val will be at least 2^19, which is > N.
            // So, we only need to check substrings of length up to ~20-21.
            // Let's use a slightly larger bound, say 22, to be safe.
            // 2^21 is about 2 million.
            // If len > 22, and s[i] is '1', then current_val >= 2^(len-1) >= 2^21, which is much larger than N.
            // So, we can break if len > 22.
            // This means the inner loop runs at most 22 times.
            // Total complexity: N * 22. This is efficient enough.

            if (s[j] == '1') {
                if (current_val > (2LL * n)) { // Optimization: if current_val is already too large, it won't match len
                    // This check is important. If current_val is already large, multiplying by 2
                    // and adding 1 might overflow long long if not careful, but more importantly,
                    // it will definitely be larger than any possible length N.
                    // Max N is 2e5. Max current_val can be 2^62.
                    // If current_val > N, it's impossible for current_val == len.
                    // We can break early.
                    break;
                }
                current_val = current_val * 2 + 1;
            } else { // s[j] == '0'
                if (current_val > (2LL * n)) { // Same optimization
                    break;
                }
                current_val = current_val * 2;
            }

            if (current_val == len) {
                good_substrings_count++;
            }
        }
    }

    std::cout << good_substrings_count << std::endl;
}

