#include <iostream>
#include <vector>
#include <string>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    // For each bit position (0 to 9), track how 0 and 1 transform.
    // initial_val_0[bit_idx] stores the final value of bit_idx if it started as 0.
    // initial_val_1[bit_idx] stores the final value of bit_idx if it started as 1.
    std::vector<int> initial_val_0(10); // All bits start as 0
    std::vector<int> initial_val_1(10); // All bits start as 1

    for (int i = 0; i < 10; ++i) {
        initial_val_0[i] = 0;
        initial_val_1[i] = 1;
    }

    for (int i = 0; i < n; ++i) {
        char op_char;
        int x;
        std::cin >> op_char >> x;

        for (int bit_idx = 0; bit_idx < 10; ++bit_idx) {
            int bit_x = (x >> bit_idx) & 1;

            if (op_char == '&') {
                initial_val_0[bit_idx] &= bit_x;
                initial_val_1[bit_idx] &= bit_x;
            } else if (op_char == '|') {
                initial_val_0[bit_idx] |= bit_x;
                initial_val_1[bit_idx] |= bit_x;
            } else if (op_char == '^') {
                initial_val_0[bit_idx] ^= bit_x;
                initial_val_1[bit_idx] ^= bit_x;
            }
        }
    }

    // Now, we have the final transformation for each bit.
    // We need to find A, B, C such that:
    // (input & A | B) ^ C = final_value
    // This is equivalent to:
    // (input_bit & A_bit | B_bit) ^ C_bit = final_bit_value

    // Let's determine A_bit, B_bit, C_bit for each bit_idx.
    // We know:
    // (0 & A_bit | B_bit) ^ C_bit = initial_val_0[bit_idx]
    // (1 & A_bit | B_bit) ^ C_bit = initial_val_1[bit_idx]

    // Case 1: A_bit = 0
    // (0 & 0 | B_bit) ^ C_bit = B_bit ^ C_bit = initial_val_0[bit_idx]
    // (1 & 0 | B_bit) ^ C_bit = B_bit ^ C_bit = initial_val_1[bit_idx]
    // This implies initial_val_0[bit_idx] must be equal to initial_val_1[bit_idx].
    // If they are equal, then B_bit ^ C_bit = initial_val_0[bit_idx].
    // We can choose B_bit = 0, then C_bit = initial_val_0[bit_idx].
    // Or choose B_bit = 1, then C_bit = 1 ^ initial_val_0[bit_idx].
    // Let's try A_bit = 0, B_bit = 0, C_bit = initial_val_0[bit_idx].
    // This means the bit is always C_bit, regardless of input.
    // This is equivalent to (input_bit & 0 | C_bit) ^ 0 = C_bit.
    // Or (input_bit & 0 | 0) ^ C_bit = C_bit.

    // Case 2: A_bit = 1
    // (0 & 1 | B_bit) ^ C_bit = B_bit ^ C_bit = initial_val_0[bit_idx]
    // (1 & 1 | B_bit) ^ C_bit = (1 | B_bit) ^ C_bit = 1 ^ C_bit = initial_val_1[bit_idx]
    // From the second equation, C_bit = 1 ^ initial_val_1[bit_idx].
    // Substitute C_bit into the first equation: B_bit ^ (1 ^ initial_val_1[bit_idx]) = initial_val_0[bit_idx].
    // B_bit = initial_val_0[bit_idx] ^ 1 ^ initial_val_1[bit_idx].
    // So, A_bit=1, B_bit=initial_val_0[bit_idx] ^ 1 ^ initial_val_1[bit_idx], C_bit=1 ^ initial_val_1[bit_idx].

    // Let's try to construct the three constants for AND, OR, XOR.
    // We want to find `and_const`, `or_const`, `xor_const`.
    // The final program will be: `& and_const`, `| or_const`, `^ xor_const`.
    // The order matters. Let's assume this order.
    // (x & and_const | or_const) ^ xor_const

    int final_and_const = 0; // All bits 1 initially, then ANDed down
    int final_or_const = 0;  // All bits 0 initially, then ORed up
    int final_xor_const = 0; // All bits 0 initially, then XORed

    for (int bit_idx = 0; bit_idx < 10; ++bit_idx) {
        int val0 = initial_val_0[bit_idx];
        int val1 = initial_val_1[bit_idx];

        if (val0 == 0 && val1 == 0) {
            // Input bit 0 -> 0, Input bit 1 -> 0
            // This means the output bit is always 0.
            // (x_bit & 0 | 0) ^ 0 = 0
            // So, for this bit: and_const_bit = 0, or_const_bit = 0, xor_const_bit = 0
            // This means we need to force the bit to 0.
            // (x_bit & 0) will make it 0.
            // So, final_and_const's bit_idx should be 0.
            // final_or_const's bit_idx should be 0.
            // final_xor_const's bit_idx should be 0.
            // (x_bit & 0 | 0) ^ 0 = 0
            final_and_const &= ~(1 << bit_idx); // Set bit to 0
            final_or_const &= ~(1 << bit_idx);  // Set bit to 0
            final_xor_const &= ~(1 << bit_idx); // Set bit to 0
        } else if (val0 == 0 && val1 == 1) {
            // Input bit 0 -> 0, Input bit 1 -> 1
            // This means the output bit is the same as the input bit.
            // (x_bit & 1 | 0) ^ 0 = x_bit
            // So, for this bit: and_const_bit = 1, or_const_bit = 0, xor_const_bit = 0
            final_and_const |= (1 << bit_idx); // Set bit to 1
            final_or_const &= ~(1 << bit_idx);  // Set bit to 0
            final_xor_const &= ~(1 << bit_idx); // Set bit to 0
        } else if (val0 == 1 && val1 == 0) {
            // Input bit 0 -> 1, Input bit 1 -> 0
            // This means the output bit is the inverse of the input bit.
            // (x_bit & 1 | 0) ^ 1 = ~x_bit
            // So, for this bit: and_const_bit = 1, or_const_bit = 0, xor_const_bit = 1
            final_and_const |= (1 << bit_idx); // Set bit to 1
            final_or_const &= ~(1 << bit_idx);  // Set bit to 0
            final_xor_const |= (1 << bit_idx); // Set bit to 1
        } else if (val0 == 1 && val1 == 1) {
            // Input bit 0 -> 1, Input bit 1 -> 1
            // This means the output bit is always 1.
            // (x_bit & 0 | 1) ^ 0 = 1
            // So, for this bit: and_const_bit = 0, or_const_bit = 1, xor_const_bit = 0
            final_and_const &= ~(1 << bit_idx); // Set bit to 0
            final_or_const |= (1 << bit_idx);  // Set bit to 1
            final_xor_const &= ~(1 << bit_idx); // Set bit to 0
        }
    }

    std::vector<std::pair<char, int>> result_ops;
    if (final_and_const != 1023) { // If not all bits are 1, then & operation is needed
        result_ops.push_back({'&', final_and_const});
    }
    if (final_or_const != 0) { // If not all bits are 0, then | operation is needed
        result_ops.push_back({'|', final_or_const});
    }
    if (final_xor_const != 0) { // If not all bits are 0, then ^ operation is needed
        result_ops.push_back({'^', final_xor_const});
    }

    std::cout << result_ops.size() << "\n";
    for (const auto& op : result_ops) {
        std::cout << op.first << " " << op.second << "\n";
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>

// Using long long for y and intermediate sums to prevent overflow
// a_i can be up to 10^9, n up to 2*10^5.
// y can grow large. Max path length is N. Each step adds up to 2*10^9.
// So y can be up to 2*10^5 * 2*10^9 = 4*10^14, which fits in long long.

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<long long> a(n + 1); // a[0] is unused, a[1] will be set for each query
    for (int i = 2; i <= n; ++i) {
        std::cin >> a[i];
    }

    // dp_x[i] stores the final x position if starting at i and taking one pair of steps (x+a[x], y+a[x], then x-a[new_x], y+a[new_x])
    // dp_y[i] stores the total y added if starting at i and taking one pair of steps
    // dp_next_x[i] stores the x position after the first step (x+a[x])
    // dp_next_y[i] stores the y value after the first step (y+a[x])
    // dp_next_x and dp_next_y are used to handle the case where the program terminates after the first step.
    std::vector<long long> dp_x(n + 1);
    std::vector<long long> dp_y(n + 1);
    std::vector<long long> dp_next_x(n + 1);
    std::vector<long long> dp_next_y(n + 1);

    // Iterate backwards from n to 1 to fill DP table
    for (int i = n; i >= 1; --i) {
        long long current_a_val = a[i];

        // Step 2: x becomes x + a[x], y becomes y + a[x]
        long long x_after_step2 = i + current_a_val;
        long long y_added_step2 = current_a_val;

        dp_next_x[i] = x_after_step2;
        dp_next_y[i] = y_added_step2;

        // Check termination after step 2
        if (x_after_step2 <= 0 || x_after_step2 > n) {
            dp_x[i] = x_after_step2;
            dp_y[i] = y_added_step2;
        } else {
            // Step 3: y becomes y + a[x_after_step2], x becomes x_after_step2 - a[x_after_step2]
            long long val_at_new_x = a[x_after_step2];
            long long x_after_step3 = x_after_step2 - val_at_new_x;
            long long y_added_step3 = val_at_new_x;

            // Check termination after step 3
            if (x_after_step3 <= 0 || x_after_step3 > n) {
                dp_x[i] = x_after_step3;
                dp_y[i] = y_added_step2 + y_added_step3;
            } else {
                // If it doesn't terminate, it moves to x_after_step3.
                // We can use the precomputed DP values for x_after_step3.
                // The total y added is y_added_step2 + y_added_step3 + dp_y[x_after_step3]
                // The final x is dp_x[x_after_step3]
                dp_x[i] = dp_x[x_after_step3];
                dp_y[i] = y_added_step2 + y_added_step3 + dp_y[x_after_step3];
            }
        }
    }

    // For each starting value i (1 to n-1)
    for (int i = 1; i < n; ++i) {
        a[1] = i; // Set a[1] for the current run

        // Initial state: x=1, y=0
        // First, apply step 2: x becomes 1 + a[1], y becomes 0 + a[1]
        long long current_x = 1 + a[1];
        long long current_y = a[1];

        // Check termination after the first step 2
        if (current_x <= 0 || current_x > n) {
            std::cout << current_y << "\n";
        } else {
            // If not terminated, apply step 3: y becomes y + a[current_x], x becomes current_x - a[current_x]
            long long val_at_current_x = a[current_x];
            current_x = current_x - val_at_current_x;
            current_y = current_y + val_at_current_x;

            // Check termination after the first step 3
            if (current_x <= 0 || current_x > n) {
                std::cout << current_y << "\n";
            } else {
                // If not terminated, it means it completed one full (step 2, step 3) cycle.
                // Now we can use the precomputed DP values for current_x.
                // The total y is current_y + dp_y[current_x]
                // The final x is dp_x[current_x]
                // If dp_x[current_x] indicates non-termination (0 or >n), then it terminates.
                // If dp_x[current_x] is within bounds, it means it never terminates.
                if (dp_x[current_x] <= 0 || dp_x[current_x] > n) {
                    std::cout << current_y + dp_y[current_x] << "\n";
                } else {
                    std::cout << -1 << "\n";
                }
            }
        }
    }

    return 0;
}

#include <iostream>
#include <algorithm> // For std::max and std::min

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        long long n, m, k;
        std::cin >> n >> m >> k;

        // Ensure n >= m by swapping if necessary.
        // This simplifies calculations as we can always assume n is the larger absolute coordinate.
        if (n < m) {
            std::swap(n, m);
        }

        // Case 1: Parity check.
        // The parity of (n + m) must be the same as the parity of k.
        // Each move changes the parity of (x+y) by 0 or 2 (diagonal) or 1 (axial).
        // (x_new + y_new) = (x_old +/- 1 + y_old +/- 1) = (x_old + y_old) +/- 2 or 0 (diagonal)
        // (x_new + y_new) = (x_old +/- 1 + y_old) = (x_old + y_old) +/- 1 (axial)
        // (x_new + y_new) = (x_old + y_old +/- 1) = (x_old + y_old) +/- 1 (axial)
        // So, (x_new + y_new) % 2 = (x_old + y_old) % 2 for diagonal moves.
        // And (x_new + y_new) % 2 != (x_old + y_old) % 2 for axial moves.
        // Starting at (0,0), (0+0)%2 = 0.
        // After k moves, the parity of (n+m) must be (0 + A) % 2, where A is number of axial moves.
        // This is equivalent to (n+m)%2 == k%2.
        if ((n % 2) != (k % 2)) { // (n+m)%2 == k%2 is equivalent to n%2 == k%2 if m%2 == 0, or n%2 != k%2 if m%2 == 1.
                                  // A simpler way: (n % 2) != (k % 2) is the condition for impossibility if m is even.
                                  // If m is odd, then (n % 2) != (k % 2) means (n+1)%2 != k%2.
                                  // Let's use the (n+m)%2 == k%2 directly.
            if (((n + m) % 2) != (k % 2)) {
                std::cout << -1 << "\n";
                continue;
            }
        }

        // Case 2: Not enough moves.
        // The minimum number of moves to reach (n, m) is max(n, m).
        // This is achieved by making min(n, m) diagonal moves and then (max(n, m) - min(n, m)) axial moves.
        if (k < n) { // Since n >= m, this is equivalent to k < max(n, m)
            std::cout << -1 << "\n";
            continue;
        }

        // If we pass the above checks, it's always possible to reach (n, m) in k moves.
        // We want to maximize diagonal moves.
        // Let D be diagonal moves, A be axial moves. k = D + A.
        // We want to maximize D.
        // The maximum number of diagonal moves is k.
        // However, we need to ensure the final position is (n, m).
        // Consider the parity of coordinates.
        // Each diagonal move changes both x and y parity.
        // Each axial move changes one coordinate's parity.
        // From (0,0) to (n,m):
        // x-coordinate changes parity D_x + A_x times.
        // y-coordinate changes parity D_y + A_y times.
        // For diagonal moves, D_x = D_y = D.
        // For axial moves, A_x is number of moves changing x, A_y is number of moves changing y.
        // A_x + A_y = A.
        // (n % 2) = (D % 2 + A_x % 2) % 2
        // (m % 2) = (D % 2 + A_y % 2) % 2
        //
        // A simpler approach:
        // We can make n diagonal moves to reach (n, n) (assuming n >= m).
        // This uses n moves. Remaining moves: k - n.
        // Current position: (n, n). Target: (n, m).
        // We need to change y-coordinate from n to m. This requires |n-m| changes.
        // We have k - n moves left.
        // Each pair of moves (e.g., (x,y) -> (x,y+1) -> (x,y)) can be used to "waste" moves
        // while keeping the parity of coordinates the same.
        //
        // The maximum number of diagonal moves is k.
        // However, we must reach (n, m).
        // The minimum number of axial moves required is (n - m).
        // This is because we need to cover the difference in coordinates.
        // We can make m diagonal moves to reach (m, m).
        // Then we need to make (n - m) axial moves along the x-axis to reach (n, m).
        // This uses m + (n - m) = n moves.
        // The remaining k - n moves must be "wasted" without changing the final position.
        // Each "wasted" move must be paired with another move that cancels its effect on the final position.
        // For example, (x,y) -> (x+1,y) -> (x,y). This uses 2 moves, changes x by 0, y by 0.
        // Or (x,y) -> (x+1,y+1) -> (x,y). This uses 2 moves, changes x by 0, y by 0.
        //
        // If k - n is even, we can use (k - n) / 2 pairs of moves like (x,y) -> (x+1,y) -> (x,y).
        // In this case, the number of diagonal moves is m.
        // The number of axial moves is (n - m) + (k - n).
        // Total moves = m + (n - m) + (k - n) = k.
        // Number of diagonal moves = m.
        //
        // If k - n is odd, we cannot simply use pairs of axial moves.
        // We need to adjust the parity of the final coordinates.
        // The condition (n % 2) == (k % 2) (since m is smaller, we can assume m is even or odd, but n is the dominant one)
        // (n+m)%2 == k%2 is the general condition.
        //
        // Let's consider the total number of moves k.
        // We want to maximize diagonal moves.
        // The maximum possible diagonal moves is k.
        // If we make k diagonal moves, we end up at a point (x,y) where x and y have the same parity as k.
        // For example, if k is even, (x,y) will be (even, even). If k is odd, (x,y) will be (odd, odd).
        //
        // The target is (n, m).
        // If n and m have the same parity, and k has the same parity as n (and m),
        // then we can make k diagonal moves.
        // Example: (2,2) in 2 moves. k=2. n=2, m=2. (2,2) -> (0,0) -> (2,2). 2 diagonal moves.
        // Example: (2,2) in 4 moves. k=4. n=2, m=2. (0,0)->(1,1)->(0,0)->(1,1)->(2,2). 4 diagonal moves.
        //
        // If n and m have different parities, it's impossible to reach (n,m) with only diagonal moves.
        // We need at least one axial move.
        //
        // The number of diagonal moves is at most k.
        // The number of diagonal moves is at most k - (n - m).
        // This is because we need at least (n - m) axial moves to cover the difference between n and m.
        // So, max_diag = k - (n - m).
        //
        // Now, consider the parity of (k - (n - m)).
        // If (k - (n - m)) is even, then we can make (k - (n - m)) diagonal moves.
        // The remaining (n - m) moves are axial.
        // Total moves = (k - (n - m)) + (n - m) = k.
        // The final position will be (n, m).
        // The number of diagonal moves is k - (n - m).
        //
        // What if (k - (n - m)) is odd?
        // This means we cannot make exactly (k - (n - m)) diagonal moves and (n - m) axial moves.
        // If (k - (n - m)) is odd, it means k and (n - m) have different parities.
        // This implies k - (n - m) - 1 is even.
        // We can make (k - (n - m) - 1) diagonal moves.
        // This leaves (n - m) + 1 moves.
        // We need to make (n - m) axial moves to cover the difference.
        // We have 1 extra move.
        // This extra move must be an axial move.
        // So, we make (n - m) + 1 axial moves.
        // Total axial moves = (n - m) + 1.
        // Total diagonal moves = k - (n - m) - 1.
        //
        // This logic is flawed. Let's restart.
        //
        // We have n, m, k. Assume n >= m.
        //
        // 1. Minimum moves: We need at least n moves to reach (n, m).
        //    If k < n, impossible. Output -1.
        //
        // 2. Parity check:
        //    Each move changes the parity of (x+y) by 1 (axial) or 0 (diagonal).
        //    Starting at (0,0), (x+y) is even.
        //    After k moves, (x+y) will have parity (k % 2) if all moves were axial.
        //    If we have D diagonal moves and A axial moves, k = D + A.
        //    The parity of (x+y) changes by A.
