            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                current_a[j] += ops[i].val;
            }
        } else { // type 2
            long long max_val = -3000000000000000000LL; // A very small number
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                max_val = std::max(max_val, current_a[j]);
            }
            if (max_val != ops[i].val) {
                possible = false;
                break;
            }
        }
    }

    if (possible) {
        std::cout << "YES\n";
        for (int i = 0; i < n; ++i) {
            std::cout << initial_a[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    } else {
        std::cout << "NO\n";
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <queue>

struct Child {
    int id;
    long long v, d, p;
    bool in_line;
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<Child> children(n);
    for (int i = 0; i < n; ++i) {
        children[i].id = i + 1;
        std::cin >> children[i].v >> children[i].d >> children[i].p;
        children[i].in_line = true;
    }

    std::vector<int> cured_children_ids;

    for (int i = 0; i < n; ++i) {
        if (!children[i].in_line) {
            continue;
        }

        cured_children_ids.push_back(children[i].id);
        children[i].in_line = false;

        long long current_v_effect = children[i].v;
        long long total_d_effect = 0; // Accumulates d_j from children who leave

        std::queue<int> crying_children_q; // Queue for children who just dropped below 0 confidence

        // Apply initial v_i effect
        for (int j = i + 1; j < n; ++j) {
            if (!children[j].in_line) {
                continue;
            }

            // Apply accumulated d_effect from previous children who left
            children[j].p -= total_d_effect;

            // Apply current_v_effect from child i
            if (current_v_effect > 0) {
                children[j].p -= current_v_effect;
                current_v_effect--; // v_i effect decreases by 1 for each subsequent child
            }

            if (children[j].p < 0) {
                crying_children_q.push(j);
            }
        }

        // Process chain reactions
        while (!crying_children_q.empty()) {
            int crying_idx = crying_children_q.front();
            crying_children_q.pop();

            if (!children[crying_idx].in_line) { // Already left due to another cry
                continue;
            }

            children[crying_idx].in_line = false;
            total_d_effect += children[crying_idx].d;

            // Apply this d_j effect to all subsequent children
            for (int k = crying_idx + 1; k < n; ++k) {
                if (!children[k].in_line) {
                    continue;
                }
                children[k].p -= children[crying_idx].d;
                if (children[k].p < 0) {
                    crying_children_q.push(k);
                }
            }
        }
    }

    std::cout << cured_children_ids.size() << "\n";
    for (size_t i = 0; i < cured_children_ids.size(); ++i) {
        std::cout << cured_children_ids[i] << (i == cured_children_ids.size() - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

