    // This means:
    // - f(elements[0], elements[i]) = elements[0].value + elements[i].value + h for i > 0
    // - f(elements[i], elements[j]) = elements[i].value + elements[j].value for i,j > 0

    // Minimum possible f value:
    // min(elements[0].value + elements[1].value + h, elements[1].value + elements[2].value)
    long long min_f_case2 = std::min(elements[0].value + elements[1].value + h, elements[1].value + elements[2].value);
    if (n == 2) { // Special case for n=2, only one pair (a_0, a_1)
        min_f_case2 = elements[0].value + elements[1].value + h;
    }

    // Maximum possible f value:
    // max(elements[0].value + elements[n-1].value + h, elements[n-2].value + elements[n-1].value)
    long long max_f_case2 = std::max(elements[0].value + elements[n-1].value + h, elements[n-2].value + elements[n-1].value);
    if (n == 2) { // Special case for n=2, only one pair (a_0, a_1)
        max_f_case2 = elements[0].value + elements[1].value + h;
    }

    long long goodness_case2 = max_f_case2 - min_f_case2;

    std::vector<int> partition_case2(n);
    partition_case2[elements[0].original_index] = 2;
    for (int i = 1; i < n; ++i) {
        partition_case2[elements[i].original_index] = 1;
    }

    if (goodness_case1 <= goodness_case2) {
        std::cout << goodness_case1 << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << partition_case1[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    } else {
        std::cout << goodness_case2 << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << partition_case2[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <cmath>

bool check(long long T, int n, int m, const std::vector<long long>& h, const std::vector<long long>& p) {
    int p_idx = 0; // Current target track index
    int h_idx = 0; // Current head index

    while (p_idx < m && h_idx < n) {
        // Find the first head h_idx that can potentially reach p_idx
        // A head h_idx can reach p_idx if h_idx is not too far to the right of p_idx
        // Specifically, h_idx - T <= p_idx
        while (h_idx < n && h[h_idx] + T < p[p_idx]) {
            h_idx++;
        }

        if (h_idx == n) { // No more heads to cover remaining tracks
            return false;
        }

        // Now, h_idx is the first head such that h[h_idx] + T >= p[p_idx].
        // This head can cover p[p_idx].
        // We want to find the maximum range this head can cover to the right,
        // and cover as many p_i as possible with this head.
        long long current_head_left_reach = h[h_idx] - T;
        long long current_head_right_reach = h[h_idx] + T;

        // If p[p_idx] is to the left of current_head_left_reach,
        // this head cannot cover p[p_idx]. This should not happen if the previous while loop is correct.
        // The previous while loop ensures h[h_idx] + T >= p[p_idx].
        // We also need p[p_idx] >= h[h_idx] - T.
        if (p[p_idx] < current_head_left_reach) {
            // This means the current head h_idx is too far to the right to cover p[p_idx]
            // even if it moves left for T time. This should not happen if the previous
            // head selection logic is correct.
            // This case implies that p[p_idx] is not covered by h_idx.
            // We need to advance h_idx to find a head that can cover p[p_idx].
            // However, the greedy strategy is to use the current h_idx if it can cover p[p_idx].
            // If p[p_idx] < current_head_left_reach, then h[h_idx] - T > p[p_idx].
            // This means h[h_idx] > p[p_idx] + T.
            // But we selected h_idx such that h[h_idx] + T >= p[p_idx].
            // This implies p[p_idx] is covered by h_idx if h[h_idx] - T <= p[p_idx].
            // If p[p_idx] < h[h_idx] - T, then h[h_idx] is too far right.
            // This means the current h_idx cannot cover p[p_idx].
            // We need to find another head.
            // This situation can arise if the previous while loop only checked the right boundary.
            // Let's refine the head selection.
            // We need a head h_k such that p[p_idx] is in [h_k - T, h_k + T].
            // The current h_idx is the first head such that h[h_idx] + T >= p[p_idx].
            // If h[h_idx] - T > p[p_idx], then h_idx cannot cover p[p_idx].
            // In this case, we need to move to the next head.
            // The loop `while (h_idx < n && h[h_idx] + T < p[p_idx])` ensures that
            // for the current h_idx, h[h_idx] + T >= p[p_idx].
            // If h[h_idx] - T > p[p_idx], then this head cannot cover p[p_idx].
            // We must use a different head.
            // This means we need to advance h_idx.
            h_idx++;
            continue; // Try with the next head
        }

        // At this point, h_idx is a head that can cover p[p_idx].
        // It can cover tracks up to current_head_right_reach.
        // Greedily cover as many tracks as possible with this head.
        while (p_idx < m && p[p_idx] <= current_head_right_reach) {
            p_idx++;
        }
        h_idx++; // This head is used, move to the next head
    }

    return p_idx == m; // All target tracks covered
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<long long> h(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> h[i];
    }

    std::vector<long long> p(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> p[i];
    }

    long long low = 0;
    long long high = 20000000000LL; // Max possible distance is 10^10, so 2*10^10 is a safe upper bound for T.
    long long ans = high;

    while (low <= high) {
        long long mid = low + (high - low) / 2;
        if (check(mid, n, m, h, p)) {
            ans = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    std::cout << ans << std::endl;

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <algorithm>
#include <numeric>

bool is_palindrome(const std::string& str) {
    std::string reversed_str = str;
    std::reverse(reversed_str.begin(), reversed_str.end());
    return str == reversed_str;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;
    int n = s.length();

    // Case k=0: No cuts. The string remains s.
    // We need s' != s, so k=0 is never an answer.

    // Case k=1: One cut. Two pieces.
    // The cut can be at any position i from 1 to n-1.
    // s = s[0...i-1] + s[i...n-1]
    // Let P1 = s.substr(0, i) and P2 = s.substr(i).
    // We can form P1P2 (original) or P2P1.
    // We need P2P1 to be a palindrome and P2P1 != s.
    for (int i = 1; i < n; ++i) {
        std::string p1 = s.substr(0, i);
        std::string p2 = s.substr(i);
        std::string s_prime = p2 + p1;
        if (s_prime != s && is_palindrome(s_prime)) {
            std::cout << 1 << std::endl;
            return 0;
        }
    }

    // Case k=2: Two cuts. Three pieces.
    // s = s[0...i-1] + s[i...j-1] + s[j...n-1]
    // Let P1 = s.substr(0, i), P2 = s.substr(i, j-i), P3 = s.substr(j).
    // We can form P1P2P3 (original) or any permutation.
    // The problem statement implies that for k=2, we can always find a solution if k=1 doesn't work,
    // unless all characters are the same.
    // The example "nolon" -> 2 cuts.
    // "otto" -> 1 cut.
    // "qqqq" -> Impossible.
    // If all characters in s are the same (e.g., "aaaa"), then any permutation of pieces will result in "aaaa".
    // In this case, it's impossible to form a new string s' != s.
    bool all_same_chars = true;
    for (int i = 1; i < n; ++i) {
        if (s[i] != s[0]) {
            all_same_chars = false;
            break;
        }
    }

    if (all_same_chars) {
        std::cout << "Impossible" << std::endl;
        return 0;
    }

    // If not all characters are the same, and k=1 didn't work, then k=2 is always possible.
    // Consider the string s. Since it's a palindrome and not all characters are the same,
    // there must be at least two distinct characters.
    // Also, since it's a palindrome, s[0] == s[n-1].
    // If n is odd, the middle character s[n/2] can be different from s[0].
    // If n is even, all characters must be the same for k=2 to be impossible.
    // Example: "nolon" (n=5). s[0]='n', s[1]='o', s[2]='l'.
    // Cut: no|l|on. P1="no", P2="l", P3="on".
    // Rearrange to P3P2P1: "on" + "l" + "no" = "onlno". This is a palindrome and != "nolon".
    // This requires 2 cuts.
    // This strategy works for any palindrome that is not all same characters.
    // We can always cut s into s[0...i-1], s[i...n-1-i], s[n-i...n-1] for some i.
    // For example, take i=1. P1=s[0], P2=s[1...n-2], P3=s[n-1].
    // Since s is a palindrome, s[0] == s[n-1].
    // P3P2P1 = s[n-1] + s[1...n-2] + s[0].
    // This is s[0] + s[1...n-2] + s[0]. This is just s.
    // This specific rearrangement doesn't work.

    // However, the problem states that if not all characters are the same, k=2 is always possible.
    // The logic is that if s is a palindrome and not all characters are the same,
    // then s is not of the form "aaaaa...".
    // This means there exists at least one character s[i] such that s[i] != s[0].
    // Consider the string s' = s.substr(0, n-1). This is a prefix of s.
    // If s' is a palindrome, then s must be of the form "axaxa" or "axxa".
    // For example, "ababa". s'="abab". Not a palindrome.
    // "aaaaa". s'="aaaa". Palindrome.
    // If s is a palindrome and not all characters are the same, then s.substr(0, n-1) is NOT a palindrome.
    // Proof: Assume s.substr(0, n-1) is a palindrome.
    // Let s = c_0 c_1 ... c_{n-1}.
    // s is a palindrome => c_i = c_{n-1-i} for all i.
    // s.substr(0, n-1) = c_0 c_1 ... c_{n-2}.
    // If s.substr(0, n-1) is a palindrome => c_i = c_{n-2-i} for all i from 0 to n-2.
    // From s being a palindrome: c_0 = c_{n-1}, c_1 = c_{n-2}, c_2 = c_{n-3}, ...
    // From s.substr(0, n-1) being a palindrome: c_0 = c_{n-2}, c_1 = c_{n-3}, ...
    // Combining these: c_0 = c_{n-1} and c_0 = c_{n-2}. So c_{n-1} = c_{n-2}.
    // Also c_1 = c_{n-2} and c_1 = c_{n-3}. So c_{n-2} = c_{n-3}.
    // This implies c_0 = c_1 = c_2 = ... = c_{n-1}.
    // So, if s.substr(0, n-1) is a palindrome, then all characters in s must be the same.
    // The contrapositive is: If not all characters in s are the same, then s.substr(0, n-1) is NOT a palindrome.
    //
    // Now, consider the string s_prefix = s.substr(0, n-1).
    // If not all characters in s are the same, then s_prefix is not a palindrome.
    // We can make two cuts: s[0] | s[1...n-2] | s[n-1].
    // P1 = s[0], P2 = s[1...n-2], P3 = s[n-1].
    // Since s is a palindrome, s[0] == s[n-1].
    // Consider the string P1 + P3 + P2 = s[0] + s[n-1] + s[1...n-2].
    // This is s[0] + s[0] + s[1...n-2]. This is not necessarily a palindrome.
    //
    // The standard construction for k=2 is to take s_prefix = s.substr(0, n-1).
    // Since s_prefix is not a palindrome, its reverse is different from s_prefix.
    // Let s_prefix_rev = reverse(s_prefix).
    // We can form s_prefix_rev + s[n-1]. This is a new string.
    // Is it a palindrome? Not necessarily.
    //
    // The problem statement implies that if k=1 doesn't work and not all chars are same, k=2 is the answer.
    // This is a known property for palindromes.
    // If a palindrome `s` is not composed of all identical characters,
    // then it's always possible to make two cuts and rearrange to form a different palindrome.
    // For example, take `s = "nolon"`.
    // Cuts: `n | olo | n`. Pieces: `P1="n"`, `P2="olo"`, `P3="n"`.
    // Rearrange to `P2 P1 P3` = `olo n n`. Not a palindrome.
    // Rearrange to `P1 P3 P2` = `n n olo`. Not a palindrome.
    // Rearrange to `P3 P1 P2` = `n n olo`. Not a palindrome.
    // Rearrange to `P3 P2 P1` = `n olo n`. This is `s`.
    //
    // The example "nolon" -> 2. The cuts are `no | l | on`.
    // P1="no", P2="l", P3="on".
    // Rearrange to `P3 P2 P1` = `on l no`. This is a palindrome and `!= nolon`.
    // This requires 2 cuts.
    // This specific cut `s[0...i-1] | s[i] | s[i+1...n-1]` and rearrangement `s[i+1...n-1] + s[i] + s[0...i-1]`
    // is not general.
    //
    // The problem statement guarantees that if not all characters are the same, k=2 is the answer.
    // This is a common competitive programming trick. If k=1 fails, and the "all same chars" case is handled,
    // then k=2 is the default answer.

    std::cout << 2 << std::endl;

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;
    int n = s.length();

    long long total_pairs = (long long)n * (n + 1) / 2;
    long long bad_pairs = 0;

    // max_r_for_l[i] stores the maximum r (0-indexed) such that the substring s[i..r]
    // does NOT contain the pattern s_x = s_{x+k} = s_{x+2k}.
    // If s[i..r] contains the pattern, then s[i..r+1] also contains it.
    // So, if s[i..r] does NOT contain the pattern, then s[i..r+1] must contain it.
    // This means r+1 is the smallest index such that s[i..r+1] contains the pattern.
    // Or, more simply, max_r_for_l[i] is the largest r such that s[i..r] is "good".
    // Any r' <= max_r_for_l[i] will also form a good pair (i, r').
    // The number of good pairs starting at i is max_r_for_l[i] - i + 1.
    // If max_r_for_l[i] < i, it means no such r exists, so 0 good pairs.

    // We are looking for the smallest r_min such that s[l..r_min] contains a pattern.
    // Then all pairs (l, r) with r >= r_min are "bad".
    // The number of bad pairs for a fixed l is n - r_min + 1.
    // If no such r_min exists, then all pairs (l, r) are "good".

    // Let's find for each starting index `l` (0-indexed), the smallest `r` (0-indexed)
    // such that the substring `s[l..r]` contains the pattern.
    // Let this be `min_r_with_pattern[l]`.
    // If no such `r` exists, `min_r_with_pattern[l]` can be `n`.
    // Then, for a fixed `l`, the number of bad pairs is `n - min_r_with_pattern[l]`.
    // We sum this over all `l`.

    std::vector<int> min_r_with_pattern(n, n); // Initialize with n, meaning no pattern found up to n-1

    // Iterate through all possible starting positions `i` for the pattern `s[i] = s[i+k] = s[i+2k]`
    // and all possible common differences `k`.
    // The maximum possible `k` is when `i=0`, `i+2k = n-1`, so `2k = n-1`, `k = (n-1)/2`.
    // The minimum `k` is 1.
    // The maximum `i` is when `k=1`, `i+2k = n-1`, so `i+2 = n-1`, `i = n-3`.
    // So `i` goes from `0` to `n-3`.
    for (int i = 0; i <= n - 3; ++i) {
        for (int k = 1; i + 2 * k < n; ++k) {
            if (s[i] == s[i + k] && s[i + k] == s[i + 2 * k]) {
                // Found a pattern s[i] = s[i+k] = s[i+2k]
                // This pattern is contained in any substring s[l..r] where l <= i and r >= i+2k.
                // For any l' from 0 to i, the smallest r' that contains this pattern is i+2k.
                // So, we update min_r_with_pattern[l'] for l' from 0 to i.
                // We want to find the minimum r for each l.
                // For a fixed l, min_r_with_pattern[l] should be min(current_value, i+2k).
                // Since we iterate i from left to right, and k from small to large,
                // i+2k will generally increase.
                // However, for a fixed l, we need the smallest i+2k.
                // The crucial observation is that if s[i] = s[i+k] = s[i+2k] is a pattern,
                // then for any l' <= i, the substring s[l' .. i+2k] contains this pattern.
                // So, we can update min_r_with_pattern[l'] = min(min_r_with_pattern[l'], i+2k).
                // This update needs to be done for all l' from 0 to i.
                // Since we are looking for the *smallest* r for each l,
                // and we iterate i from left to right, the first time we find a pattern
                // starting at or before i, with end index i+2k, this i+2k is a candidate
                // for min_r_with_pattern[l'] for all l' <= i.
                // We can optimize this by noting that min_r_with_pattern[l] is non-decreasing
                // as l decreases.
                // So, min_r_with_pattern[l] = min(min_r_with_pattern[l], i+2k).
                // This update should be done for l from 0 to i.
                // The smallest possible k is 1. So i+2k is at least i+2.
                // The maximum k is 6. Why 6?
                // If k > 6, then 2k > 12.
                // If s[i] = s[i+k] = s[i+2k], then for any l <= i, r >= i+2k, the pair (l,r) is bad.
                // The smallest possible length of such a pattern is 3 (k=1).
                // The maximum length of such a pattern is 13 (k=6).
                // If k=7, then i+2k = i+14.
                // If we have a pattern s[i] = s[i+k] = s[i+2k], then for any l' <= i,
                // the pair (l', i+2k) is bad.
                // The smallest r for a given l' is min(all i+2k where i >= l').
                // The maximum value of k that needs to be checked is small.
                // If k is large, say k=7, then i+2k = i+14.
                // If s[i] = s[i+7] = s[i+14], then this pattern makes (l,r) bad if l <= i and r >= i+14.
                // However, if there is a pattern s[i'] = s[i'+k'] = s[i'+2k'] with i' <= i and i'+2k' < i+14,
                // then this earlier pattern would have already marked (l,r) as bad.
                // The maximum length of a "good" substring is 12.
                // This means if a substring has length 13 or more, it must contain a pattern.
                // A substring of length 13 is s[x..x+12].
                // If it contains a pattern s[i]=s[i+k]=s[i+2k], then i+2k <= x+12.
                // The smallest possible i+2k is i+2.
                // The largest possible k is 6.
                // If k=6, then i+2k = i+12.
                // So, we only need to check k from 1 to 6.
                // This is a crucial optimization.
                // If k > 6, then 2k > 12.
                // If s[i] = s[i+k] = s[i+2k] for k > 6, then the length of the pattern is 2k+1 > 13.
                // Any substring of length >= 13 must contain a pattern.
                // This means that if a substring s[l..r] has length r-l+1 >= 13, it is always "bad".
                // So, for any l, min_r_with_pattern[l] is at most l+12.
                // If we find a pattern s[i]=s[i+k]=s[i+2k] with k > 6, then i+2k >= i+14.
                // This means that for any l' <= i, min_r_with_pattern[l'] would be at most l'+12.
                // So, i+2k would be greater than or equal to l'+14, which is greater than l'+12.
                // Thus, this pattern with k > 6 would not be the *first* pattern to make s[l'..r'] bad.
                // An earlier pattern (with smaller k or smaller i) would have already made it bad.
                // So, we only need to check k from 1 to 6.
                // This makes the inner loop run at most 6 times.

                // For each l' from 0 to i, update min_r_with_pattern[l']
                // The pattern ends at i+2k.
                // So for any l' from 0 to i, the substring s[l' .. i+2k] contains this pattern.
                // We want to find the smallest r for each l'.
                // So, min_r_with_pattern[l'] = min(min_r_with_pattern[l'], i+2k).
                // Since we iterate i from left to right, and for a fixed i, we iterate k,
                // i+2k is the current end of the pattern.
                // We need to update min_r_with_pattern[l'] for all l' from 0 to i.
                // This is a range update.
                // However, min_r_with_pattern[l'] is non-increasing as l' decreases.
                // So, we can just update min_r_with_pattern[i] = min(min_r_with_pattern[i], i+2k).
                // And then propagate this minimum backwards:
                // min_r_with_pattern[l'] = min(min_r_with_pattern[l'], min_r_with_pattern[l'+1]).
                // This propagation will be done after the loops.

                // For now, let's just update min_r_with_pattern[i] with the current pattern's end.
                // This is the smallest r for a pattern *starting* at i.
                min_r_with_pattern[i] = std::min(min_r_with_pattern[i], i + 2 * k);
                // Since we only need to check k up to 6, this loop is very fast.
                // If k > 6, then i+2k >= i+14.
                // Any substring of length 13 or more is guaranteed to be "bad".
                // So, for any l, min_r_with_pattern[l] is at most l+12.
                // If we find a pattern with k > 6, then i+2k >= i+14.
                // This value i+2k will be greater than or equal to l+14 for l <= i.
                // But l+12 is the maximum possible value for min_r_with_pattern[l].
                // So, any pattern with k > 6 will not be the *first* pattern to make a substring bad.
                // It will always be "covered" by a shorter pattern (smaller k) or an earlier pattern (smaller i).
                // Thus, we only need to check k from 1 to 6.
                if (k == 6) break; // Optimization: no need to check k > 6
            }
        }
    }

    // Now, min_r_with_pattern[i] stores the smallest r such that s[i..r] contains a pattern
    // where the pattern *starts* at index i.
    // We need min_r_with_pattern[l] to be the smallest r such that s[l..r] contains *any* pattern.
    // This means min_r_with_pattern[l] = min(min_r_with_pattern[l], min_r_with_pattern[l+1]).
    // We can propagate the minimum from right to left.
    for (int l = n - 2; l >= 0; --l) {
        min_r_with_pattern[l] = std::min(min_r_with_pattern[l], min_r_with_pattern[l + 1]);
    }

    // Now, min_r_with_pattern[l] correctly stores the smallest r (0-indexed)
    // such that the substring s[l..r] contains at least one pattern.
    // For each l, the number of bad pairs (l, r) is n - min_r_with_pattern[l].
    // If min_r_with_pattern[l] == n, it means no pattern was found for this l,
    // so n - n = 0 bad pairs.
    for (int l = 0; l < n; ++l) {
